    function buildBlueprint(data) {
      const model = { ...data };
      const faceEntries = model.normals.map((normal, faceIndex) => {
        const ids = new Set();
        model.edges.forEach((edge, edgeIndex) => {
          const ef = model.edgeFaces[edgeIndex];
          if (ef[0] === ef[1]) return;
          if (ef.includes(faceIndex)) {
            ids.add(edge[0]);
            ids.add(edge[1]);
          }
        });
        if (ids.size < 3) return null;
        const n = norm(vec(normal[0], normal[1], normal[2]));
        const center = [...ids].reduce((sum, i) => add(sum, vec(...model.verts[i])), vec());
        const c = scale(center, 1 / ids.size);
        let axis = cross(n, Math.abs(n.y) < .9 ? vec(0, 1, 0) : vec(1, 0, 0));
        if (len(axis) < .0001) axis = cross(n, vec(0, 0, 1));
        const u = norm(axis);
        const v = norm(cross(n, u));
        const face = [...ids].sort((a, b) => {
          const pa = sub(vec(...model.verts[a]), c);
          const pb = sub(vec(...model.verts[b]), c);
          return Math.atan2(dot(pa, v), dot(pa, u)) - Math.atan2(dot(pb, v), dot(pb, u));
        });
        if (face.length >= 3) {
          const calc = faceNormal(vec(...model.verts[face[0]]), vec(...model.verts[face[1]]), vec(...model.verts[face[2]]));
          if (dot(calc, n) < 0) face.reverse();
        }
        // UV is derived from the object-local (unrotated) vertex positions, so it's
        // fixed per face and stays glued to the surface as the object rotates on screen.
        const uv = face.map((i) => {
          const p = sub(vec(...model.verts[i]), c);
          return [dot(p, u), dot(p, v)];
        });
        return { face, uv, normalIndex: faceIndex };
      });
      const entries = faceEntries.filter(Boolean);
      const duplicateFaceKeys = new Set();
      const faceKeyMap = new Map();
      for (const entry of entries) {
        const key = [...entry.face].sort((a, b) => a - b).join(",");
        if (!faceKeyMap.has(key)) faceKeyMap.set(key, []);
        faceKeyMap.get(key).push(entry);
      }
      for (const group of faceKeyMap.values()) {
        if (group.length < 2) continue;
        for (let i = 0; i < group.length; i++) {
          for (let j = i + 1; j < group.length; j++) {
            const a = norm(vec(...model.normals[group[i].normalIndex]));
            const b = norm(vec(...model.normals[group[j].normalIndex]));
            if (dot(a, b) < -.85) {
              duplicateFaceKeys.add(group[i].normalIndex);
              duplicateFaceKeys.add(group[j].normalIndex);
            }
          }
        }
      }
      model.faceByNormalIndex = faceEntries.map((entry) => entry ? entry.face : null);
      model.faceUVByNormalIndex = faceEntries.map((entry) => entry ? entry.uv : null);
      model.faces = entries.map((e) => e.face);
      model.faceUV = entries.map((e) => e.uv);
      model.faceNormalIndices = entries.map((e) => e.normalIndex);
      model.wireMaskFaces = entries.map((e) => duplicateFaceKeys.has(e.normalIndex) ? 0 : 1);
      model.wireCullEdgeKeys = new Set(Object.keys(model.edgeCullNormals || {}).map((edgeIndex) => {
        const edge = model.edges[Number(edgeIndex)];
        return edge ? (edge[0] < edge[1] ? `${edge[0]},${edge[1]}` : `${edge[1]},${edge[0]}`) : "";
      }).filter(Boolean));
      model.decalUV = buildContinuousDecalUV(model.verts, model.faces);
      model.imageProjectionUV = buildProjectedImageDecalUV(model.verts, model.faces, model.faceNormalIndices, model.normals, model.imageProjection || {});
      return model;
    }

