    function modelBoundingRadius(model) {
      if (!model?.verts?.length) return 0;
      if (model._boundingRadius != null) return model._boundingRadius;
      let maxR = 0;
      for (const v of model.verts) {
        const r = Math.hypot(v[0], v[1], v[2]);
        if (r > maxR) maxR = r;
      }
      model._boundingRadius = maxR;
      return maxR;
    }

    function modelOverallSize(model) {
      if (!model?.verts?.length) return 1;
      const min = [Infinity, Infinity, Infinity];
      const max = [-Infinity, -Infinity, -Infinity];
      for (const v of model.verts) {
        for (let i = 0; i < 3; i++) {
          min[i] = Math.min(min[i], v[i]);
          max[i] = Math.max(max[i], v[i]);
        }
      }
      return Math.max(max[0] - min[0], max[1] - min[1], max[2] - min[2], 1);
    }

