    function setDomText(el, value) {
      const text = String(value);
      if (el && el.textContent !== text) el.textContent = text;
    }

    function setDomHidden(el, value) {
      if (el && el.hidden !== value) el.hidden = value;
    }

    function setDomDisabled(el, value) {
      if (el && el.disabled !== value) el.disabled = value;
    }

    function setDomAttr(el, name, value) {
      const text = String(value);
      if (el && el.getAttribute(name) !== text) el.setAttribute(name, text);
    }

    function setStyleProp(el, prop, value) {
      if (el && el.style[prop] !== value) el.style[prop] = value;
    }

    function updatePauseHud() {
      setDomText(hudEls.pauseValue, game.paused ? "PAUSED" : "RUN");
      setDomAttr(hudEls.pauseBtn, "aria-pressed", game.paused ? "true" : "false");
      setDomAttr(hudEls.pauseBtn, "aria-label", game.paused ? "Resume game" : "Pause game");
      setDomHidden(hudEls.pauseBtn, false);
    }

    function updateVolumeHud() {
      const pct = Math.round(normalizeAudioVolume(game.audioVolume) * 100);
      if (hudEls.volumeSlider && hudEls.volumeSlider.value !== String(pct)) hudEls.volumeSlider.value = String(pct);
      setDomText(hudEls.volumeValue, pct);
      setDomAttr(hudEls.volumeControl, "data-volume-state", pct <= 0 ? "muted" : pct < 35 ? "low" : "normal");
      setDomHidden(hudEls.volumeControl, false);
    }

    function updateBrightnessHud() {
      const level = normalizeVisualBrightness(game.visualBrightness);
      const pct = Math.round(level * 100);
      if (space) space.style.setProperty("--visual-brightness", String(level));
      if (hudEls.brightnessSlider && hudEls.brightnessSlider.value !== String(pct)) hudEls.brightnessSlider.value = String(pct);
      setDomText(hudEls.brightnessValue, pct);
      setDomAttr(hudEls.brightnessControl, "data-brightness-state", pct < 92 ? "dim" : pct > 108 ? "bright" : "normal");
      setDomHidden(hudEls.brightnessControl, false);
    }

    function updatePerformanceTickerHud() {
      const perf = game.performance;
      if (!hudEls.perfTicker || !perf) return;
      const fps = Math.round(1000 / Math.max(1, perf.frameMs || 16.7));
      const label = perf.qualityLabel || PERFORMANCE_LOD_LABELS[perf.lod || 0] || "HIGH";
      setDomText(hudEls.perfTicker, `FPS ${fps}  AUTO ${label}  LOD ${perf.lod || 0}  OBJ ${perf.visibleModels || 0}${summarizeSimPhases()}`);
      setDomAttr(hudEls.perfTicker, "data-load", (perf.lod || 0) >= 2 ? "high" : "normal");
      setDomHidden(hudEls.perfTicker, false);
    }

    function toggleClass(el, name, value) {
      if (el && el.classList.contains(name) !== value) el.classList.toggle(name, value);
    }

    function currentSystem() {
      return galaxies[game.galaxy][game.current];
    }

    function targetSystem() {
      return galaxies[game.galaxy][game.target];
    }

    function distance(a, b) {
      return Math.hypot(a.x - b.x, a.y - b.y) / 4;
    }

    function usedCargo() {
      return Object.values(game.cargo).reduce((a, b) => a + b, 0);
    }

    function rankName() {
      let r = RANKS[0][0];
      for (const [name, min] of RANKS) if (game.kills >= min) r = name;
      return r;
    }

    function legalStatus() {
      if (game.legal <= 0) return "CLEAN";
      if (game.legal < 16) return "OFFENDER";
      return "FUGITIVE";
    }

    function laserPower() {
      const shotHeat = 8; // BBC Elite's LASLI adds the same gun heat per actual firing event.
      if (game.equipment.militaryLaser) return {
        id: "military", name: "Military", damage: 14, heat: shotHeat, range: 4600,
        cooldown: 72, duration: 95, width: 2.8, color: "#8fe8ff", sound: "laserMilitary"
      };
      if (game.equipment.beamLaser) return {
        id: "beam", name: "Beam", damage: 9, heat: shotHeat, range: 3400,
        cooldown: 72, duration: 135, width: 2.1, color: "#ffd33d", sound: "laserBeam"
      };
      if (game.equipment.miningLaser) return {
        id: "mining", name: "Mining", damage: 18, rockMul: 3, heat: shotHeat, range: 1700,
        cooldown: 1000, duration: 230, width: 4.6, color: "#e8f2e4", sound: "laserMining"
      };
      return {
        id: "pulse", name: "Pulse", damage: 16, heat: shotHeat, range: 2400,
        cooldown: 200, duration: 125, width: 2.4, color: "#ff6a55", sound: "laserPulse"
      };
    }

    const LASER_EQUIPMENT_IDS = ["miningLaser", "beamLaser", "militaryLaser"];
    const DEV_EQUIPMENT_ORDER = {
      miningLaser: 10,
      beamLaser: 11,
      militaryLaser: 12
    };

    function isLaserEquipment(id) {
      return LASER_EQUIPMENT_IDS.includes(id);
    }

    function fitLaser(id) {
      for (const laserId of LASER_EQUIPMENT_IDS) game.equipment[laserId] = laserId === id;
    }

    function normalizeLaserFit() {
      const active = ["militaryLaser", "beamLaser", "miningLaser"].find((id) => game.equipment[id]);
      if (active) fitLaser(active);
    }

    function normalizeCommanderName(name) {
      const clean = String(name || "")
        .toUpperCase()
        .replace(/[^A-Z0-9 ]/g, "")
        .replace(/\s+/g, " ")
        .trim()
        .slice(0, 7);
      return clean || "JAMESON";
    }

    function askCommanderName(force = false) {
      const current = normalizeCommanderName(game.commander);
      const entered = window.prompt("COMMANDER NAME", current);
      if (entered === null && !force) return false;
      game.commander = normalizeCommanderName(entered === null ? current : entered);
      setMessage(`Commander registered: ${game.commander}.`, true);
      renderPanel();
      updateReadouts();
      return true;
    }

    function baseMarketFor(system) {
      return GOODS.map(([name, basePrice, factor, baseQty, mask, unit, illegal]) => {
        const swing = system.marketRand & mask;
        const price = Math.max(1, (basePrice + swing + system.economy * factor) * 0.4);
        const raw = baseQty + swing - system.economy * factor;
        const qty = clamp(raw & 63, 0, 63);
        return { name, price, qty, unit, illegal };
      });
    }

    function marketStockKey(system) {
      const systemIndex = Number.isFinite(system?.index) ? system.index : game.current;
      return `${game.galaxy}:${systemIndex}`;
    }

    function marketStockFor(system) {
      if (!game.marketStock || typeof game.marketStock !== "object") game.marketStock = {};
      const key = marketStockKey(system);
      if (!game.marketStock[key]) {
        game.marketStock[key] = Object.fromEntries(baseMarketFor(system).map((item) => [item.name, item.qty]));
      }
      return game.marketStock[key];
    }

    function marketFor(system) {
      const stock = marketStockFor(system);
      return baseMarketFor(system).map((item) => ({
        ...item,
        qty: Math.max(0, Math.trunc(Number(stock[item.name] ?? item.qty) || 0))
      }));
    }

    function canUseMarket() {
      return !!game.docked && !game.transition && !game.jumpCountdown && !game.playerDestroyed;
    }

    // --- NPC comms chatter -------------------------------------------------------
    // Situation-driven one-liners from live ships, shown in a small fading log on the
    // flight view. Same panel is the natural home for player chat if multiplayer lands.
    const HACK_DISABLE_CHATTER = true;
    const escapeHtml = (s) => String(s).replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
    const escapeAttr = (s) => escapeHtml(s).replace(/"/g, "&quot;");
    const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];
    const alienGlyphCache = new Map();
    const commsSenderThrottle = new Map();
    let commsSeq = 0;

    function inferCommsKind(from, alien = false) {
      const name = String(from || "").toUpperCase();
      if (alien) return "alien";
      if (name.includes("CONTROL") || name.includes("TRAFFIC")) return "station";
      if (name.includes("POLICE") || name.includes("VIPER") || name.includes("PATROL")) return "police";
      if (name.includes("PIRATE")) return "hostile";
      if (name.includes("TRADER") || name.includes("ARMADA")) return "trader";
      return "trader";
    }

    function commsMessage(from, text, alienOrKind = false) {
      if (HACK_DISABLE_CHATTER) return false;
      const alien = alienOrKind === true || alienOrKind === "alien";
      const kind = typeof alienOrKind === "string" ? alienOrKind : inferCommsKind(from, alien);
      const now = performance.now();
      const throttleKey = `${kind}:${from}`;
      const recent = commsSenderThrottle.get(throttleKey);
      const protectedComms = kind === "station" || kind === "warning";
      if (!protectedComms && recent && now - recent.at < 4200) {
        if (recent.text === text || now - recent.at < 1800) return false;
      }
      commsSenderThrottle.set(throttleKey, { text, at: now });
      game.comms.push({ id: ++commsSeq, from, text, alien, kind, born: now, until: now + 9500 });
      if (game.comms.length > 4) game.comms.splice(0, game.comms.length - 4);
      renderComms();
      return true;
    }

    function alienGlyphSvg(ch) {
      const key = ch.toUpperCase();
      if (alienGlyphCache.has(key)) return alienGlyphCache.get(key);
      const rng = mulberry(hash32(`alien-glyph:${key}`));
      const anchors = [
        [2, 2], [5, 1.4], [8, 2],
        [2, 6], [5, 6], [8, 6],
        [2, 12], [5, 12.6], [8, 12]
      ];
      const lineCount = 2 + Math.floor(rng() * 3);
      const used = new Set();
      const parts = [];
      for (let i = 0; i < lineCount; i++) {
        let a = Math.floor(rng() * anchors.length);
        let b = Math.floor(rng() * anchors.length);
        for (let guard = 0; guard < 8 && (a === b || used.has(`${Math.min(a, b)}:${Math.max(a, b)}`)); guard++) b = Math.floor(rng() * anchors.length);
        if (a === b) continue;
        used.add(`${Math.min(a, b)}:${Math.max(a, b)}`);
        parts.push(`<line x1="${anchors[a][0].toFixed(1)}" y1="${anchors[a][1].toFixed(1)}" x2="${anchors[b][0].toFixed(1)}" y2="${anchors[b][1].toFixed(1)}"></line>`);
      }
      if (rng() > .48) {
        const c = anchors[Math.floor(rng() * anchors.length)];
        parts.push(`<circle class="${rng() > .55 ? "filled" : ""}" cx="${c[0].toFixed(1)}" cy="${c[1].toFixed(1)}" r="${(1 + rng() * 1.15).toFixed(1)}"></circle>`);
      }
      if (rng() > .68) {
        const side = rng() > .5 ? 1 : -1;
        parts.push(`<path d="M ${side > 0 ? 2 : 8} 3 Q 5 ${2 + rng() * 9} ${side > 0 ? 8 : 2} 11"></path>`);
      }
      const svg = `<svg class="alien-glyph" viewBox="0 0 10 14" aria-hidden="true">${parts.join("")}</svg>`;
      alienGlyphCache.set(key, svg);
      return svg;
    }

    function alienGlyphMarkup(text) {
      let html = "";
      for (const ch of String(text)) {
        if (/\s/.test(ch)) html += `<span class="alien-space"></span>`;
        else if (/[A-Z]/i.test(ch)) html += alienGlyphSvg(ch);
        else if (ch === "'") html += `<span class="alien-punct">·</span>`;
        else if (ch === "/") html += `<span class="alien-punct">∕</span>`;
        else if (ch === "?") html += `<span class="alien-punct">⌁</span>`;
        else if (ch === "!") html += `<span class="alien-punct">⌇</span>`;
        else if (ch === "…") html += `<span class="alien-punct">⋯</span>`;
        else html += `<span class="alien-punct">${escapeHtml(ch)}</span>`;
      }
      return `<span class="alien-text" title="${escapeAttr(text)}" aria-label="${escapeAttr(text)}">${html}</span>`;
    }

    function renderComms() {
      const el = byId("commsLog");
      if (!el) return;
      if (HACK_DISABLE_CHATTER) {
        if (game.comms.length) game.comms = [];
        if (el.dataset.renderKey !== "muted") {
          el.dataset.renderKey = "muted";
          setDomHtml(el, "");
        }
        return;
      }
      const now = performance.now();
      const live = game.comms.filter((m) => m.until > now);
      if (live.length !== game.comms.length) game.comms = live;
      const newest = live[live.length - 1];
      const renderState = live.map((m) => `${m.id}:${Math.min(String(m.text).length, Math.floor(Math.max(0, now - (m.born || 0)) / 18))}`).join("|");
      const key = `${renderState}:${newest ? newest.id : 0}`;
      if (el.dataset.renderKey === key) return;
      el.dataset.renderKey = key;
      el.innerHTML = live.map((m) => {
        const typed = Math.min(String(m.text).length, Math.floor(Math.max(0, now - (m.born || 0)) / 18));
        const visibleText = String(m.text).slice(0, typed);
        const body = m.alien ? alienGlyphMarkup(visibleText) : escapeHtml(visibleText);
        const kindClass = m.alien ? "alien-comms" : `comms-${escapeAttr(m.kind || "trader")}`;
        const cursor = m === newest ? `<span class="comms-cursor">_</span>` : "";
        return `<div class="comms-line ${kindClass}"><span class="comms-from">${escapeHtml(m.from)}:</span> ${body}${cursor}</div>`;
      }).join("");
    }
    if (!ULTRA_ELITE_RENDER_BENCH) setInterval(renderComms, 120);

    function isAlienShip(o) {
      return !!o && (o.thargoid || ALIEN_MODELS.includes(o.model));
    }

    const ALIEN_BASE_ALPHABET = "ZXQKVRTHNGMLPDSWYFJCBAXUO".split("");

    function alienAlphabet() {
      const rng = mulberry(hash32(`alien-alphabet:${game.galaxy}:${currentSystem().index}`));
      const chars = ALIEN_BASE_ALPHABET.slice();
      for (let i = chars.length - 1; i > 0; i--) {
        const j = Math.floor(rng() * (i + 1));
        [chars[i], chars[j]] = [chars[j], chars[i]];
      }
      return chars.slice(0, 25);
    }

    function alienWord(rng, alphabet, min = 2, max = 6) {
      const len = min + Math.floor(rng() * (max - min + 1));
      let out = "";
      for (let i = 0; i < len; i++) {
        out += alphabet[Math.floor(rng() * alphabet.length)];
        if (i > 0 && i < len - 1 && rng() < .18) out += "'";
      }
      return out;
    }

    function alienChatterLine(o, mood = "ambient") {
      const seed = hash32(`${currentSystem().name}:${o?.name || "alien"}:${mood}:${Math.floor(performance.now() / 2400)}`);
      const rng = mulberry(seed);
      const alphabet = alienAlphabet();
      const words = 3 + Math.floor(rng() * 5);
      let text = Array.from({ length: words }, (_, i) => alienWord(rng, alphabet, i === 0 ? 3 : 2, mood === "threat" ? 7 : 6)).join(" ");
      if (mood === "threat") text = `${alienWord(rng, alphabet, 5, 8)} // ${text}`;
      if (mood === "flee") text = `${text} ? ${alienWord(rng, alphabet, 3, 5)}`;
      if (mood === "mercy") text = `${alienWord(rng, alphabet, 4, 7)} ? ${text} ? ${alienWord(rng, alphabet, 3, 5)}`;
      return text + pick(["", "", "", "!", "…"]);
    }

    const hail = (o, text) => commsMessage(o.name || "UNKNOWN", text, isAlienShip(o) ? "alien" : o.police ? "police" : o.hostile ? "hostile" : "trader");
    const stationCommsName = () => `${currentSystem().name.toUpperCase()} CONTROL`;

    function shipHail(o, mood, text, chance = 1, cooldown = 9000) {
      if (!o || Math.random() > chance) return false;
      const now = performance.now();
      o._hailTimes = o._hailTimes || {};
      if (o._hailTimes[mood] && now - o._hailTimes[mood] < cooldown) return false;
      o._hailTimes[mood] = now;
      return hail(o, text);
    }

    function governmentCommsTone() {
      const gov = currentSystem().government;
      if (gov === 0) return "anarchy";
      if (gov === 1) return "feudal";
      if (gov === 2) return "multi";
      if (gov === 3) return "dictatorship";
      if (gov === 4) return "communist";
      if (gov === 5) return "confederacy";
      if (gov === 6) return "democracy";
      if (gov === 7) return "corporate";
      return "neutral";
    }

    function toneLines(map) {
      return (map[governmentCommsTone()] || map.neutral || []).concat(map.any || []);
    }

    function hostileThreatLine(o) {
      const sys = currentSystem();
      if (isAlienShip(o)) return alienChatterLine(o, "threat");
      return pick([
        `Cargo and credits, ${game.commander}, and you keep breathing.`,
        `Fresh meat on the ${sys.name} lanes!`,
        `That ${shipName(playerShipModel())} will strip for parts nicely.`,
        "Nothing personal. Scrap prices are up.",
        `${GOVS[sys.government]} law can't save you out here.`,
        "Your transponder just became negotiable.",
        "Power down and dump the hold. Try anything clever and burn.",
        `I know a fence at ${sys.name} who'll pay for your hull plates.`,
        "Nice cargo profile. Shame about the escort.",
        "Running only makes the salvage colder."
      ]);
    }

    function fleeLine(o) {
      if (isAlienShip(o)) return alienChatterLine(o, "flee");
      return o.hostile
        ? pick([
          "This isn't over, pilot!",
          "Breaking off — that one's a demon!",
          "Not worth the paint. I'm gone.",
          "Engines redlining. Disengaging.",
          "Keep the cargo, keep the curse.",
          "Next time I bring friends."
        ])
        : pick([
          "Mayday! Mayday! Under fire!",
          `Any police in ${currentSystem().name} sector?! Help!`,
          "I'm just a hauler! Hold your fire!",
          "Ceasing manoeuvres! Don't shoot!",
          "My insurer is going to love this.",
          "Control, logging hostile contact now!"
        ]);
    }

    function attackedFleeLine(o, profile = {}) {
      if (isAlienShip(o)) return alienChatterLine(o, "flee");
      if (profile.timid || ["shuttle", "transporter", "worm"].includes(o.model)) {
        return pick([
          "Civilian vessel under fire! Breaking lane!",
          "No weapons aboard! We are disengaging!",
          "Control, this is a shuttle taking fire!",
          "Transport manifest emergency! Fleeing contact!",
          "We are non-combat traffic! Hold your fire!",
          "Crew compartment hit! Running for beacon cover!"
        ]);
      }
      if (profile.hauler || o.role === "trader") {
        return pick([
          "Hauler under attack. Dumping vector and running!",
          "Cargo insured, hull isn't. We're leaving!",
          "Freighter breaking off. Marking attacker hostile.",
          "Control, commercial vessel fleeing weapons fire!",
          "No cargo is worth this. Engines to emergency thrust.",
          "Escort contract clearly expired. We are out."
        ]);
      }
      return pick([
        "Taking fire. Disengaging!",
        "Hull strike logged. Running cold!",
        "Not my fight. Breaking contact.",
        "Vectoring away from hostile commander.",
        "Shields unstable. I'm gone."
      ]);
    }

    function retaliationLine(o, profile = {}) {
      if (isAlienShip(o)) return alienChatterLine(o, "threat");
      if (o.police || o.role === "police") return pick([
        "Assault on Viper patrol. Weapons free.",
        "Commander, you have fired on police. Stand by for enforcement.",
        "Viper unit hit. Pursuit authority granted.",
        "Patrol shields struck. Returning fire.",
        "Criminal assault confirmed. Engaging."
      ]);
      if (profile.bountyHunter) return pick([
        "Bad choice, commander. I was hunting bigger game.",
        "You just made the bounty board.",
        "Bounty hunter returning fire.",
        "Assault logged. I'll collect the fine from your wreck.",
        "You wanted my attention. You have it."
      ]);
      if (profile.pirate || o.hostile) return pick([
        "You shoot first? I respect that.",
        "Now it's personal, commander.",
        "Fine. No cargo deal. Just wreckage.",
        "You'll pay for that scratch.",
        "Weapons hot. Coming about."
      ]);
      return pick([
        "Self-defence systems live. Back off!",
        "You fired on the wrong ship.",
        "Warning ignored. Returning fire.",
        "I don't want this fight, but I'll finish it.",
        "Hostile act confirmed. Engaging."
      ]);
    }

    function assaultReportLine(o, profile = {}) {
      if (profile.timid) return pick([
        `${o.name} reports civilian vessel under attack.`,
        `Emergency beacon from ${o.name}: weapons impact logged.`,
        `${o.name} requests immediate patrol support.`,
        `Control copies distress call from ${o.name}.`
      ]);
      if (profile.hauler || o.role === "trader") return pick([
        `${o.name} reports commercial traffic under fire.`,
        `Freighter distress beacon received from ${o.name}.`,
        `${o.name} has marked attacker hostile on trade net.`,
        `Control copies cargo vessel assault report from ${o.name}.`
      ]);
      return pick([
        `${o.name} reports illegal weapons strike.`,
        `Assault report received from ${o.name}.`,
        `${o.name} transponder marks hostile contact.`,
        `Weapons impact logged by ${o.name}.`
      ]);
    }

    function mercyLine(o, attackerName = game.commander) {
      if (isAlienShip(o)) return alienChatterLine(o, "mercy");
      if (o.role === "police" || o.police) {
        return pick([
          "Mayday! Viper hull breach, losing control!",
          "Officer down! Request emergency recovery!",
          "Patrol unit crippled. Any friendly contact, respond!",
          `${attackerName}, cease fire! Pilot survival priority!`,
          "Command, shields gone. I need cover now!"
        ]);
      }
      if (o.hostile) {
        return pick([
          "Wait! Wait! I can pay!",
          "Hold fire, commander! Cargo is yours!",
          "Engines are gone! Let me drift!",
          "No more shots! I'll dump the hold!",
          "Mercy! I yield, I yield!",
          "Take the bounty if you must, just leave the pod!"
        ]);
      }
      return pick([
        "Please, hold fire! I'm venting atmosphere!",
        "I surrender! Cargo, credits, anything!",
        "My reactor is cracking! Let me eject!",
        "Ceasing thrust! Please don't finish this!",
        "I'm just a trader! Please, no more!",
        `${attackerName}, I have crew aboard! Hold fire!`
      ]);
    }

    function maybeHailMercy(o, attackerName = game.commander, chance = 1) {
      if (!o || o.type !== "ship" || !o.maxHp || o.hp <= 0 || o._mercyHailed) return;
      const hullFrac = o.hp / o.maxHp;
      if (hullFrac > .16 || Math.random() > chance) return;
      o._mercyHailed = true;
      hail(o, mercyLine(o, attackerName));
    }

    function shipHitReactionChance(o, profile) {
      if (o.police || o.role === "police") return 1;
      if (o.thargoid || isAlienShip(o)) return 1;
      if (o.hostile || profile.pirate || profile.hostile) return .94;
      if (profile.bountyHunter) return .82;
      if (profile.timid || o.role === "pod") return .08;
      if (profile.hauler || o.role === "trader") return .28;
      return .45;
    }

    function reactToPlayerAttack(o) {
      if (!o || o.type !== "ship" || o.role === "pod" || o.hp <= 0) return;
      const profile = SOURCE_BEHAVIOUR[o.model] || {};
      const innocent = profile.innocent || (!o.hostile && (o.role === "trader" || profile.trader || profile.hauler || profile.timid));
      if (innocent && !o._reportedAssault) {
        o._reportedAssault = true;
        game.legal = Math.min(60, game.legal + (profile.timid ? 5 : 8));
        commsMessage(stationCommsName(), assaultReportLine(o, profile), "station");
        if (nearStationSafeZone()) provokeStationPolice(`${o.name} attacked near the station`);
        else if (Math.random() < .42) spawnPoliceResponse();
      }

      const hullFrac = o.maxHp ? o.hp / o.maxHp : 1;
      const shouldFlee = !o.police && !o.thargoid && (
        o.role === "trader" ||
        profile.timid ||
        profile.hauler ||
        (innocent && hullFrac < .72)
      );
      const fightChance = shipHitReactionChance(o, profile);
      if (shouldFlee && Math.random() > fightChance) {
        o.hostile = false;
        o.target = null;
        o.aiMode = "flee";
        o.fleeFrom = { ...game.camera.pos };
        o._fleeCommitted = true;
        if (!o._fleeHailed) {
          o._fleeHailed = true;
          shipHail(o, "flee", attackedFleeLine(o, profile), .92, 12000);
        }
        return;
      }

      if (Math.random() <= fightChance) {
        o.hostile = true;
        o.target = null;
        o.aiMode = "attack";
        o.attackClock = Math.min(o.attackClock || .35, .28 + Math.random() * .55);
        o._fleeCommitted = false;
        if (o.role === "trader" && !profile.timid && !profile.hauler) o.role = "retaliating";
        if (!o._retaliationHailed) {
          o._retaliationHailed = true;
          hail(o, retaliationLine(o, profile));
        }
      }
    }

    function policeScrambleLine() {
      return pick(toneLines({
        dictatorship: [
          "Weapons violation. Submit immediately or be destroyed.",
          "Authorised force deployed. Civilian traffic will disperse.",
          "Station command has marked you non-compliant."
        ],
        corporate: [
          "Security incident logged. Viper response billed to offender.",
          "Compliance breach detected. Enforcement assets dispatched.",
          "Insurance risk elevated. Security response in progress."
        ],
        anarchy: [
          "Local patrol responding... if the transponder holds.",
          "Station guns are awake. Everyone else, good luck.",
          "Shots fired near the slot. Vipers launching, probably."
        ],
        democracy: [
          "Weapons fire reported. Patrol responding under station authority.",
          "All vessels, clear the enforcement lane.",
          "Suspect contact marked. Please reduce speed and hold course."
        ],
        communist: [
          "Collective traffic safety breach. Patrol responding.",
          "Citizen vessels, clear space for enforcement action.",
          "Unauthorised weapons discharge logged by station committee."
        ],
        neutral: [
          `${currentSystem().name} patrol: weapons fire detected. Responding.`,
          "Station control reports shots fired. Vipers scrambled.",
          "This is the law. Power down and heave to."
        ],
        any: [
          "Suspect contact marked. Interceptors released.",
          "Weapons violation logged. Pursuit authorised."
        ]
      }));
    }

    function witnessLine(victimName) {
      return pick([
        `Control, ${victimName} just went up!`,
        "Debris field ahead... someone's having a bad day.",
        "Did you see that kill? Staying well clear.",
        `${victimName}'s beacon just went dark.`,
        "I'm recording this. Nobody shoot the recorder.",
        "That was a clean hit. Too clean.",
        `May ${victimName}'s escape pod be luckier than the hull.`
      ]);
    }

    function stationChatterLine() {
      const sys = currentSystem();
      const dest = galaxies[game.galaxy][game.target].name;
      const good = GOODS[Math.floor(Math.random() * GOODS.length)][0];
      return pick(toneLines({
        dictatorship: [
          "All ships will maintain assigned vector. Deviations are violations.",
          "Docking queue is mandatory. Unauthorised approach will be punished.",
          "Transmit cargo manifest before entering the control perimeter.",
          "Station command reminds traffic: silence on non-essential channels."
        ],
        corporate: [
          `Traffic advisory: priority lane open for ${dest} departures.`,
          "Docking fees are recalculated on final approach. Have credit ready.",
          "Security scan consent is implied by station proximity.",
          `Market bulletin: ${ECONOMIES[sys.economy].toLowerCase()} exchange prices updated.`
        ],
        anarchy: [
          "Docking queue is advisory. Survival remains at pilot discretion.",
          "Beacon three is unreliable. Approach by eye if you must.",
          "Station guns report partial coverage. Keep your shields warm.",
          "Traffic control accepts no liability for pirate activity."
        ],
        democracy: [
          "Civilian traffic, please hold vector until patrol clears the slot.",
          "Docking bay strobes cycling. Watch the slot rotation.",
          "Outer marker active. Reduce speed before requesting clearance.",
          "Control thanks pilots for maintaining scanner separation."
        ],
        communist: [
          "Collective traffic lane open. Queue discipline preserves safety.",
          "Cargo declarations support fair distribution. Transmit manifest.",
          "Public dock crews are ready for scheduled arrivals.",
          "Fuel ration bulletin updated for all registered commanders."
        ],
        feudal: [
          "By station charter, yield to vessels under house protection.",
          "Harbour-master requests tribute manifests before docking.",
          "Keep weapons sheathed in the approach lane.",
          "Noble convoy has priority through the slot."
        ],
        multi: [
          "Control advisory: local traffic rules may vary by beacon.",
          "Docking authority is shared today. Expect contradictory instructions.",
          "Maintain scanner separation while committees argue about lanes.",
          "Approach queue revised again. Check beacon before final."
        ],
        neutral: [
          `Inbound freighters, declare ${good} tonnage before final approach.`,
          `${sys.name} control to all ships: maintain scanner separation.`,
          "Automated tug traffic crossing the mail slot.",
          "Navigation buoy three reports minor debris drift."
        ],
        any: [
          `Registered departures for ${dest}, confirm jump fuel before launch.`,
          `Commodity watch: ${good} traffic higher than usual.`
        ]
      }));
    }

    function stationControllerLine(kind, detail = "") {
      const sys = currentSystem();
      const base = {
        launch: {
          dictatorship: [
            `${game.commander}, departure authorised. Maintain vector zero-seven-one until released.`,
            "Launch window assigned. No deviation from outbound corridor.",
            `Commander ${game.commander}, transponder locked. Proceed under station command.`
          ],
          corporate: [
            `${game.commander}, launch clearance approved. Departure slot billed and open.`,
            "Outbound vector clear. Insurance beacon verified.",
            "Departure lane green. Keep to filed traffic profile."
          ],
          anarchy: [
            `${game.commander}, slot looks clear. Punch it before that changes.`,
            "Launch when ready. Beacon coverage is patchy past the marker.",
            "Outbound corridor is mostly clear. Watch your own six."
          ],
          democracy: [
            `${game.commander}, launch clearance granted. Safe flight.`,
            "Departure vector clear. Maintain traffic separation.",
            `Welcome to ${sys.name} space. Contact control beyond outer marker.`
          ],
          neutral: [
            `${game.commander}, launch clearance granted. Safe flight.`,
            "Departure vector clear. Mind outbound traffic.",
            `Slot is yours, commander. Welcome to ${sys.name} space.`,
            "Transponder logged. You are clear of the bay."
          ]
        },
        dockClear: {
          dictatorship: [
            "Approach authorised. Hold assigned vector and speed.",
            "Docking clearance issued. Do not improvise final approach.",
            "Slot control has you. Comply with strobe sequence."
          ],
          corporate: [
            "Approach accepted. Docking fee reserved.",
            "Bay assigned. Traffic liability window begins now.",
            "Docking lock confirmed. Services account active on touchdown."
          ],
          anarchy: [
            "Bay looks open. If the strobes fail, follow the scorch marks.",
            "Approach accepted. No promises about loose traffic.",
            "Slot timing is good enough. Bring it in clean."
          ],
          democracy: [
            "Clearance granted. Welcome home, commander.",
            "Bay assigned. Mind the rotation on approach.",
            "Docking lock confirmed. Cutting you in."
          ],
          neutral: [
            "Approach accepted. Follow the strobes.",
            "Slot timing green. Reduce thrust on final.",
            "Traffic has you painted. Bring it in clean."
          ]
        },
        dockComplete: {
          dictatorship: [
            "Docking complete. Engines will remain safed until release.",
            "Mag clamps locked. Await station inspection.",
            "Touchdown confirmed. Disembark only when authorised."
          ],
          corporate: [
            "Docking complete. Account services are online.",
            "Mag clamps locked. Hangar fees now accruing.",
            "Touchdown confirmed. Refuel and repair options posted."
          ],
          anarchy: [
            "You're down. Lock your canopy.",
            "Mag clamps caught you. Welcome aboard, more or less.",
            "Touchdown confirmed. Ignore anyone selling permits."
          ],
          neutral: [
            "Docking complete. Bay pressure normal.",
            "Mag clamps locked. Welcome aboard.",
            "Touchdown confirmed. Services are online.",
            "Hangar crew has you. Power down engines."
          ]
        },
        dockDeny: {
          dictatorship: [`Docking denied: ${detail}. Correct immediately.`],
          corporate: [`Docking denied: ${detail}. Re-queue after compliance.`],
          anarchy: [`Docking denied: ${detail}. Try not to decorate the slot.`],
          neutral: [`Docking denied: ${detail}.`]
        },
        autoOn: {
          dictatorship: [
            "Auto-dock command accepted. Manual input is now discouraged.",
            "Computer vector locked. Hold still and comply.",
            "Beacon captured. Station has authority over final approach."
          ],
          corporate: [
            "Auto-dock vector received. Premium approach profile engaged.",
            "Computer lock accepted. Liability transfers on touchdown.",
            "Beacon captured. Approach automation active."
          ],
          anarchy: [
            "Auto-dock sees the slot. Let it argue with physics.",
            "Computer has a vector. Keep a hand near override.",
            "Beacon captured, mostly. Hold steady."
          ],
          neutral: [
            "Auto-dock vector received. Hold steady.",
            "Computer lock accepted. Hands off the stick.",
            "Beacon captured. Approach profile loading.",
            "Autopilot has the slot. Monitor speed only."
          ]
        },
        autoOff: {
          neutral: [
            "Auto-dock cancelled. Manual control returned.",
            "Computer lock released. You have the ship.",
            "Approach automation standing down."
          ]
        }
      }[kind] || {};
      return pick(toneLines(base));
    }

    function ambientChatterLine(o) {
      const sys = currentSystem();
      const dest = galaxies[game.galaxy][game.target].name;
      const good = GOODS[Math.floor(Math.random() * GOODS.length)][0];
      if (isAlienShip(o)) return alienChatterLine(o, "ambient");
      if (o.aiMode === "flee") return pick([
        "Keeping distance from hostile contact.",
        "Emergency vector set. No cargo is worth this.",
        "Mayday logged. Running for clear space.",
        "Shields unstable. Requesting patrol cover.",
        "Breaking traffic lane, under fire.",
        "If anyone asks, I was never on this route."
      ]);
      if (o.role === "retaliating") return pick([
        "Self-defence profile armed.",
        "Attacker marked. Holding weapons hot.",
        "I gave them a warning. Now I give them fire.",
        "Private vessel returning unlawful fire.",
        "Combat log open. Let's settle this."
      ]);
      if (o.police) return pick([
        "Routine sweep. Keep your transponder on.",
        `Scan complete: ${game.legal > 30 ? "fugitive-class vessel in sector." : "all clean."}`,
        `${sys.name} patrol, sector clear.`,
        "Viper wing two, rolling to station shadow.",
        "Contraband scan net is live.",
        "Hold your lane and keep your heat signature tidy.",
        `Patrol notes pirate chatter on the ${dest} vector.`,
        "Civilian contact confirmed. No action.",
        "Traffic control, patrol sweep entering outer marker."
      ]);
      if (o.hostile) return pick([
        "Any fat traders on this lane today?",
        "Heard the Vipers run thin out here.",
        "Keep your scanner dark and follow my lead.",
        "Don't touch the clean ships until they clear the slot.",
        `Fence says ${good} is hot at ${dest}.`,
        "I count two escorts and one easy mark.",
        "Station patrol is looking sunward. Move now.",
        "Paint your beacon clean and they'll never know.",
        "Leave the escape pods. They slow us down."
      ]);
      return pick([
        `Word is ${good} pays double at ${dest}.`,
        `${ECONOMIES[sys.economy]} markets... you haul what you can.`,
        `Three jumps out of ${sys.name} and the ${GOVS[sys.government].toLowerCase()} paperwork still follows me.`,
        "Coffee's cold, cargo's warm. Onward.",
        `Anyone else getting scanner ghosts near ${sys.name}?`,
        `If the price holds, I'm buying fuel and sleeping at ${dest}.`,
        "Remind me never to take textiles through an anarchy again.",
        "My aft shield has sounded wrong since the last jump.",
        `Control, requesting queue number for ${sys.name} station.`,
        "Canister recovery crews are getting bold today.",
        `Running ${good} on a thin margin, same as always.`,
        "If you see a Python with red trim, turn the other way.",
        "Docking computer sings better than my co-pilot."
      ]);
    }

    function setMessage(msg, important = false) {
      byId("message").textContent = msg;
      game.messageTimer = important ? 4 : 2;
    }

    // BBC Master Elite drives an SN76489 sound chip through a tiny buffered
    // sound table: beeps, two-part laser/hyperspace effects, launch/missile,
    // ECM, hit and explosion noise. This Web Audio synth follows those sound
    // categories procedurally rather than shipping sampled audio assets.
    const eliteAudio = (() => {
      let ctx = null;
      let master = null;
      let limiter = null;
      let buses = null;
      let noiseBuffer = null;
      let engineBed = null;
      let flybyBed = null;
      let transitionBed = null;
      let solarBed = null;
      const pitchScale = .62;
      const filterScale = .68;
      const BUS_LEVELS = {
        cockpit: .88,
        weapons: 1,
        ship: .72,
        world: .96,
        ambience: .56
      };

      function ensure() {
        if (!game.soundEnabled) return null;
        const AudioCtx = window.AudioContext || window.webkitAudioContext;
        if (!AudioCtx) return null;
        if (!ctx) {
          ctx = new AudioCtx();
          master = ctx.createGain();
          limiter = ctx.createDynamicsCompressor();
          limiter.threshold.value = -17;
          limiter.knee.value = 18;
          limiter.ratio.value = 4.2;
          limiter.attack.value = .004;
          limiter.release.value = .22;
          master.gain.value = masterTargetVolume();
          master.connect(limiter).connect(ctx.destination);
          buses = {};
          for (const [name, level] of Object.entries(BUS_LEVELS)) {
            const bus = ctx.createGain();
            bus.gain.value = level;
            bus.connect(master);
            buses[name] = bus;
          }
          noiseBuffer = makeNoiseBuffer();
        }
        if (ctx.state === "suspended") ctx.resume().catch(() => {});
        return ctx;
      }

      function makeNoiseBuffer() {
        const length = Math.max(1, Math.floor(ctx.sampleRate * 1.2));
        const buffer = ctx.createBuffer(1, length, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < length; i++) data[i] = Math.random() * 2 - 1;
        return buffer;
      }

      function distortionCurve(amount = 1.6) {
        const curve = new Float32Array(256);
        const k = clamp(amount, .1, 8) * 28;
        for (let i = 0; i < curve.length; i++) {
          const x = i / (curve.length - 1) * 2 - 1;
          curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
        }
        return curve;
      }

      function envelope(gain, t, dur, level, attack = .006, release = .035) {
        gain.gain.cancelScheduledValues(t);
        gain.gain.setValueAtTime(0.0001, t);
        gain.gain.exponentialRampToValueAtTime(Math.max(.0001, level), t + attack);
        gain.gain.exponentialRampToValueAtTime(.0001, t + Math.max(attack + release, dur));
      }

      function outputNode(bus = "cockpit") {
        return buses?.[bus] || master;
      }

      function connectAmp(amp, bus = "cockpit", pan = 0) {
        if (!ctx) return;
        if (Math.abs(pan) > .001 && ctx.createStereoPanner) {
          const panner = ctx.createStereoPanner();
          panner.pan.value = clamp(pan, -1, 1);
          amp.connect(panner).connect(outputNode(bus));
        } else {
          amp.connect(outputNode(bus));
        }
      }

      function smoothParam(param, value, lag = .08) {
        if (!ctx || !param) return;
        param.setTargetAtTime(Math.max(.00001, value), ctx.currentTime, lag);
      }

      function applyMasterVolume(lag = .035) {
        if (!ctx || !master) return;
        master.gain.setTargetAtTime(masterTargetVolume(), ctx.currentTime, lag);
      }

      function masterTargetVolume() {
        return game.paused ? .00001 : effectiveAudioVolume(game.audioVolume);
      }

      function smoothSignedParam(param, value, lag = .08) {
        if (!ctx || !param) return;
        param.setTargetAtTime(value, ctx.currentTime, lag);
      }

      function spatialAudioFromWorld(pos, range = 1600) {
        if (!pos || !finiteVec3(pos) || !finiteVec3(game.camera?.pos)) return { pan: 0, gain: 1, dist: 0 };
        const rel = cameraTransform(pos, game.camera);
        const dist = len(sub(pos, game.camera.pos));
        const zSpread = Math.abs(rel.z) * .42 + 170;
        return {
          pan: clamp(rel.x / zSpread, -1, 1),
          gain: clamp(1 - dist / Math.max(1, range), 0, 1),
          dist
        };
      }

      function startEngineBed() {
        const c = ensure();
        if (!c || engineBed || !noiseBuffer) return;
        const sub = c.createOscillator();
        const body = c.createOscillator();
        const noiseSrc = c.createBufferSource();
        const subGain = c.createGain();
        const bodyGain = c.createGain();
        const crackleGain = c.createGain();
        const rushGain = c.createGain();
        const damageGain = c.createGain();
        const bodyFilter = c.createBiquadFilter();
        const crackleHp = c.createBiquadFilter();
        const crackleBp = c.createBiquadFilter();
        const rushHp = c.createBiquadFilter();
        const rushLp = c.createBiquadFilter();
        const damageBp = c.createBiquadFilter();
        const engineOut = c.createGain();
        const enginePan = c.createStereoPanner ? c.createStereoPanner() : null;

        sub.type = "sine";
        body.type = "triangle";
        noiseSrc.buffer = noiseBuffer;
        noiseSrc.loop = true;
        bodyFilter.type = "lowpass";
        crackleHp.type = "highpass";
        crackleBp.type = "bandpass";
        crackleBp.Q.value = 11;
        rushHp.type = "highpass";
        rushLp.type = "lowpass";
        damageBp.type = "bandpass";
        damageBp.Q.value = 7;
        engineOut.gain.value = 1;
        for (const g of [subGain, bodyGain, crackleGain, rushGain, damageGain]) g.gain.value = .00001;

        if (enginePan) engineOut.connect(enginePan).connect(outputNode("ship"));
        else engineOut.connect(outputNode("ship"));
        sub.connect(subGain).connect(engineOut);
        body.connect(bodyFilter).connect(bodyGain).connect(engineOut);
        noiseSrc.connect(crackleHp).connect(crackleBp).connect(crackleGain).connect(engineOut);
        noiseSrc.connect(rushHp).connect(rushLp).connect(rushGain).connect(engineOut);
        noiseSrc.connect(damageBp).connect(damageGain).connect(engineOut);
        sub.start();
        body.start();
        noiseSrc.start();
        engineBed = { sub, body, noiseSrc, subGain, bodyGain, crackleGain, rushGain, damageGain, engineOut, enginePan, bodyFilter, crackleHp, crackleBp, rushHp, rushLp, damageBp };
      }

      function updateEngineBed(dt = 0) {
        if (!game.soundEnabled) return;
        if (DEV_DISABLE_ENGINE_EFFECTS) {
          if (engineBed) {
            smoothParam(engineBed.subGain.gain, .00001, .08);
            smoothParam(engineBed.bodyGain.gain, .00001, .08);
            smoothParam(engineBed.crackleGain.gain, .00001, .08);
            smoothParam(engineBed.rushGain.gain, .00001, .08);
            smoothParam(engineBed.damageGain.gain, .00001, .08);
            smoothParam(engineBed.engineOut.gain, .00001, .08);
          }
          return;
        }
        const transitionKind = game.transition?.kind || "";
        const hangarTransition = transitionKind === "launchHangar" || transitionKind === "dockHangar";
        const engineTransition = transitionKind === "launch" || transitionKind === "hyperspace" || transitionKind === "galactic";
        const externalListen = game.viewMode === "ext" || hangarTransition;
        const active = ultraFxEnabled() && !game.playerDestroyed && !externalListen && (!game.docked || engineTransition);
        if (active && !ctx) ensure();
        if (!ctx) return;
        if (active && !engineBed) startEngineBed();
        if (!engineBed) return;
        if (!active) {
          smoothParam(engineBed.subGain.gain, .00001, .08);
          smoothParam(engineBed.bodyGain.gain, .00001, .08);
          smoothParam(engineBed.crackleGain.gain, .00001, .08);
          smoothParam(engineBed.rushGain.gain, .00001, .08);
          smoothParam(engineBed.damageGain.gain, .00001, .08);
          smoothParam(engineBed.engineOut.gain, .00001, .08);
          return;
        }
        const launchHangar = transitionKind === "launchHangar";
        const dockHangar = transitionKind === "dockHangar";
        const transitionP = game.transition ? clamp((game.transition.t || 0) / Math.max(.01, game.transition.dur || 1), 0, 1) : 0;
        const speedNorm = clamp((game.speed || 0) / Math.max(1, game.maxSpeed || 220), 0, 1.35);
        const dockEntry = dockHangar ? smoothstep(.03, .36, transitionP) * (1 - smoothstep(.42, .7, transitionP)) : 0;
        const dockSettle = dockHangar ? smoothstep(.52, .7, transitionP) * (1 - smoothstep(.74, .94, transitionP)) : 0;
        const boost = clamp(game.playerEngineBoost || (launchHangar ? .75 : 0), 0, 1.6);
        const stress = clamp(1 - (Number.isFinite(game.energy) ? game.energy : 100) / 100, 0, 1);
        const heat = clamp((game.cabinTemp || 0) / 100, 0, 1.4);
        const flicker = .72 + Math.sin(ctx.currentTime * (8 + stress * 16)) * .16 + Math.sin(ctx.currentTime * 17.7) * .08;
        const crackle = .55 + Math.max(0, Math.sin(ctx.currentTime * 23.7)) * .24 + Math.max(0, Math.sin(ctx.currentTime * 41.3 + 1.7)) * .16;
        const throttle = active ? clamp(.1 + speedNorm * .68 + boost * .42, 0, 1.45) : 0;
        const fade = active ? 1 : 0;
        const lag = active ? .11 : .22;
        const bodyFreq = dockHangar
          ? 34 + dockEntry * 16 + dockSettle * 7 + stress * 5
          : externalListen ? 58 + speedNorm * 62 + boost * 42 + stress * 8 : 42 + speedNorm * 44 + boost * 28 + stress * 8;
        const pan = launchHangar
          ? -smoothstep(5.2, 7.3, game.transition?.t || 0) * .62
          : dockHangar ? smoothstep(.08, .44, transitionP) * .22
          : 0;

        if (dockHangar) {
          smoothParam(engineBed.sub.frequency, 21 + dockEntry * 7 + dockSettle * 3, lag);
          smoothParam(engineBed.body.frequency, bodyFreq, lag);
          smoothParam(engineBed.bodyFilter.frequency, 115 + dockEntry * 135 + dockSettle * 70, .16);
          smoothParam(engineBed.crackleHp.frequency, 1850 + dockEntry * 520 + heat * 120, .18);
          smoothParam(engineBed.crackleBp.frequency, 2200 + dockEntry * 640, .1);
          smoothParam(engineBed.rushHp.frequency, 1400 + dockEntry * 420, .18);
          smoothParam(engineBed.rushLp.frequency, 2600 + dockEntry * 900, .16);
          smoothParam(engineBed.damageBp.frequency, 260 + stress * 840 + Math.sin(ctx.currentTime * 6.5) * 90, .08);
          smoothParam(engineBed.subGain.gain, fade * (.0012 + dockEntry * .0042 + dockSettle * .0022), lag);
          smoothParam(engineBed.bodyGain.gain, fade * (.001 + dockEntry * .0035 + dockSettle * .002), lag);
          smoothParam(engineBed.crackleGain.gain, fade * (dockEntry * .0016 + dockSettle * .00045) * crackle, .05);
          smoothParam(engineBed.rushGain.gain, fade * dockEntry * .0015, lag);
          smoothParam(engineBed.damageGain.gain, fade * Math.pow(stress, 1.65) * .026 * flicker, .04);
          smoothParam(engineBed.engineOut.gain, .48, .18);
          if (engineBed.enginePan) smoothSignedParam(engineBed.enginePan.pan, pan, .22);
          return;
        }

        smoothParam(engineBed.sub.frequency, 26 + speedNorm * 20 + boost * 18, lag);
        smoothParam(engineBed.body.frequency, bodyFreq, lag);
        smoothParam(engineBed.bodyFilter.frequency, externalListen ? 260 + speedNorm * 340 + boost * 460 : 180 + speedNorm * 260 + boost * 360, .14);
        smoothParam(engineBed.crackleHp.frequency, externalListen ? 2300 + boost * 1200 + heat * 380 : 1450 + boost * 720 + heat * 240, .16);
        smoothParam(engineBed.crackleBp.frequency, externalListen ? 3200 + speedNorm * 640 + boost * 1500 : 2200 + speedNorm * 520 + boost * 1100, .07);
        smoothParam(engineBed.rushHp.frequency, externalListen ? 2400 + boost * 820 : 1800 + boost * 600, .16);
        smoothParam(engineBed.rushLp.frequency, externalListen ? 4200 + boost * 1650 + heat * 520 : 3100 + boost * 1200 + heat * 420, .14);
        smoothParam(engineBed.damageBp.frequency, 260 + stress * 840 + Math.sin(ctx.currentTime * 6.5) * 90, .08);
        smoothParam(engineBed.subGain.gain, fade * (externalListen ? .0018 + throttle * .0055 + boost * .0035 : .004 + throttle * .026 + boost * .012), lag);
        smoothParam(engineBed.bodyGain.gain, fade * (externalListen ? .0016 + throttle * .005 + boost * .0045 : .002 + throttle * .011 + boost * .010), lag);
        smoothParam(engineBed.crackleGain.gain, fade * (externalListen ? .001 + speedNorm * .0022 + boost * .0058 : .00035 + speedNorm * .0012 + boost * .0045) * crackle, .035);
        smoothParam(engineBed.rushGain.gain, fade * (externalListen ? .001 + speedNorm * .0017 + boost * .0062 + heat * .0014 : .00025 + boost * .0032 + heat * .0012), lag);
        smoothParam(engineBed.damageGain.gain, fade * Math.pow(stress, 1.65) * .026 * flicker, .04);
        smoothParam(engineBed.engineOut.gain, externalListen ? .78 : 1, .16);
        if (engineBed.enginePan) smoothSignedParam(engineBed.enginePan.pan, pan, .18);
      }

      function cutsceneExternalEngineTarget() {
        const tr = game.transition;
        const kind = tr?.kind || "";
        if (!ultraFxEnabled() || game.playerDestroyed) return null;
        if (kind === "launchHangar") {
          const t = tr.t || 0;
          const p = clamp(t / Math.max(.01, tr.dur || 1), 0, 1);
          const spool = smoothstep(2, 3, t);
          const exit = smoothstep(4.85, 6.45, t);
          const boost = smoothstep(4.85, 5.45, t);
          const distanceFade = 1 - smoothstep(6.4, 8.1, t);
          const score = clamp((spool * .22 + exit * .62 + boost * .72) * distanceFade, 0, 1.35);
          if (score <= .01) return null;
          return {
            rel: vec(lerp(.08, -.72, smoothstep(5.2, 7.4, t)) * 260, 0, lerp(520, 1900, exit)),
            speed: lerp(65, 520, boost) + exit * 280,
            approach: -smoothstep(5.1, 7.4, t),
            score,
            pan: lerp(.04, -.82, smoothstep(5.1, 7.2, t)),
            source: "hangarLaunch"
          };
        }
        if (kind === "dockHangar") {
          const t = tr.t || 0;
          const entry = smoothstep(.05, 2.65, t) * (1 - smoothstep(3.45, 6.6, t));
          const brake = smoothstep(2.65, 3.75, t) * (1 - smoothstep(5.9, 7.25, t));
          const settle = smoothstep(5.4, 7.15, t) * (1 - smoothstep(7.2, 8.4, t));
          const score = clamp(entry * .62 + brake * .35 + settle * .14, 0, 1.1);
          if (score <= .01) return null;
          return {
            rel: vec(lerp(.55, .06, smoothstep(.3, 3.2, t)) * 240, 0, lerp(1900, 520, smoothstep(.05, 3.55, t))),
            speed: lerp(460, 55, smoothstep(.1, 5.8, t)),
            approach: smoothstep(.05, 2.8, t) * .65 - brake * .4,
            score,
            pan: lerp(.52, .08, smoothstep(.3, 3.4, t)),
            source: "hangarDock"
          };
        }
        if (game.viewMode === "ext" && !game.docked && !tr) {
          const speedNorm = clamp((game.speed || 0) / Math.max(1, game.maxSpeed || 220), 0, 1.45);
          const boost = clamp(game.playerEngineBoost || 0, 0, 1.6);
          return {
            rel: vec(0, 0, 420),
            speed: (game.speed || 0) * (1 + boost * .3),
            approach: -.15 - boost * .25,
            score: clamp(.28 + speedNorm * .42 + boost * .36, 0, 1.12),
            pan: 0,
            source: "externalPlayer"
          };
        }
        return null;
      }

      function startFlybyBed() {
        const c = ensure();
        if (!c || flybyBed || !noiseBuffer) return;
        const body = c.createOscillator();
        const fizzSrc = c.createBufferSource();
        const bodyFilter = c.createBiquadFilter();
        const fizzHp = c.createBiquadFilter();
        const fizzBp = c.createBiquadFilter();
        const bodyGain = c.createGain();
        const fizzGain = c.createGain();
        const out = c.createGain();
        const pan = c.createStereoPanner ? c.createStereoPanner() : null;
        body.type = "triangle";
        fizzSrc.buffer = noiseBuffer;
        fizzSrc.loop = true;
        bodyFilter.type = "lowpass";
        fizzHp.type = "highpass";
        fizzBp.type = "bandpass";
        fizzBp.Q.value = 6.5;
        bodyGain.gain.value = .00001;
        fizzGain.gain.value = .00001;
        out.gain.value = .00001;
        if (pan) out.connect(pan).connect(outputNode("world"));
        else out.connect(outputNode("world"));
        body.connect(bodyFilter).connect(bodyGain).connect(out);
        fizzSrc.connect(fizzHp).connect(fizzBp).connect(fizzGain).connect(out);
        body.start();
        fizzSrc.start();
        flybyBed = { body, fizzSrc, bodyFilter, fizzHp, fizzBp, bodyGain, fizzGain, out, pan };
      }

      function nearestAudibleFlyby() {
        const cutsceneTarget = cutsceneExternalEngineTarget();
        if (cutsceneTarget) return cutsceneTarget;
        if (!ultraFxEnabled() || game.docked || game.transition || !game.objects?.length) return null;
        let best = null;
        let bestScore = 0;
        for (const o of game.objects) {
          if (!o || o.type !== "ship" || !finiteVec3(o.pos)) continue;
          const d = len(sub(o.pos, game.camera.pos));
          if (d > 1150) continue;
          const speed = o.speed || (o.vel ? len(o.vel) : 0);
          const near = clamp(1 - (d - 160) / 990, 0, 1);
          const speedScore = clamp(speed / 260, .18, 1.4);
          const score = near * near * speedScore;
          if (score > bestScore) {
            const rel = cameraTransform(o.pos, game.camera);
            best = { o, rel, d, speed, score, source: "npc" };
            bestScore = score;
          }
        }
        return best;
      }

      function updateFlybyBed(dt = 0) {
        if (!game.soundEnabled) return;
        if (!ultraFxEnabled()) {
          if (!ctx) return;
          if (flybyBed) {
            smoothParam(flybyBed.bodyGain.gain, .00001, .12);
            smoothParam(flybyBed.fizzGain.gain, .00001, .12);
            smoothParam(flybyBed.out.gain, .00001, .12);
          }
          return;
        }
        const target = nearestAudibleFlyby();
        if (target && !ctx) ensure();
        if (!ctx) return;
        if (target && !flybyBed) startFlybyBed();
        if (!flybyBed) return;
        const active = !!target;
        const score = active ? clamp(target.score, 0, 1.2) : 0;
        const pan = active ? (Number.isFinite(target.pan) ? clamp(target.pan, -1, 1) : clamp(target.rel.x / (Math.abs(target.rel.z) * .36 + 140), -1, 1)) : 0;
        const vel = active && target.o?.vel ? target.o.vel : vec();
        const toCamera = active && target.o ? norm(sub(game.camera.pos, target.o.pos)) : vec(0, 0, 1);
        const approach = active ? (Number.isFinite(target.approach) ? clamp(target.approach, -1, 1) : clamp(dot(vel, toCamera) / 320, -1, 1)) : 0;
        const speedNorm = active ? clamp(target.speed / 260, .2, 1.5) : 0;
        const externalPlayer = target?.source === "externalPlayer" || target?.source === "hangarLaunch" || target?.source === "hangarDock";
        smoothParam(flybyBed.body.frequency, (externalPlayer ? 44 : 54) + speedNorm * (externalPlayer ? 46 : 52) + approach * 18, .09);
        smoothParam(flybyBed.bodyFilter.frequency, (externalPlayer ? 280 : 360) + speedNorm * (externalPlayer ? 470 : 520), .12);
        smoothParam(flybyBed.fizzHp.frequency, (externalPlayer ? 1550 : 1800) + speedNorm * 900, .12);
        smoothParam(flybyBed.fizzBp.frequency, (externalPlayer ? 2200 : 2600) + speedNorm * 1500 + Math.sin(ctx.currentTime * 5.5) * 180, .07);
        smoothParam(flybyBed.bodyGain.gain, score * (externalPlayer ? .016 : .007), .08);
        smoothParam(flybyBed.fizzGain.gain, score * (externalPlayer ? .034 : .018), .055);
        smoothParam(flybyBed.out.gain, active ? (externalPlayer ? 1 : .9) : .00001, .12);
        if (flybyBed.pan) smoothSignedParam(flybyBed.pan.pan, pan, .08);
      }

      function startTransitionBed() {
        const c = ensure();
        if (!c || transitionBed || !noiseBuffer) return;
        const pressure = c.createOscillator();
        const drive = c.createOscillator();
        const noiseSrc = c.createBufferSource();
        const pressureGain = c.createGain();
        const driveGain = c.createGain();
        const tunnelGain = c.createGain();
        const crackleGain = c.createGain();
        const pressureFilter = c.createBiquadFilter();
        const driveFilter = c.createBiquadFilter();
        const tunnelHp = c.createBiquadFilter();
        const tunnelBp = c.createBiquadFilter();
        const crackleHp = c.createBiquadFilter();
        const crackleBp = c.createBiquadFilter();
        const pan = c.createStereoPanner ? c.createStereoPanner() : null;

        pressure.type = "sine";
        drive.type = "triangle";
        noiseSrc.buffer = noiseBuffer;
        noiseSrc.loop = true;
        pressureFilter.type = "lowpass";
        driveFilter.type = "lowpass";
        tunnelHp.type = "highpass";
        tunnelBp.type = "bandpass";
        tunnelBp.Q.value = 3.2;
        crackleHp.type = "highpass";
        crackleBp.type = "bandpass";
        crackleBp.Q.value = 9;
        for (const g of [pressureGain, driveGain, tunnelGain, crackleGain]) g.gain.value = .00001;

        pressure.connect(pressureFilter).connect(pressureGain).connect(outputNode("ambience"));
        drive.connect(driveFilter).connect(driveGain).connect(outputNode("ambience"));
        const tunnelOut = pan || outputNode("ambience");
        noiseSrc.connect(tunnelHp).connect(tunnelBp).connect(tunnelGain).connect(tunnelOut);
        if (pan) pan.connect(outputNode("ambience"));
        noiseSrc.connect(crackleHp).connect(crackleBp).connect(crackleGain).connect(outputNode("world"));
        pressure.start();
        drive.start();
        noiseSrc.start();
        transitionBed = { pressure, drive, noiseSrc, pressureGain, driveGain, tunnelGain, crackleGain, pressureFilter, driveFilter, tunnelHp, tunnelBp, crackleHp, crackleBp, pan };
      }

      function updateTransitionBed(dt = 0) {
        if (!game.soundEnabled) return;
        const dockedStation = !game.transition && !game.jumpCountdown && game.docked && ultraFxEnabled();
        const source = game.transition || game.jumpCountdown || (dockedStation ? { kind: "stationIdle", t: (performance.now() % 9000) / 1000, dur: 9 } : null);
        const kind = source?.kind || "";
        const countdown = !game.transition && !!game.jumpCountdown && (kind === "hyperspace" || kind === "galactic");
        const transitionActive = !!game.transition && ["hyperspace", "galactic", "launchHangar", "dockHangar"].includes(kind);
        const active = ultraFxEnabled() && !!source && (countdown || transitionActive || dockedStation);
        if (active && !ctx) ensure();
        if (!ctx) return;
        if (active && !transitionBed) startTransitionBed();
        if (!transitionBed) return;
        const p = source ? clamp((source.t || 0) / Math.max(.01, source.dur || 1), 0, 1) : 0;
        const fade = active ? 1 : 0;
        const now = ctx.currentTime;
        const flutter = .72 + Math.sin(now * 13.1) * .14 + Math.sin(now * 27.3 + 1.1) * .08;

        let pressure = 0, drive = 0, tunnel = 0, crackle = 0;
        let pressureFreq = 34, driveFreq = 72, tunnelFreq = 480, tunnelHp = 120, crackleFreq = 2200, pan = 0;
        if (countdown) {
          const big = kind === "galactic";
          const charge = smoothstep(.08, .96, p);
          const pulse = .72 + Math.max(0, Math.sin(now * (big ? 5.4 : 4.2))) * .18;
          pressure = (.006 + charge * .015) * (big ? 1.18 : 1);
          drive = (.005 + charge * .026) * pulse * (big ? 1.22 : 1);
          tunnel = charge * charge * .006;
          crackle = charge * .007 * flutter;
          pressureFreq = 24 + charge * 12;
          driveFreq = 74 + charge * (big ? 420 : 300);
          tunnelHp = 900 + charge * 900;
          tunnelFreq = 1200 + charge * 1800 + Math.sin(now * .5) * 80;
          crackleFreq = 2400 + charge * 2600;
          pan = Math.sin(now * .22) * charge * .12;
        } else if (kind === "hyperspace" || kind === "galactic") {
          const big = kind === "galactic";
          const accel = smoothstep(.04, big ? .24 : .20, p);
          const cruise = smoothstep(.16, .34, p) * (1 - smoothstep(.68, .9, p));
          const arrive = smoothstep(.72, .94, p);
          const burst = Math.max(accel * (1 - smoothstep(.3, .46, p)), arrive);
          pressure = (.018 + accel * .032 + cruise * .022 + arrive * .042) * (big ? 1.18 : 1);
          drive = (.006 + accel * .024 + cruise * .018) * (big ? 1.16 : 1);
          tunnel = (cruise * .052 + burst * .026) * (big ? 1.22 : 1);
          crackle = (burst * .019 + arrive * .027) * flutter * (big ? 1.25 : 1);
          pressureFreq = 26 + accel * 28 + arrive * 20 + (big ? 6 : 0);
          driveFreq = 78 + accel * 130 + cruise * 80 + arrive * 38;
          tunnelHp = 70 + accel * 280 + cruise * 180;
          tunnelFreq = 430 + cruise * (big ? 1850 : 1350) + arrive * 740 + Math.sin(now * (big ? .9 : .7)) * 140;
          crackleFreq = 1800 + burst * 1800 + Math.sin(now * 6.7) * 260;
          pan = Math.sin(now * (big ? .42 : .34)) * (.16 + cruise * .26);
        } else if (kind === "launchHangar" || kind === "dockHangar") {
          const launch = kind === "launchHangar";
          const machinery = smoothstep(.03, .18, p) * (1 - smoothstep(.88, .98, p));
          const fieldAt = launch ? .68 : .18;
          const field = Math.max(0, 1 - Math.abs(p - fieldAt) / .12);
          const motion = launch ? smoothstep(.38, .82, p) : smoothstep(.08, .46, p) * (1 - smoothstep(.68, .9, p));
          const clampHum = launch
            ? smoothstep(.16, .36, p) * (1 - smoothstep(.43, .58, p))
            : smoothstep(.54, .7, p) * (1 - smoothstep(.82, .94, p));
          const stationPulse = .5 + Math.sin(now * 2.15) * .22 + Math.sin(now * .63 + 1.7) * .16;
          const exitBlast = launch
            ? smoothstep(.58, .72, p) * (1 - smoothstep(.76, 1, p))
            : 0;
          const dockBrake = launch ? 0 : smoothstep(.08, .36, p) * (1 - smoothstep(.48, .72, p));
          pressure = (.014 + machinery * .022 + motion * .018) * fade;
          pressure += exitBlast * .038 + dockBrake * .024 + clampHum * (.012 + stationPulse * .006);
          drive = 0;
          tunnel = (field * (launch ? .018 : .026) + exitBlast * .044 + dockBrake * .008 + clampHum * .005) * flutter;
          crackle = (field * .034 + exitBlast * .018 + dockBrake * .012 + clampHum * .007) * flutter;
          pressureFreq = 27 + stationPulse * 5 + (launch ? motion * 18 + exitBlast * 20 : dockBrake * 8 + clampHum * 4);
          driveFreq = launch
            ? 54 + clampHum * 36 + motion * 92 + exitBlast * 150
            : 38 + clampHum * 16 + dockBrake * 24 + Math.sin(now * 1.6) * 4;
          tunnelHp = 620 + field * 600 + exitBlast * 950 + dockBrake * 120;
          tunnelFreq = 900 + field * 1700 + exitBlast * 1500 + dockBrake * 360 + Math.sin(now * 3.4) * 160;
          crackleFreq = 2100 + field * 2600 + exitBlast * 1900 + dockBrake * 620 + Math.sin(now * 11.2) * 240;
          pan = Math.sin(now * .55) * field * .22 + Math.sin(now * .38) * exitBlast * .18 + Math.sin(now * .28) * dockBrake * .12;
        } else if (kind === "stationIdle") {
          const pulse = .54 + Math.sin(now * 1.85) * .22 + Math.sin(now * .47 + 2.1) * .18;
          const duct = .5 + Math.sin(now * .28) * .22;
          pressure = (.022 + pulse * .021) * fade;
          drive = (.008 + duct * .009) * fade;
          tunnel = .0019 * duct;
          crackle = .0012 * Math.max(0, Math.sin(now * 5.2));
          pressureFreq = 25 + pulse * 5;
          driveFreq = 42 + duct * 24;
          tunnelHp = 180;
          tunnelFreq = 520 + duct * 160;
          crackleFreq = 1450 + duct * 380;
          pan = Math.sin(now * .18) * .08;
        }

        smoothParam(transitionBed.pressure.frequency, pressureFreq, .08);
        smoothParam(transitionBed.drive.frequency, driveFreq, .08);
        smoothParam(transitionBed.pressureFilter.frequency, 160 + pressure * 6800, .11);
        smoothParam(transitionBed.driveFilter.frequency, 340 + drive * 9200, .12);
        smoothParam(transitionBed.tunnelHp.frequency, tunnelHp, .1);
        smoothParam(transitionBed.tunnelBp.frequency, tunnelFreq, .08);
        smoothParam(transitionBed.crackleHp.frequency, 1450 + crackle * 26000, .08);
        smoothParam(transitionBed.crackleBp.frequency, crackleFreq, .04);
        const transitionLevel = kind === "stationIdle" ? 2.15 : transitionActive || countdown ? 1.28 : 1;
        smoothParam(transitionBed.pressureGain.gain, fade * pressure * transitionLevel, active ? .08 : .2);
        smoothParam(transitionBed.driveGain.gain, fade * drive * transitionLevel, active ? .08 : .2);
        smoothParam(transitionBed.tunnelGain.gain, fade * tunnel * transitionLevel, active ? .06 : .18);
        smoothParam(transitionBed.crackleGain.gain, fade * crackle * transitionLevel, active ? .035 : .16);
        if (transitionBed.pan) transitionBed.pan.pan.setTargetAtTime(pan, ctx.currentTime, .12);
      }

      function solarRadiationAudioLevel() {
        if (!ultraFxEnabled() || game.docked || game.playerDestroyed) return 0;
        const heat = clamp((game.cabinTemp || 0) / 110, 0, 1.35);
        return clamp(smoothstep(.14, .82, heat), 0, 1);
      }

      function startSolarRadiationBed() {
        const c = ensure();
        if (!c || solarBed || !noiseBuffer) return;
        const sub = c.createOscillator();
        const body = c.createOscillator();
        const hissSrc = c.createBufferSource();
        const subGain = c.createGain();
        const bodyGain = c.createGain();
        const hissGain = c.createGain();
        const out = c.createGain();
        const bodyFilter = c.createBiquadFilter();
        const hissHp = c.createBiquadFilter();
        const hissBp = c.createBiquadFilter();

        sub.type = "sine";
        body.type = "triangle";
        hissSrc.buffer = noiseBuffer;
        hissSrc.loop = true;
        bodyFilter.type = "lowpass";
        hissHp.type = "highpass";
        hissBp.type = "bandpass";
        hissBp.Q.value = 2.6;
        for (const g of [subGain, bodyGain, hissGain, out]) g.gain.value = .00001;

        sub.connect(subGain).connect(out);
        body.connect(bodyFilter).connect(bodyGain).connect(out);
        hissSrc.connect(hissHp).connect(hissBp).connect(hissGain).connect(out);
        out.connect(outputNode("ambience"));
        sub.start();
        body.start();
        hissSrc.start();
        solarBed = { sub, body, hissSrc, subGain, bodyGain, hissGain, out, bodyFilter, hissHp, hissBp };
      }

      function updateSolarRadiationBed(dt = 0) {
        if (!game.soundEnabled) return;
        const level = solarRadiationAudioLevel();
        if (level > .01 && !ctx) ensure();
        if (!ctx) return;
        if (level > .01 && !solarBed) startSolarRadiationBed();
        if (!solarBed) return;
        const now = ctx.currentTime;
        const throb = .62 + Math.sin(now * (1.1 + level * 1.45)) * .22 + Math.sin(now * .37 + 1.4) * .12;
        const shimmer = .72 + Math.sin(now * 5.1) * .14 + Math.sin(now * 13.7 + .8) * .08;
        smoothParam(solarBed.sub.frequency, 18 + level * 9, .18);
        smoothParam(solarBed.body.frequency, 32 + level * 21 + throb * 3, .16);
        smoothParam(solarBed.bodyFilter.frequency, 110 + level * 520, .18);
        smoothParam(solarBed.hissHp.frequency, 760 + level * 1180, .16);
        smoothParam(solarBed.hissBp.frequency, 1250 + level * 3400 + Math.sin(now * 2.1) * 180, .08);
        smoothParam(solarBed.subGain.gain, level * .018 * throb, .12);
        smoothParam(solarBed.bodyGain.gain, level * .027 * throb, .1);
        smoothParam(solarBed.hissGain.gain, Math.pow(level, 1.22) * .018 * shimmer, .07);
        smoothParam(solarBed.out.gain, level > .01 ? .86 : .00001, .2);
      }

      function tone({
        delay = 0, freq = 440, endFreq = null, dur = .12, gain = .08,
        type = "square", attack = .004, release = .035, bus = "cockpit",
        pan = 0, highpass = null, lowpass = null, drive = 0, minFreq = 24
      }) {
        const c = ensure();
        if (!c) return;
        const t = c.currentTime + delay;
        const osc = c.createOscillator();
        const amp = c.createGain();
        let node = osc;
        const floor = Math.max(1, minFreq);
        osc.type = type;
        osc.frequency.setValueAtTime(Math.max(floor, freq * pitchScale), t);
        if (endFreq) osc.frequency.exponentialRampToValueAtTime(Math.max(floor, endFreq * pitchScale), t + Math.max(.01, dur));
        if (highpass != null) {
          const hp = c.createBiquadFilter();
          hp.type = "highpass";
          hp.frequency.setValueAtTime(Math.max(20, highpass * filterScale), t);
          node.connect(hp);
          node = hp;
        }
        if (lowpass != null) {
          const lp = c.createBiquadFilter();
          lp.type = "lowpass";
          lp.frequency.setValueAtTime(Math.max(80, lowpass * filterScale), t);
          node.connect(lp);
          node = lp;
        }
        if (drive > 0) {
          const shaper = c.createWaveShaper();
          shaper.curve = distortionCurve(drive);
          shaper.oversample = "2x";
          node.connect(shaper);
          node = shaper;
        }
        envelope(amp, t, dur, gain, attack, release);
        node.connect(amp);
        connectAmp(amp, bus, pan);
        osc.start(t);
        osc.stop(t + dur + .05);
      }

      function modulatedSquare({
        delay = 0, freq = 48, endFreq = null, lfoFreq = 18, lfoDepth = 12,
        dur = .8, gain = .08, attack = .01, release = .18, bus = "ship",
        lowpass = 680, drive = 2.4, pan = 0
      }) {
        const c = ensure();
        if (!c) return;
        const t = c.currentTime + delay;
        const osc = c.createOscillator();
        const lfo = c.createOscillator();
        const lfoGain = c.createGain();
        const shaper = c.createWaveShaper();
        const lp = c.createBiquadFilter();
        const amp = c.createGain();
        osc.type = "square";
        lfo.type = "sine";
        osc.frequency.setValueAtTime(Math.max(24, freq * pitchScale), t);
        if (endFreq) osc.frequency.exponentialRampToValueAtTime(Math.max(24, endFreq * pitchScale), t + Math.max(.01, dur));
        lfo.frequency.setValueAtTime(Math.max(.1, lfoFreq), t);
        lfoGain.gain.setValueAtTime(lfoDepth * pitchScale, t);
        shaper.curve = distortionCurve(drive);
        shaper.oversample = "2x";
        lp.type = "lowpass";
        lp.frequency.setValueAtTime(Math.max(120, lowpass * filterScale), t);
        envelope(amp, t, dur, gain, attack, release);
        lfo.connect(lfoGain).connect(osc.frequency);
        osc.connect(shaper).connect(lp).connect(amp);
        connectAmp(amp, bus, pan);
        osc.start(t);
        lfo.start(t);
        osc.stop(t + dur + .08);
        lfo.stop(t + dur + .08);
      }

      function noise({
        delay = 0, dur = .16, gain = .08, highpass = 80, lowpass = 6000,
        endLowpass = null, attack = .004, release = .035, bus = "cockpit", pan = 0,
        drive = 0, minHighpass = 20, minLowpass = 120
      }) {
        const c = ensure();
        if (!c || !noiseBuffer) return;
        const t = c.currentTime + delay;
        const src = c.createBufferSource();
        const hp = c.createBiquadFilter();
        const lp = c.createBiquadFilter();
        const amp = c.createGain();
        src.buffer = noiseBuffer;
        src.loop = true;
        hp.type = "highpass";
        hp.frequency.setValueAtTime(Math.max(minHighpass, highpass * filterScale), t);
        lp.type = "lowpass";
        lp.frequency.setValueAtTime(Math.max(minLowpass, lowpass * filterScale), t);
        if (endLowpass) lp.frequency.exponentialRampToValueAtTime(Math.max(minLowpass, endLowpass * filterScale), t + Math.max(.01, dur));
        envelope(amp, t, dur, gain, attack, release);
        src.connect(hp).connect(lp);
        if (drive > 0) {
          const shaper = c.createWaveShaper();
          shaper.curve = distortionCurve(drive);
          shaper.oversample = "2x";
          lp.connect(shaper).connect(amp);
        } else {
          lp.connect(amp);
        }
        connectAmp(amp, bus, pan);
        src.start(t);
        src.stop(t + dur + .05);
      }

      function rumble({ delay = 0, strength = 1, dur = .8, bus = "world", pan = 0 }) {
        const c = ensure();
        if (!c || strength <= .02) return;
        const t = c.currentTime + delay;
        const level = clamp(strength, 0, 1.8);
        const sub = c.createOscillator();
        const sub2 = c.createOscillator();
        const body = c.createOscillator();
        const amp = c.createGain();
        const shaper = c.createWaveShaper();
        const curve = new Float32Array(256);
        for (let i = 0; i < curve.length; i++) {
          const x = i / (curve.length - 1) * 2 - 1;
          curve[i] = Math.tanh(x * 1.6);
        }
        shaper.curve = curve;
        sub.type = "sine";
        sub2.type = "sine";
        body.type = "triangle";
        sub.frequency.setValueAtTime(28, t);
        sub.frequency.exponentialRampToValueAtTime(14, t + dur * 1.12);
        sub2.frequency.setValueAtTime(20, t + .08);
        sub2.frequency.exponentialRampToValueAtTime(11.5, t + dur * 1.18);
        body.frequency.setValueAtTime(42, t);
        body.frequency.exponentialRampToValueAtTime(20, t + dur);
        envelope(amp, t, dur * 1.32, .064 * level, .03, .42);
        sub.connect(shaper);
        sub2.connect(shaper);
        body.connect(shaper);
        shaper.connect(amp);
        connectAmp(amp, bus, pan);
        sub.start(t);
        sub2.start(t + .08);
        body.start(t + .015);
        sub.stop(t + dur * 1.32 + .12);
        sub2.stop(t + dur * 1.36 + .12);
        body.stop(t + dur * 1.28 + .12);
        noise({ delay: delay + .035, dur: dur * 1.28, gain: .066 * level, highpass: 10, lowpass: 92, attack: .045, release: .5, bus, pan });
      }

      function sparkTicks({ count = 5, dur = .38, gain = .025, bus = "weapons", pan = 0 }) {
        for (let i = 0; i < count; i++) {
          const delay = Math.random() * dur;
          const f = 520 + Math.random() * 1800;
          tone({ delay, freq: f, endFreq: f * (.62 + Math.random() * .26), dur: .025 + Math.random() * .045, gain: gain * (.55 + Math.random()), type: "triangle", attack: .001, release: .025, bus, pan: clamp(pan + (Math.random() - .5) * .35, -1, 1), highpass: 260 });
        }
      }

      function explosionRumble(pos, magnitude = 1) {
        const d = len(sub(pos, game.camera.pos));
        const near = clamp(1 - d / 2300, 0, 1);
        const through = clamp(1 - d / 650, 0, 1);
        const strength = clamp(magnitude * (.24 + near * near * .9 + through * through * 1.28), 0, 1.8);
        if (strength < .08) return;
        rumble({ strength, dur: .9 + strength * .82 });
      }

      function playUltra(name, opts = {}) {
        const spatialGain = clamp(opts.gain ?? 1, 0, 1.6);
        const spatialPan = clamp(opts.pan ?? 0, -1, 1);
        const jitterPan = (amount = .25) => clamp(spatialPan + (Math.random() - .5) * amount, -1, 1);
        switch (name) {
          case "laser":
          case "laserPulse":
            tone({ freq: 170, endFreq: 82, dur: .07, gain: .105, type: "square", attack: .001, release: .025, bus: "weapons", lowpass: 1600 });
            tone({ delay: .018, freq: 920, endFreq: 260, dur: .12, gain: .048, type: "sawtooth", attack: .001, bus: "weapons", highpass: 260, lowpass: 7200 });
            noise({ delay: .006, dur: .13, gain: .04, highpass: 980, lowpass: 8800, endLowpass: 2600, attack: .001, bus: "weapons" });
            return true;
          case "laserBeam":
            tone({ freq: 285, endFreq: 210, dur: .16, gain: .068, type: "sawtooth", attack: .004, release: .045, bus: "weapons", lowpass: 1200 });
            tone({ delay: .015, freq: 820, endFreq: 620, dur: .12, gain: .038, type: "triangle", attack: .002, bus: "weapons", highpass: 300, lowpass: 4800 });
            noise({ delay: .004, dur: .16, gain: .035, highpass: 520, lowpass: 7200, endLowpass: 2600, attack: .006, bus: "weapons" });
            return true;
          case "laserMilitary":
            tone({ freq: 210, endFreq: 54, dur: .18, gain: .12, type: "sawtooth", attack: .001, release: .055, bus: "weapons", lowpass: 1400 });
            tone({ delay: .026, freq: 1180, endFreq: 190, dur: .16, gain: .052, type: "sawtooth", attack: .001, bus: "weapons", highpass: 320, lowpass: 7600 });
            noise({ delay: .002, dur: .18, gain: .05, highpass: 360, lowpass: 9200, endLowpass: 1700, attack: .001, bus: "weapons" });
            sparkTicks({ count: 3, dur: .14, gain: .014 });
            return true;
          case "laserMining":
            tone({ freq: 132, endFreq: 58, dur: .46, gain: .105, type: "sawtooth", attack: .018, release: .12, bus: "weapons", lowpass: 900 });
            tone({ delay: .055, freq: 72, endFreq: 42, dur: .42, gain: .062, type: "triangle", attack: .028, release: .16, bus: "weapons" });
            noise({ delay: .018, dur: .42, gain: .07, highpass: 45, lowpass: 2600, endLowpass: 900, attack: .02, release: .16, bus: "weapons" });
            sparkTicks({ count: 7, dur: .38, gain: .012 });
            return true;
          case "enemyLaser":
            {
              const cls = opts.laserClass || "medium";
              const pan = opts.spatial ? jitterPan(cls === "heavy" ? .16 : .24) : (Math.random() - .5) * .7;
              const heavy = cls === "heavy";
              const alien = cls === "alien";
              const beam = cls === "beam";
              const light = cls === "light";
              tone({
                freq: alien ? 420 : heavy ? 310 : beam ? 610 : light ? 720 : 520,
                endFreq: alien ? 820 : heavy ? 72 : beam ? 330 : light ? 210 : 110,
                dur: heavy ? .2 : beam ? .17 : alien ? .22 : .14,
                gain: (heavy ? .078 : alien ? .07 : light ? .044 : .06) * spatialGain,
                type: heavy || beam ? "sawtooth" : "triangle",
                attack: .001,
                bus: "weapons",
                pan,
                highpass: heavy ? 90 : 180,
                lowpass: alien ? 6800 : heavy ? 4600 : 5200,
                drive: heavy ? .8 : 0
              });
              if (heavy) tone({ delay: .018, freq: 1200, endFreq: 190, dur: .16, gain: .032 * spatialGain, type: "sawtooth", attack: .001, bus: "weapons", pan, highpass: 320, lowpass: 7600 });
              noise({ dur: heavy ? .14 : alien ? .16 : .1, gain: (heavy ? .048 : alien ? .041 : light ? .022 : .032) * spatialGain, highpass: alien ? 920 : 640, lowpass: alien ? 9000 : 7600, endLowpass: alien ? 2600 : 1800, attack: .001, bus: "weapons", pan });
            }
            return true;
          case "hit":
            noise({ dur: .98, gain: .107 * spatialGain, highpass: 118, lowpass: 1235, endLowpass: 1324, attack: .01, release: .14, bus: "ship", pan: spatialPan });
            tone({ freq: 96, endFreq: 77, dur: 2.2, gain: .018 * spatialGain, type: "triangle", attack: .24, release: .7, bus: "ship", lowpass: 618, pan: clamp(spatialPan - .08, -1, 1) });
            noise({ dur: 3.68, gain: .009 * spatialGain, highpass: 235, lowpass: 912, attack: .2, release: .335, bus: "ship", pan: clamp(spatialPan + .08, -1, 1), drive: 1.2 });
            tone({ freq: 116, dur: .87, gain: .04 * spatialGain, type: "sine", attack: .01, release: .08, bus: "ship", lowpass: 1765, pan: spatialPan });
            return true;
          case "explosion":
            noise({ dur: 1.05, gain: .15 * spatialGain, highpass: 32, lowpass: 3235, endLowpass: 853, attack: .001, release: .34, bus: "world", pan: spatialPan });
            tone({ delay: .05, freq: 63, endFreq: 24, dur: .28, gain: .157 * spatialGain, type: "sawtooth", attack: .001, release: .28, bus: "world", lowpass: 1059, drive: .4, pan: spatialPan });
            sparkTicks({ count: 9, dur: .62, gain: .002 * spatialGain, bus: "world", pan: spatialPan });
            rumble({ strength: .82 * spatialGain, dur: 1.15, pan: spatialPan });
            return true;
          case "death":
            noise({ dur: 1.75, gain: .18, highpass: 18, lowpass: 1600, endLowpass: 340, attack: .001, release: .55, bus: "world" });
            tone({ freq: 118, endFreq: 18, dur: 1.65, gain: .095, type: "sawtooth", attack: .001, release: .46, bus: "world", lowpass: 760 });
            rumble({ delay: .03, strength: 1.28, dur: 1.55 });
            sparkTicks({ count: 16, dur: 1.05, gain: .022, bus: "world" });
            return true;
          case "missile":
            tone({ freq: 96, endFreq: 420, dur: .32, gain: .075, type: "sawtooth", attack: .008, release: .075, bus: "weapons", lowpass: 1600 });
            noise({ delay: .03, dur: .4, gain: .06, highpass: 80, lowpass: 4200, endLowpass: 1800, attack: .02, release: .16, bus: "weapons" });
            return true;
          case "cargoScoop":
            tone({ freq: 74, endFreq: 46, dur: .18, gain: .06, type: "triangle", attack: .002, release: .09, bus: "ship", lowpass: 520 });
            noise({ delay: .012, dur: .16, gain: .052, highpass: 28, lowpass: 740, endLowpass: 260, attack: .002, release: .08, bus: "ship", drive: .9 });
            tone({ delay: .11, freq: 185, endFreq: 92, dur: .34, gain: .032, type: "sawtooth", attack: .012, release: .13, bus: "ship", lowpass: 980, drive: .7 });
            noise({ delay: .18, dur: .48, gain: .024, highpass: 520, lowpass: 2600, endLowpass: 880, attack: .018, release: .2, bus: "ship", drive: 1.1 });
            tone({ delay: .32, freq: 58, endFreq: 34, dur: .26, gain: .05, type: "triangle", attack: .004, release: .11, bus: "ship", lowpass: 420 });
            sparkTicks({ count: 3, dur: .22, gain: .006, bus: "ship", pan: -.08 });
            return true;
          case "launch":
            tone({ freq: 72, endFreq: 260, dur: .9, gain: .075, type: "sawtooth", attack: .04, release: .22, bus: "ship", lowpass: 1050 });
            noise({ delay: .05, dur: .95, gain: .07, highpass: 34, lowpass: 3400, endLowpass: 1650, attack: .04, release: .26, bus: "ship" });
            rumble({ delay: .08, strength: .46, dur: .85, bus: "ship" });
            return true;
          case "launchSpool":
            modulatedSquare({ freq: 42, endFreq: 58, lfoFreq: 3.4, lfoDepth: 2.8, dur: 1.15, gain: .036, attack: .12, release: .34, bus: "ship", lowpass: 328, drive: .5 });
            noise({ delay: .08, dur: 1.18, gain: .038, highpass: 693, lowpass: 2823, endLowpass: 5645, attack: .16, release: .42, bus: "ship", drive: 1.4 });
            sparkTicks({ count: 8, dur: .9, gain: .004, bus: "ship" });
            rumble({ delay: .08, strength: .34, dur: 1.05, bus: "ship" });
            return true;
          case "blastOff":
            modulatedSquare({ freq: 32, endFreq: 24, lfoFreq: 9.9, lfoDepth: 20.6, dur: 1.28, gain: .088, attack: .001, release: .22, bus: "ship", lowpass: 565, drive: 3.2 });
            modulatedSquare({ delay: .05, freq: 58, endFreq: 98, lfoFreq: 6.3, lfoDepth: 86.2, dur: 1.95, gain: .052, attack: .007, release: .28, bus: "ship", lowpass: 693, drive: 4.1 });
            noise({ dur: 1.04, gain: .029, highpass: 2480, lowpass: 1131, endLowpass: 22156, attack: .03, release: 1.805, bus: "ship", drive: 2.5 });
            rumble({ delay: .14, strength: 1.46, dur: 1.18, bus: "ship" });
            return true;
          case "hangarServo":
            tone({ freq: 82, endFreq: 132, dur: .48, gain: .046, type: "triangle", attack: .018, release: .14, bus: "world", lowpass: 780, pan: -.16 });
            tone({ delay: .045, freq: 205, endFreq: 96, dur: .42, gain: .024, type: "sawtooth", attack: .018, release: .16, bus: "world", lowpass: 1150, pan: .18 });
            noise({ delay: .02, dur: .48, gain: .032, highpass: 55, lowpass: 1450, endLowpass: 520, attack: .018, release: .18, bus: "world", pan: .08 });
            return true;
          case "clampRelease":
            tone({ freq: 56, endFreq: 38, dur: .3, gain: .082, type: "triangle", attack: .002, release: .16, bus: "ship", lowpass: 510.6 });
            tone({ delay: .16, freq: 25, endFreq: 223, dur: .42, gain: .072, type: "sine", attack: .001, release: .22, bus: "ship", minFreq: 16 });
            noise({ delay: .006, dur: 1.73, gain: .053, highpass: 21.9, lowpass: 565.3, endLowpass: 136.8, attack: .09, release: .095, bus: "ship", minHighpass: 1, minLowpass: 1 });
            sparkTicks({ count: 3, dur: .13, gain: .009, bus: "ship" });
            return true;
          case "clampEngage":
            tone({ freq: 42, endFreq: 30, dur: .36, gain: .074, type: "triangle", attack: .001, release: .19, bus: "ship", lowpass: 520 });
            noise({ delay: .01, dur: .2, gain: .072, highpass: 22, lowpass: 480, endLowpass: 130, attack: .001, release: .12, bus: "ship" });
            tone({ delay: .12, freq: 118, endFreq: 68, dur: .28, gain: .036, type: "triangle", attack: .004, release: .12, bus: "world", lowpass: 820 });
            return true;
          case "hyperspace":
            tone({ freq: 74, endFreq: 920, dur: 1.05, gain: .075, type: "sawtooth", attack: .025, release: .14, bus: "ambience", lowpass: 2600 });
            tone({ delay: .14, freq: 180, endFreq: 1480, dur: .98, gain: .052, type: "triangle", attack: .025, bus: "ambience", highpass: 90, lowpass: 6200 });
            noise({ delay: .02, dur: 1.18, gain: .072, highpass: 120, lowpass: 9800, endLowpass: 3400, attack: .025, release: .22, bus: "ambience" });
            rumble({ delay: .02, strength: .54, dur: 1.05, bus: "ambience" });
            return true;
          case "bomb":
            noise({ dur: .82, gain: .17, highpass: 70, lowpass: 9800, endLowpass: 880, attack: .001, release: .28, bus: "world" });
            tone({ freq: 58, endFreq: 18, dur: .9, gain: .095, type: "sawtooth", attack: .001, release: .28, bus: "world", lowpass: 780 });
            rumble({ strength: 1.05, dur: 1.05 });
            sparkTicks({ count: 8, dur: .4, gain: .018, bus: "world" });
            return true;
          default:
            return false;
        }
      }

      function play(name, opts = {}) {
        if (!game.soundEnabled) return;
        if (ultraFxEnabled() && playUltra(name, opts)) return;
        switch (name) {
          case "boop":
            tone({ freq: 150, endFreq: 120, dur: .32, gain: .07 });
            break;
          case "beep":
            tone({ freq: 920, endFreq: 780, dur: .09, gain: .07 });
            break;
          case "laser":
            tone({ freq: 1180, endFreq: 260, dur: .16, gain: .075 });
            tone({ delay: .035, freq: 540, endFreq: 180, dur: .13, gain: .045, type: "sawtooth" });
            noise({ dur: .09, gain: .035, highpass: 900, lowpass: 9000 });
            break;
          case "laserPulse":
            tone({ freq: 920, endFreq: 210, dur: .15, gain: .07 });
            noise({ dur: .07, gain: .028, highpass: 850, lowpass: 7800 });
            break;
          case "laserBeam":
            tone({ freq: 680, endFreq: 520, dur: .11, gain: .045, type: "sawtooth" });
            tone({ delay: .025, freq: 1040, endFreq: 860, dur: .08, gain: .03 });
            noise({ dur: .09, gain: .024, highpass: 1000, lowpass: 9500 });
            break;
          case "laserMilitary":
            tone({ freq: 1280, endFreq: 180, dur: .18, gain: .082, type: "sawtooth" });
            tone({ delay: .035, freq: 420, endFreq: 92, dur: .18, gain: .05, type: "triangle" });
            noise({ dur: .12, gain: .04, highpass: 650, lowpass: 8200 });
            break;
          case "laserMining":
            tone({ freq: 260, endFreq: 95, dur: .36, gain: .078, type: "sawtooth", attack: .018 });
            tone({ delay: .05, freq: 130, endFreq: 72, dur: .31, gain: .044, type: "triangle", attack: .025 });
            noise({ dur: .28, gain: .048, highpass: 80, lowpass: 2400, attack: .016 });
            break;
          case "enemyLaser":
            {
              const cls = opts.laserClass || "medium";
              const heavy = cls === "heavy" || cls === "alien";
              const beam = cls === "beam";
              tone({ freq: heavy ? 960 : beam ? 820 : 740, endFreq: heavy ? 120 : beam ? 260 : 190, dur: heavy ? .17 : .13, gain: heavy ? .07 : .055, type: heavy ? "sawtooth" : "square" });
              noise({ dur: heavy ? .1 : .07, gain: heavy ? .034 : .025, highpass: 700, lowpass: heavy ? 8200 : 7000 });
            }
            break;
          case "hit":
            noise({ dur: .2, gain: .085, highpass: 220, lowpass: 4200 });
            tone({ freq: 210, endFreq: 95, dur: .16, gain: .04, type: "triangle" });
            break;
          case "explosion":
            noise({ dur: .95, gain: .14, highpass: 24, lowpass: 1850, attack: .002 });
            tone({ freq: 82, endFreq: 28, dur: .92, gain: .066, type: "sawtooth" });
            break;
          case "death":
            noise({ dur: 1.38, gain: .17, highpass: 20, lowpass: 1320, attack: .002 });
            tone({ freq: 108, endFreq: 22, dur: 1.28, gain: .084, type: "sawtooth" });
            break;
          case "missile":
            tone({ freq: 380, endFreq: 1200, dur: .24, gain: .07 });
            noise({ dur: .2, gain: .035, highpass: 1000, lowpass: 8500 });
            break;
          case "launch":
            tone({ freq: 105, endFreq: 390, dur: .75, gain: .08, type: "sawtooth", attack: .015 });
            noise({ dur: .7, gain: .06, highpass: 65, lowpass: 3200, attack: .02 });
            break;
          case "hyperspace":
            tone({ freq: 120, endFreq: 1180, dur: .85, gain: .075, type: "sawtooth", attack: .02 });
            tone({ delay: .18, freq: 260, endFreq: 1620, dur: .72, gain: .055 });
            noise({ delay: .06, dur: .9, gain: .055, highpass: 500, lowpass: 10000, attack: .02 });
            break;
          case "ecm":
            for (let i = 0; i < 7; i++) tone({ delay: i * .08, freq: i % 2 ? 1220 : 740, endFreq: i % 2 ? 760 : 1400, dur: .07, gain: .045 });
            noise({ dur: .58, gain: .035, highpass: 1300, lowpass: 9000 });
            break;
          case "bomb":
            noise({ dur: .78, gain: .16, highpass: 120, lowpass: 10000, attack: .001 });
            tone({ freq: 70, endFreq: 34, dur: .72, gain: .08, type: "sawtooth" });
            for (let i = 0; i < 4; i++) tone({ delay: i * .06, freq: 480 + i * 220, dur: .055, gain: .045 });
            break;
          case "scoop":
            tone({ freq: 420, endFreq: 620, dur: .09, gain: .05 });
            tone({ delay: .08, freq: 780, endFreq: 640, dur: .08, gain: .045 });
            break;
          case "cargoScoop":
            noise({ dur: .13, gain: .052, highpass: 45, lowpass: 900, attack: .002 });
            tone({ delay: .07, freq: 260, endFreq: 120, dur: .18, gain: .045, type: "triangle" });
            tone({ delay: .21, freq: 120, endFreq: 72, dur: .14, gain: .04, type: "triangle" });
            break;
        }
      }

      function playAt(name, pos, opts = {}) {
        const spatial = spatialAudioFromWorld(pos, opts.range || 1600);
        if (spatial.gain <= .01) return;
        play(name, {
          ...opts,
          spatial: true,
          pan: spatial.pan,
          gain: (opts.gain ?? 1) * (.28 + spatial.gain * .72)
        });
      }

      return {
        play,
        playAt,
        explosionRumble,
        update: (dt) => {
          updateEngineBed(dt);
          updateFlybyBed(dt);
          updateTransitionBed(dt);
          updateSolarRadiationBed(dt);
        },
        resume: () => { ensure(); },
        setVolume: (value, persist = true) => {
          game.audioVolume = normalizeAudioVolume(value);
          if (persist) saveAudioVolumeSetting(game.audioVolume);
          applyMasterVolume();
        },
        setPaused: (value) => {
          game.paused = !!value;
          applyMasterVolume(game.paused ? .02 : .06);
        },
        toggle: () => {
          game.soundEnabled = !game.soundEnabled;
          if (game.soundEnabled) play("beep");
          else if (ctx) ctx.suspend().catch(() => {});
          setMessage(`Sound: ${game.soundEnabled ? "on" : "off"}.`);
        }
      };
    })();

    function flash() {
      const el = byId("flash");
      el.classList.remove("on");
      void el.offsetWidth;
      el.classList.add("on");
    }

    function ensureShipSystems() {
      const legacyShield = Number.isFinite(game.shields) ? game.shields : 100;
      if (!Number.isFinite(game.foreShield)) game.foreShield = legacyShield;
      if (!Number.isFinite(game.aftShield)) game.aftShield = legacyShield;
      if (!Number.isFinite(game.cabinTemp)) game.cabinTemp = 0;
      game.foreShield = clamp(game.foreShield, 0, 100);
      game.aftShield = clamp(game.aftShield, 0, 100);
      game.energy = clamp(Number.isFinite(game.energy) ? game.energy : 100, 0, 100);
      game.shields = Math.min(game.foreShield, game.aftShield);
    }

    function restoreShipSystems() {
      game.energy = 100;
      game.foreShield = 100;
      game.aftShield = 100;
      game.shields = 100;
      game.cabinTemp = 0;
      game.playerDamageMarks = [];
      game._lastHullDamageMarkAt = 0;
    }

    function playerHullRepairNeeded() {
      ensureShipSystems();
      return game.energy < 99.5 || (game.playerDamageMarks?.length || 0) > 0;
    }

    function stationHullRepairLine() {
      return pick([
        "Hull scoring patched. Repair charge waived.",
        "Maintenance crew sealed the hull. Complimentary landing service.",
        "Hull plates pressure-tested and signed off. No charge logged.",
        "Surface damage dressed out. Consider it a courtesy repair."
      ]);
    }

    function makeDockScene(stationName, hullRepaired, repairLine, marks = []) {
      const sys = currentSystem();
      return {
        stationName,
        systemName: sys.name,
        shipModel: playerShipModel(),
        hullRepaired,
        repairLine,
        preRepairMarks: marks.map((m) => ({ ...m })),
        seed: hash32(`dock-scene:${game.galaxy}:${sys.index}:${stationName}:${game.kills}`),
        born: performance.now()
      };
    }

    function syncDockSceneShip() {
      if (!game?.dockScene || !game.docked) return;
      const model = playerShipModel();
      if (game.dockScene.shipModel === model) return;
      const sys = currentSystem();
      game.dockScene.shipModel = model;
      game.dockScene.preRepairMarks = [];
      game.dockScene.seed = hash32(`dock-scene:${game.galaxy}:${sys.index}:${game.dockScene.stationName}:${game.kills}:${model}`);
      game.dockScene.born = performance.now();
    }

    function recordPlayerHullDamage(arc, sourcePos, amount = 1) {
      if (game.docked || game.playerDestroyed) return;
      const now = performance.now();
      if (amount < 1.2 && game._lastHullDamageMarkAt && now - game._lastHullDamageMarkAt < 650) return;
      game._lastHullDamageMarkAt = now;

      const model = MODELS[playerShipModel()];
      const radius = Math.max(42, model ? modelBoundingRadius(model) : 72);
      let localDir;
      if (sourcePos) {
        const worldDir = norm(sub(sourcePos, game.camera.pos));
        localDir = quatRotate(quatConj(ensureCameraQuat(game.camera)), len(worldDir) > .001 ? worldDir : vec(0, 0, arc === "aft" ? -1 : 1));
      } else {
        localDir = vec((Math.random() - .5) * .5, (Math.random() - .5) * .34, arc === "aft" ? -1 : 1);
      }
      localDir = norm(add(localDir, vec((Math.random() - .5) * .2, (Math.random() - .5) * .16, 0)));
      if (arc === "aft" && localDir.z > -.08) localDir = norm(vec(localDir.x, localDir.y, -.42 - Math.abs(localDir.z)));
      if (arc !== "aft" && localDir.z < .08) localDir = norm(vec(localDir.x, localDir.y, .42 + Math.abs(localDir.z)));

      const hit = scale(localDir, radius * (.64 + Math.random() * .18));
      game.playerDamageMarks = game.playerDamageMarks || [];
      game.playerDamageMarks.push({
        x: hit.x,
        y: hit.y,
        z: hit.z,
        radius: clamp(8 + amount * 1.15 + Math.random() * 9, 8, 28),
        severity: clamp(amount / 18, .18, 1),
        at: now
      });
      if (game.playerDamageMarks.length > 28) game.playerDamageMarks.splice(0, game.playerDamageMarks.length - 28);
    }

    function hitArcFromWorld(pos) {
      if (!pos) return "fore";
      return cameraTransform(pos, game.camera).z < 0 ? "aft" : "fore";
    }

    function damagePlayer(amount, reason, options = {}) {
      ensureShipSystems();
      let remaining = Math.max(0, amount);
      const arc = options.arc || hitArcFromWorld(options.sourcePos);
      if (game.godMode) {
        game.foreShield = 100;
        game.aftShield = 100;
        game.shields = 100;
        game.energy = 100;
        return arc;
      }
      if (!options.bypassShields) {
        if (options.shieldMode === "both") {
          for (let pass = 0; pass < 2 && remaining > .0001; pass++) {
            const activeBanks = ["foreShield", "aftShield"].filter((key) => game[key] > .0001);
            if (!activeBanks.length) break;
            const share = remaining / activeBanks.length;
            let absorbedThisPass = 0;
            for (const shieldKey of activeBanks) {
              const absorbed = Math.min(game[shieldKey], share);
              game[shieldKey] -= absorbed;
              absorbedThisPass += absorbed;
            }
            remaining -= absorbedThisPass;
            if (absorbedThisPass <= .0001) break;
          }
        } else {
          const shieldKey = arc === "aft" ? "aftShield" : "foreShield";
          const absorbed = Math.min(game[shieldKey], remaining);
          game[shieldKey] -= absorbed;
          remaining -= absorbed;
        }
      }
      if (remaining > 0) {
        game.energy -= remaining;
        recordPlayerHullDamage(arc, options.sourcePos, remaining);
      }
      ensureShipSystems();
      if (game.energy <= 0) destroyPlayer(reason);
      return arc;
    }

    function playerCollisionRadius() {
      const model = MODELS[playerShipModel()];
      return Math.max(38, (model ? modelBoundingRadius(model) : 72) * .58);
    }

    function objectCollisionRadius(o) {
      const modelRadius = MODELS[o?.model] ? modelBoundingRadius(MODELS[o.model]) : 0;
      const base = o?.r || modelRadius || 20;
      if (o.type === "canister" || o.type === "plate" || o.type === "splinter") return Math.max(10, base * .92);
      if (o.type === "boulder" || o.type === "asteroid") return Math.max(16, base * .82);
      return Math.max(14, base * .74);
    }

    function objectCollisionMass(o) {
      const r = objectCollisionRadius(o);
      if (o.type === "ship") return Math.max(1, r * r * .018);
      if (o.type === "asteroid" || o.type === "boulder") return Math.max(1, r * r * .03);
      return Math.max(.35, r * r * .008);
    }

    function collisionBody(o) {
      return o && !o._remove && (
        o.type === "ship" ||
        o.type === "asteroid" ||
        o.type === "boulder" ||
        o.type === "splinter" ||
        ((o.type === "canister" || o.type === "plate") && !game.equipment.fuelScoop)
      );
    }

    function largeCollisionBody(o) {
      return o && !o._remove && (
        o.type === "station" ||
        o.type === "hermit" ||
        o.type === "planet" ||
        o.type === "sun"
      );
    }

    function largeCollisionRadius(o) {
      if (o.type === "planet" || o.type === "sun") return Math.max(80, o.r || 80);
      if (o.type === "station") return Math.max(120, modelBoundingRadius(stationModelFor(o)) * .9);
      if (o.type === "hermit") return Math.max(80, objectCollisionRadius(o) * 1.12);
      return Math.max(80, o.r || objectCollisionRadius(o));
    }

    function inStationDockingCorridor(st) {
      if (!st || st.type !== "station") return false;
      const { center, outward } = stationSlotAxes(st);
      const rel = sub(game.camera.pos, center);
      const depth = dot(rel, outward);
      const lateral = len(sub(rel, scale(outward, depth)));
      const slotFacing = Math.abs(Math.sin(st.rot || 0)) < .45;
      return slotFacing && depth > -190 && depth < 620 && lateral < 180 && game.speed < 115;
    }

    function manualDockingStatus(st, capture = false) {
      if (!st) return { ok: false, reason: "NO STATION" };
      if (st.type !== "station") {
        const rel = cameraTransform(st.pos, game.camera);
        const dist = len(sub(st.pos, game.camera.pos));
        const centered = Math.hypot(rel.x, rel.y) < 55;
        const slow = game.speed < 55;
        return {
          ok: dist < 210 && centered && slow,
          reason: !slow ? "TOO FAST" : !centered ? "BAD APPROACH" : "TOO FAR",
          dist,
          lateral: Math.hypot(rel.x, rel.y),
          depth: dist,
          alignment: centered ? 1 : 0
        };
      }
      const slot = stationSlotFrame(st);
      const inward = scale(slot.outward, -1);
      const rel = sub(game.camera.pos, slot.center);
      const depth = dot(rel, slot.outward);
      const lateral = len(sub(rel, scale(slot.outward, depth)));
      const alignment = dot(forwardVector(game.camera), inward);
      const slotOk = Math.abs(Math.sin(st.rot || 0)) < (capture ? .48 : .5);
      const slow = game.speed < (capture ? 82 : 75);
      const nearDepth = capture ? depth > -115 && depth < 155 : depth > -145 && depth < 340;
      const nearLateral = lateral < (capture ? 112 : 140);
      const aligned = alignment > (capture ? .84 : .68);
      const ok = slotOk && slow && nearDepth && nearLateral && aligned;
      const reason = !slow ? "TOO FAST"
        : !slotOk ? "SLOT ROTATION"
          : !nearDepth ? "TOO FAR"
            : !nearLateral || !aligned ? "BAD APPROACH"
              : "TOO FAR";
      return { ok, reason, dist: len(rel), lateral, depth, alignment };
    }

    function inAutoDockStationCorridor(st) {
      if (!st || st.type !== "station" || !game.autoDock) return false;
      const target = dockableTarget();
      if (target !== st) return false;
      const state = typeof game.autoDock === "object" ? game.autoDock : null;
      const stage = state?.stage || "marshal";
      if (stage === "marshal" || stage === "goAround") return false;
      const { center, outward } = stationAutoDockFrame(st);
      const rel = sub(game.camera.pos, center);
      const depth = dot(rel, outward);
      const lateral = len(sub(rel, scale(outward, depth)));
      const lateralLimit = stage === "final" ? 180 : stage === "align" ? 240 : 380;
      return depth > -170 && depth < 980 && lateral < lateralLimit && game.speed < 140;
    }

    function bodyVelocity(o) {
      if (o.vel) return { ...o.vel };
      if (o.type === "ship") return scale(shipForwardWorld(o), o.speed || 0);
      return vec();
    }

    function setBodyVelocity(o, v) {
      if (!o) return;
      const speed = len(v);
      o.vel = speed > .01 ? { ...v } : vec();
      if (o.type === "ship") {
        const prev = o.speed || 0;
        o.speed = clamp(speed, 12, Math.max(24, 180 * (shipStats(o.model).speed || 1)));
        registerShipAcceleration(o, o.speed - prev, 1 / 30);
        if (speed > 6) setNoseDirection(o, v, o.roll || 0);
      }
    }

    function objectIntervalDue(o, key, dt, interval, jitter = 0) {
      if (!o) return true;
      if (o[key] == null) o[key] = 0;
      o[key] -= dt;
      if (o[key] > 0) return false;
      o[key] = interval + Math.random() * jitter;
      return true;
    }

    function registerShipAcceleration(o, deltaSpeed, dt) {
      if (!o || o.type !== "ship") return;
      const accel = deltaSpeed / Math.max(.016, dt || .016);
      const boost = clamp((accel - 8) / 95, 0, 1.35);
      o.engineBoost = Math.max((o.engineBoost || 0) * Math.pow(.16, dt || .016), boost);
    }

    function shipEngineGlowLevel(o, base = null) {
      const speed = o?.speed ?? len(o?.vel || vec());
      const stats = shipStats(o?.model || playerShipModel());
      const max = Math.max(90, 180 * (stats.speed || 1));
      const cruiseGlow = base ?? clamp(speed / max, .22, .78);
      return clamp(cruiseGlow + (o?.engineBoost || 0) * .95, 0, 1.85);
    }

    function resolvedEngineGlowLevel(entity, opts = {}) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return 0;
      if (entity?.engineGlow != null) return clamp(entity.engineGlow, 0, 1.85);
      if (opts.engineGlow != null) return clamp(opts.engineGlow, 0, 1.85);
      if ((entity?.type || "ship") === "ship") return shipEngineGlowLevel(entity);
      return 0;
    }

    function engineDetailVisual(level, stroke = "#ffffff") {
      const glow = clamp(level, 0, 1.85);
      if (glow <= .02) {
        return {
          fill: "#343a37",
          stroke: "rgba(20,24,22,.75)",
          glowAlpha: 0
        };
      }
      const heat = smoothstep(.05, .85, glow);
      const boost = smoothstep(.75, 1.55, glow);
      return {
        fill: `rgb(${Math.round(118 + 129 * heat)},${Math.round(134 + 121 * heat)},${Math.round(142 + 113 * heat)})`,
        stroke: glow > .08 ? stroke : "rgba(92,124,118,.7)",
        glowAlpha: clamp(.3 + glow * .92 + boost * .35, 0, 1.85)
      };
    }

    function resolveBodyBounce(a, b, restitution = .46) {
      const delta = sub(b.pos, a.pos);
      const d = len(delta);
      const ar = objectCollisionRadius(a);
      const br = objectCollisionRadius(b);
      const minD = ar + br;
      if (d >= minD) return false;
      const n = d > .001 ? scale(delta, 1 / d) : norm(vec(Math.random() - .5, Math.random() - .5, Math.random() - .5));
      const overlap = minD - d + .8;
      const am = objectCollisionMass(a);
      const bm = objectCollisionMass(b);
      const total = am + bm || 1;
      a.pos = add(a.pos, scale(n, -overlap * (bm / total)));
      b.pos = add(b.pos, scale(n, overlap * (am / total)));

      const av = bodyVelocity(a);
      const bv = bodyVelocity(b);
      const closing = dot(sub(bv, av), n);
      if (closing < 0) {
        const impulse = -(1 + restitution) * closing / (1 / am + 1 / bm);
        setBodyVelocity(a, sub(av, scale(n, impulse / am)));
        setBodyVelocity(b, add(bv, scale(n, impulse / bm)));
      } else {
        setBodyVelocity(a, sub(av, scale(n, 8 * (bm / total))));
        setBodyVelocity(b, add(bv, scale(n, 8 * (am / total))));
      }
      return true;
    }

    function handlePlayerCollision(o) {
      if (!o || game.docked || game.transition) return;
      if (!collisionBody(o)) return;
      const delta = sub(o.pos, game.camera.pos);
      const d = len(delta);
      const n = d > .001 ? scale(delta, 1 / d) : forwardVector(game.camera);
      const hitRadius = objectCollisionRadius(o) + playerCollisionRadius();
      if (d > hitRadius) return;
      const overlap = hitRadius - d + 1.2;
      const playerMass = Math.max(1.2, playerCollisionRadius() * playerCollisionRadius() * .02);
      const objectMass = objectCollisionMass(o);
      const totalMass = playerMass + objectMass;
      game.camera.pos = add(game.camera.pos, scale(n, -overlap * (objectMass / totalMass)));
      o.pos = add(o.pos, scale(n, overlap * (playerMass / totalMass)));

      const fwd = forwardVector(game.camera);
      const playerVel = scale(fwd, game.speed || 0);
      const objectVel = bodyVelocity(o);
      const closing = dot(sub(objectVel, playerVel), n);
      if (closing < 0) {
        const impulse = -(1 + .42) * closing / (1 / playerMass + 1 / objectMass);
        const bouncedPlayer = sub(playerVel, scale(n, impulse / playerMass));
        const bouncedObject = add(objectVel, scale(n, impulse / objectMass));
        game.speed = clamp(Math.max(0, dot(bouncedPlayer, fwd)), 0, game.maxSpeed);
        setBodyVelocity(o, bouncedObject);
      } else {
        game.speed = clamp(game.speed * .86, 0, game.maxSpeed);
        setBodyVelocity(o, add(objectVel, scale(n, 12)));
      }

      const now = performance.now();
      if (o._playerCollisionAt && now - o._playerCollisionAt < 850) return;
      o._playerCollisionAt = now;
      const objectSpeed = o.speed || (o.vel ? len(o.vel) : 0);
      const impact = clamp(5 + game.speed / 24 + objectSpeed / 70 + (o.r || 20) / 90, 7, 42);
      const arc = damagePlayer(impact, `${o.name || o.type} collision`, { sourcePos: o.pos });
      if (Number.isFinite(o.hp)) {
        o.hp -= impact * (o.type === "ship" ? 1.35 : 2.6);
        if (o.hp <= 0) destroyObject(o, false);
      }
      game.speed = clamp(game.speed - impact * .8, 0, game.maxSpeed);
      const contactPos = add(game.camera.pos, scale(n, playerCollisionRadius()));
      eliteAudio.playAt("hit", contactPos, { range: 1200 });
      addImpactShake(clamp(impact / 15, .8, 2.4));
      setMessage(`${arc === "aft" ? "Aft" : "Fore"} shield collision.`);
    }

    function handlePlayerLargeCollision(o) {
      if (!largeCollisionBody(o) || game.docked || game.transition) return;
      if (o.type === "station" && (inStationDockingCorridor(o) || inAutoDockStationCorridor(o))) return;
      const bodyR = largeCollisionRadius(o);
      const playerR = playerCollisionRadius();
      const delta = sub(game.camera.pos, o.pos);
      const d = len(delta);
      const minD = bodyR + playerR;
      if (d >= minD) return;

      const away = d > .001 ? scale(delta, 1 / d) : scale(forwardVector(game.camera), -1);
      const overlap = minD - d + 2;
      game.camera.pos = add(game.camera.pos, scale(away, overlap));

      const fwd = forwardVector(game.camera);
      const intoSurface = dot(scale(fwd, game.speed || 0), away) < 0;
      const sizeImpact = o.type === "planet" || o.type === "sun" ? 18 : 8;
      const impact = clamp(sizeImpact + (game.speed || 0) / 13 + overlap / 28, 12, o.type === "sun" ? 95 : 62);
      game.speed = clamp(game.speed * (intoSurface ? .16 : .62), 0, game.maxSpeed);

      const now = performance.now();
      if (o._playerCollisionAt && now - o._playerCollisionAt < 900) return;
      o._playerCollisionAt = now;
      const label = o.type === "sun" ? "stellar impact" : o.type === "planet" ? "planetary impact" : `${o.name || o.type} collision`;
      const arc = damagePlayer(impact, label, { sourcePos: o.pos });
      const contactPos = add(game.camera.pos, scale(away, -playerR));
      eliteAudio.playAt("hit", contactPos, { range: 1800, gain: o.type === "sun" || o.type === "planet" ? 1.25 : 1 });
      addImpactShake(clamp(impact / 16, 1, 2.4));
      setMessage(o.type === "sun" ? "STELLAR IMPACT" : o.type === "planet" ? "PLANETARY IMPACT" : `${arc === "aft" ? "Aft" : "Fore"} shield collision.`);
    }

    function collisionCandidatePairs(bodies) {
      if (bodies.length < 10) {
        const pairs = [];
        for (let i = 0; i < bodies.length; i++) {
          for (let j = i + 1; j < bodies.length; j++) pairs.push([bodies[i], bodies[j]]);
        }
        return pairs;
      }
      const cellSize = 720;
      const buckets = new Map();
      const keyFor = (p) => `${Math.floor(p.x / cellSize)},${Math.floor(p.y / cellSize)},${Math.floor(p.z / cellSize)}`;
      for (const body of bodies) {
        const key = keyFor(body.pos);
        const bucket = buckets.get(key);
        if (bucket) bucket.push(body);
        else buckets.set(key, [body]);
      }
      const pairs = [];
      const seen = new Set();
      for (const body of bodies) {
        const cx = Math.floor(body.pos.x / cellSize);
        const cy = Math.floor(body.pos.y / cellSize);
        const cz = Math.floor(body.pos.z / cellSize);
        for (let dx = -1; dx <= 1; dx++) {
          for (let dy = -1; dy <= 1; dy++) {
            for (let dz = -1; dz <= 1; dz++) {
              const bucket = buckets.get(`${cx + dx},${cy + dy},${cz + dz}`);
              if (!bucket) continue;
              for (const other of bucket) {
                if (other === body) continue;
                const a = body._simId;
                const b = other._simId;
                const pairKey = a < b ? `${a}:${b}` : `${b}:${a}`;
                if (seen.has(pairKey)) continue;
                seen.add(pairKey);
                pairs.push([body, other]);
              }
            }
          }
        }
      }
      return pairs;
    }

    function resolveObjectCollisions() {
      const bodies = worldSnapshot().collisionBodies;
      const pairs = collisionCandidatePairs(bodies);
      const now = performance.now();
      for (const [a, b] of pairs) {
        if (a._remove || b._remove) continue;
        const maxD = objectCollisionRadius(a) + objectCollisionRadius(b);
        if (Math.abs(a.pos.x - b.pos.x) > maxD || Math.abs(a.pos.y - b.pos.y) > maxD || Math.abs(a.pos.z - b.pos.z) > maxD) continue;
        if (!resolveBodyBounce(a, b)) continue;
        if ((a._collisionAt && now - a._collisionAt < 700) || (b._collisionAt && now - b._collisionAt < 700)) continue;
        a._collisionAt = now;
        b._collisionAt = now;
        const impact = clamp((len(bodyVelocity(a)) + len(bodyVelocity(b))) / 95, 1.2, 9);
        if (Number.isFinite(a.hp)) a.hp -= impact * (b.type === "ship" ? .75 : 1.15);
        if (Number.isFinite(b.hp)) b.hp -= impact * (a.type === "ship" ? .75 : 1.15);
        if (a.hp <= 0) destroyObject(a, false);
        if (b.hp <= 0) destroyObject(b, false);
      }
    }

    function rechargeShipSystems(dt) {
      ensureShipSystems();
      const energyRate = game.equipment.extraEnergy ? 5.2 : 3.1;
      const shieldRate = game.equipment.extraEnergy ? 7.2 : 4.6;
      game.energy = clamp(game.energy + dt * energyRate, 0, 100);
      for (let i = 0; i < 2; i++) {
        const target = game.foreShield <= game.aftShield ? "foreShield" : "aftShield";
        if (game[target] >= 100 || game.energy <= 4) break;
        const transfer = Math.min(dt * shieldRate * .5, 100 - game[target], Math.max(0, game.energy - 4));
        game[target] += transfer;
        game.energy -= transfer * .72;
      }
      ensureShipSystems();
    }

    function playerAltitude() {
      let nearest = Infinity;
      for (const o of worldSnapshot().planets) {
        nearest = Math.min(nearest, len(sub(o.pos, game.camera.pos)) - (o.r || 0));
      }
      return Number.isFinite(nearest) ? Math.max(0, nearest) : null;
    }

    function updateCabinTemperature(dt) {
      const sun = primarySun();
      let targetHeat = 0;
      if (sun) {
        const heatRadius = sun.heatRadius || sun.r;
        const surfaceDist = Math.max(1, len(sub(sun.pos, game.camera.pos)) - heatRadius * .45);
        targetHeat = clamp(Math.pow((heatRadius * 2.9) / surfaceDist, 2.35) * 30, 0, 125);
      }
      const response = targetHeat > game.cabinTemp ? 1.25 : .42;
      game.cabinTemp += (targetHeat - game.cabinTemp) * clamp(dt * response, 0, 1);
      game.cabinTemp = clamp(game.cabinTemp, 0, 125);
      if (game.cabinTemp > 84 && !game.docked) {
        const excess = (game.cabinTemp - 84) / 16;
        const shieldBefore = (game.foreShield || 0) + (game.aftShield || 0);
        const energyBefore = game.energy || 0;
        damagePlayer(dt * Math.pow(excess, 1.75) * 7.5, "solar over temperature", { shieldMode: "both", sourcePos: sun?.pos });
        if (!game._heatWarnAt || performance.now() - game._heatWarnAt > 1150) {
          game._heatWarnAt = performance.now();
          const shieldAfter = (game.foreShield || 0) + (game.aftShield || 0);
          setMessage(shieldAfter < shieldBefore && game.energy >= energyBefore - .01 ? "SOLAR LOAD ON SHIELDS" : "HULL OVER TEMPERATURE", true);
          flash();
        }
      }
    }

    function updateSolarFuelScoop(o, dt) {
      if (!o || o.type !== "sun" || !game.equipment.fuelScoop || game.docked || game.transition) return;
      if (game.fuel >= 7) return;
      const dist = len(sub(o.pos, game.camera.pos));
      const visibleRadius = largeCollisionRadius(o);
      const clearance = dist - visibleRadius - playerCollisionRadius();
      const heatRadius = o.heatRadius || o.r || visibleRadius;
      const scoopBand = o.scoopBand || Math.max(560, Math.min(1800, heatRadius * .62 + 260));
      if (clearance > scoopBand || clearance < -playerCollisionRadius() * 2) return;
      const strength = smoothstep(scoopBand, 0, Math.max(0, clearance));
      const before = game.fuel;
      game.fuel = clamp(game.fuel + dt * lerp(.08, .32, strength), 0, 7);
      if (game.fuel <= before) return;
      const now = performance.now();
      if (!game._solarScoopAt || now - game._solarScoopAt > 1700) {
        game._solarScoopAt = now;
        eliteAudio.play("scoop");
        setMessage(`Fuel scoops active: ${fmt(game.fuel)} LY.`);
      }
    }

    // A brief, non-interactive animated beat for launch/dock/hyperspace/galactic jump,
    // instead of those all being an instant state snap. update() freezes normal flight
    // control/AI while game.transition is set and advances its timer instead; drawSpace()
    // overlays a transition effect keyed on kind/progress. onComplete runs the actual
    // state change (what each of these functions used to do immediately) once the timer
    // finishes, so save data / game state is never in a "half-jumped" condition.
    function startTransition(kind, dur, onComplete, extra = {}) {
      game.transition = { kind, t: 0, dur, onComplete, ...extra };
    }

    function jumpTransitionProgress(tr) {
      return tr ? clamp(tr.t / tr.dur, 0, 1) : 0;
    }

    function jumpShowcaseBody(camera = game.camera) {
      let best = null;
      for (const o of game.objects) {
        if (!o?.pos || (o.type !== "sun" && o.type !== "planet")) continue;
        const cam = cameraTransform(o.pos, camera);
        if (!Number.isFinite(cam.x) || !Number.isFinite(cam.y) || !Number.isFinite(cam.z)) continue;
        const dist = len(sub(o.pos, camera.pos));
        if (dist < 120 || dist > 90000) continue;
        const sx = cam.x / cam.z;
        const sy = cam.y / cam.z;
        const inFrame = cam.z > 120 && Math.abs(sx) <= 1.35 && Math.abs(sy) <= 1.05;
        const ahead = clamp(dot(norm(sub(o.pos, camera.pos)), forwardVector(camera)), -1, 1);
        const turnPenalty = Math.acos(ahead) / Math.PI;
        const apparent = (o.r || (o.type === "sun" ? 2200 : 900)) / Math.max(1, dist);
        const centred = inFrame ? 1 - clamp(Math.hypot(sx / 1.35, sy / 1.05), 0, 1) : 0;
        const distanceBias = clamp(18000 / dist, .08, 1.2);
        const score = apparent * (o.type === "sun" ? 1.55 : 1.08)
          + distanceBias * (o.type === "sun" ? .9 : .7)
          + centred * .34
          + (inFrame ? .45 : 0)
          - turnPenalty * .38;
        if (!best || score > best.score) best = { o, score };
      }
      return best?.o || null;
    }

    function jumpBodyNavRadius(o) {
      if (!o) return 0;
      const fallback = o.type === "sun" ? 2800 : 1100;
      const base = Math.max(o.r || 0, o.heatRadius || 0, fallback);
      return base * (o.type === "sun" ? 1.28 : 1.38);
    }

    function jumpShowcaseTrajectoryQuat(camera = game.camera, seed = 1) {
      const body = jumpShowcaseBody(camera);
      if (!body) return null;
      const q = ensureCameraQuat(camera);
      const forward = forwardVector(camera);
      const upHint = quatRotate(q, vec(0, 1, 0));
      const toBody = sub(body.pos, camera.pos);
      const dist = Math.max(1, len(toBody));
      const bodyDir = norm(toBody);
      const currentSide = sub(forward, scale(bodyDir, dot(forward, bodyDir)));
      const rng = mulberry(seed || hash32(`${body.type}:${body.name || ""}:${body.pos.x|0}:${body.pos.y|0}:${body.pos.z|0}`));
      let away = len(currentSide) > .02 ? norm(currentSide) : null;
      if (!away) {
        const right = norm(cross(forward, upHint));
        const up = norm(cross(right, forward));
        const a = rng() * TAU;
        away = norm(add(scale(right, Math.cos(a)), scale(up, Math.sin(a))));
      } else if (rng() < .5) {
        away = scale(away, -1);
      }
      const angularRadius = Math.asin(clamp(jumpBodyNavRadius(body) / dist, 0, .96));
      const targetAngle = clamp(
        angularRadius + (body.type === "sun" ? .2 : .16) + rng() * .08,
        body.type === "sun" ? .38 : .34,
        1.22
      );
      const dir = norm(add(scale(bodyDir, Math.cos(targetAngle)), scale(away, Math.sin(targetAngle))));
      return quatLookRotation(dir, upHint);
    }

    function calculateJumpTrajectoryQuat(camera = game.camera, seed = 1) {
      const showcase = jumpShowcaseTrajectoryQuat(camera, seed);
      if (showcase) return showcase;
      const q = ensureCameraQuat(camera);
      const currentForward = forwardVector(camera);
      const upHint = quatRotate(q, vec(0, 1, 0));
      const yawSteps = [-2.45, -2.05, -1.62, -1.18, -.78, -.38, 0, .38, .78, 1.18, 1.62, 2.05, 2.45, Math.PI];
      const pitchSteps = [-1.08, -.78, -.52, -.26, 0, .26, .52, .78, 1.08];
      let bestDir = currentForward;
      let bestScore = -Infinity;
      for (const yaw of yawSteps) {
        for (const pitch of pitchSteps) {
          const cp = Math.cos(pitch);
          const localDir = norm(vec(Math.sin(yaw) * cp, Math.sin(pitch), Math.cos(yaw) * cp));
          const dir = norm(quatRotate(q, localDir));
          let score = dot(dir, currentForward) * .55 - (Math.abs(yaw) + Math.abs(pitch)) * .05;
          for (const o of game.objects) {
            if (!o?.pos) continue;
            const rel = sub(o.pos, camera.pos);
            const dist = len(rel);
            if (dist < 1 || dist > 24000) continue;
            const ahead = dot(norm(rel), dir);
            if (ahead <= .04) continue;
            const miss = dist * Math.sqrt(Math.max(0, 1 - ahead * ahead));
            const baseR = o.r || (o.type === "ship" ? 80 : 120);
            const clearance = baseR
              + (o.type === "sun" ? 4200
                : o.type === "planet" ? 2200
                  : o.type === "station" ? 900
                    : o.type === "ship" ? 260
                      : 180);
            const cone = clearance * (o.type === "sun" || o.type === "planet" ? 2.9 : 2.15);
            if (miss < cone) {
              const severity = (1 - miss / cone) * ahead;
              const weight = o.type === "sun" ? 7.5
                : o.type === "planet" ? 6.2
                  : o.type === "station" ? 4.8
                    : o.type === "ship" ? 2.7
                      : 1.4;
              score -= severity * weight * clamp(12000 / dist, .35, 3.2);
            }
          }
          if (score > bestScore) {
            bestScore = score;
            bestDir = dir;
          }
        }
      }
      return quatLookRotation(bestDir, upHint);
    }

    function jumpDepartureClearanceDistance(q = ensureCameraQuat(game.camera), camera = game.camera) {
      const dir = forwardVector({ q });
      let required = 0;
      for (const o of game.objects) {
        if (!o?.pos || (o.type !== "sun" && o.type !== "planet")) continue;
        const rel = sub(o.pos, camera.pos);
        const along = dot(rel, dir);
        if (along <= 0) continue;
        const sideways = len(sub(rel, scale(dir, along)));
        const radius = jumpBodyNavRadius(o);
        if (sideways < radius) required = Math.max(required, along + radius * 3);
        else if (sideways < Math.max(radius * 2.25, along * .78)) required = Math.max(required, along + radius * 1.8);
      }
      return required;
    }

    function jumpTransitionCameraOffset(tr) {
      if (!tr || !ultraFxEnabled() || (tr.kind !== "hyperspace" && tr.kind !== "galactic")) return 0;
      const p = jumpTransitionProgress(tr);
      const bigJump = tr.kind === "galactic";
      const maxOffset = Math.max(bigJump ? 32000 : 19000, tr.departureClearance || 0);
      const departureEnd = tr.departureEnd ?? (bigJump ? .2 : .24);
      const arrivalAt = tr.arrivalAt ?? .74;
      if (tr._arrived) {
        const t = clamp((p - arrivalAt) / Math.max(.08, 1 - arrivalAt), 0, 1);
        return -maxOffset * (1 - easeInOut(t));
      }
      const solveEnd = Math.min(departureEnd * .22, .045);
      if (p < solveEnd) return 0;
      if (p < departureEnd) return maxOffset * easeInOut((p - solveEnd) / Math.max(.04, departureEnd - solveEnd));
      return maxOffset;
    }

    function jumpDustMotion(tr = game.transition) {
      if (!tr || !ultraFxEnabled() || (tr.kind !== "hyperspace" && tr.kind !== "galactic")) return { speed: 0, travel: 0 };
      const p = jumpTransitionProgress(tr);
      const bigJump = tr.kind === "galactic";
      const departureEnd = tr.departureEnd ?? (bigJump ? .2 : .24);
      const arrivalAt = tr.arrivalAt ?? (bigJump ? .76 : .74);
      const solveEnd = Math.min(departureEnd * .22, .045);
      if (p < solveEnd) return { speed: 0, travel: 0 };
      const speedAt = (x) => {
        if (x < solveEnd) return 0;
        const accel = easeInOut(clamp((x - solveEnd) / Math.max(.04, departureEnd - solveEnd), 0, 1));
        const decel = x < arrivalAt ? 1 : 1 - easeInOut(clamp((x - arrivalAt) / Math.max(.08, 1 - arrivalAt), 0, 1));
        return accel * decel;
      };
      const speed = speedAt(p) * (bigJump ? 1.25 : 1);
      let area = 0;
      const samples = 12;
      let prevX = solveEnd, prevV = speedAt(prevX);
      for (let i = 1; i <= samples; i++) {
        const x = lerp(solveEnd, p, i / samples);
        const v = speedAt(x);
        area += (prevV + v) * .5 * (x - prevX);
        prevX = x;
        prevV = v;
      }
      const travel = area / Math.max(.05, 1 - solveEnd) * (bigJump ? 62000 : 43000);
      return { speed, travel };
    }

    function jumpDepartureStarBoost(tr = game.transition) {
      return jumpDustMotion(tr).speed || 0;
    }

    function jumpDepartureDustTravel(tr = game.transition) {
      return jumpDustMotion(tr).travel || 0;
    }

    function jumpTransitionRenderCamera(renderCam, shipCam, tr) {
      const offset = jumpTransitionCameraOffset(tr);
      if (!Number.isFinite(offset) || Math.abs(offset) < .001) return renderCam;
      return {
        pos: add(renderCam.pos, scale(forwardVector(shipCam), offset)),
        q: renderCam.q
      };
    }

    function captureJumpDepartureStarfield(camera = game.camera) {
      return (game.stars || [])
        .map((star, i) => {
          const p = cameraTransform(star, camera);
          return {
            x: p.x,
            y: p.y,
            z: p.z,
            size: star.size || 1.2,
            hue: star.hue || 205,
            sat: star.sat || 0,
            tw: star.tw || i * 17.31,
            depth: (i * 1103515245 + 12345 >>> 0) / 0xffffffff
          };
        })
        .filter((s) => s.z > 18 && s.z < 5200 && Math.abs(s.x / s.z) < 2.4 && Math.abs(s.y / s.z) < 1.8);
    }

    function arrivalStationFacingQuat(camera = game.camera) {
      const station = dockableTarget();
      if (!station?.pos) return ensureCameraQuat(camera);
      return quatLookRotation(norm(sub(station.pos, camera.pos)), vec(0, 1, 0));
    }

    function startJumpCountdown(kind, dur, label, onComplete, extra = {}) {
      game.jumpCountdown = { kind, t: 0, dur, countdownLabel: label, onComplete, ...extra };
    }

    function updateJumpTrajectoryControl(jc, dt) {
      if (!jc?.trajectoryControl || !ultraFxEnabled()) return;
      if (!jc.fromQ) jc.fromQ = quatNorm(ensureCameraQuat(game.camera));
      if (!jc.trajectoryQ) jc.trajectoryQ = calculateJumpTrajectoryQuat(game.camera);
      const p = clamp(jc.t / jc.dur, 0, 1);
      const settle = easeInOut(p);
      const wobbleWindow = Math.sin(Math.PI * clamp(p, 0, 1));
      const finalCalm = 1 - easeInOut(clamp((p - .72) / .28, 0, 1));
      const amp = (jc.kind === "galactic" ? .105 : .075) * wobbleWindow * (.35 + finalCalm * .65);
      const seed = jc.wobbleSeed || 1;
      const yawWobble = Math.sin(jc.t * 2.15 + seed * .0017) * amp;
      const pitchWobble = Math.sin(jc.t * 2.85 + seed * .0031) * amp * .62;
      const rollWobble = Math.sin(jc.t * 1.55 + seed * .0043) * amp * .45;
      const base = quatSlerp(jc.fromQ, jc.trajectoryQ, settle);
      const wobbleQ = quatMul(
        quatFromAxisAngle(vec(0, 1, 0), yawWobble),
        quatMul(quatFromAxisAngle(vec(1, 0, 0), pitchWobble), quatFromAxisAngle(vec(0, 0, 1), rollWobble))
      );
      game.camera.q = quatNorm(quatMul(base, wobbleQ));
      game.rollRate = game.pitchRate = game.yawRate = 0;
    }

    function updateJumpCountdown(dt) {
      const jc = game.jumpCountdown;
      if (!jc || game.transition) return;
      jc.t += dt;
      updateJumpTrajectoryControl(jc, dt);
      if (jc.t < jc.dur) return;
      game.jumpCountdown = null;
      jc.onComplete();
    }

    const FRESH_DROP_LASER_GRACE_MS = 3500;

    function isProtectedDrop(o) {
      return !!o && (
        o.type === "canister" ||
        o.type === "plate" ||
        o.role === "pod" ||
        o.model === "escapePod"
      );
    }

    function protectFreshDropFromLaser(o, ms = FRESH_DROP_LASER_GRACE_MS) {
      if (isProtectedDrop(o)) o._laserProtectedUntil = performance.now() + ms;
      return o;
    }

    function freshDropLaserProtected(o, now = performance.now()) {
      return isProtectedDrop(o) && Number.isFinite(o._laserProtectedUntil) && now < o._laserProtectedUntil;
    }

    function spawnDeathDebris(pos, count = 7) {
      for (let i = 0; i < count; i++) {
        const isPlate = Math.random() < .55;
        const model = isPlate ? "plate" : "canister";
        const stats = shipStats(model);
        const dir = randomBurstDir(.7);
        game.objects.push(protectFreshDropFromLaser({
          type: isPlate ? "plate" : "canister",
          model,
          name: isPlate ? "HULL PLATE" : "WRECKAGE CANISTER",
          pos: add(pos, scale(dir, 18 + Math.random() * 34)),
          vel: scale(dir, 85 + Math.random() * 210),
          rot: Math.random() * TAU,
          pitch: Math.random() * TAU,
          roll: Math.random() * TAU,
          tumbleRot: (Math.random() - .5) * 3.4,
          tumblePitch: (Math.random() - .5) * 2.6,
          r: stats.r,
          color: isPlate ? "#a9b5aa" : "#ffd33d",
          hp: stats.hp,
          hostile: false,
          _deathCinematic: true
        }));
      }
    }

    function updateDeathTransitionEvents(tr, dt) {
      const pos = tr.deathPos || game.camera.pos;
      game.speed = 0;
      game.camera.pos = { ...pos };
      game.camera.q = tr.deathQuat || game.camera.q;
      if (tr.hadCapsule && !tr._podLaunched && tr.t >= .95) {
        tr._podLaunched = true;
        const podDir = norm(add(quatRotate(tr.deathQuat || ensureCameraQuat(game.camera), vec(.28, .18, -1)), randomBurstDir(.15)));
        const pod = spawnEscapePod(add(pos, scale(podDir, 42)));
        pod.vel = scale(podDir, 235);
        pod._deathCinematic = true;
        spawnEjectFlash(pos);
        eliteAudio.play("launch");
        setMessage("ESCAPE CAPSULE LAUNCHED", true);
      }
      if (!tr._exploded && tr.t >= (tr.hadCapsule ? 1.55 : 1.08)) {
        tr._exploded = true;
        spawnExplosion(pos, 4.2);
        addImpactShake(2.1);
        spawnSmokePuffs(pos, 3.1, 18);
        spawnDeathDebris(pos, 9);
        flash();
      }
      for (const o of game.objects) {
        if (!o._deathCinematic || !o.vel) continue;
        o.pos = add(o.pos, scale(o.vel, dt));
        o.rot = (o.rot || 0) + (o.tumbleRot || .8) * dt;
        o.pitch = (o.pitch || 0) + (o.tumblePitch || .5) * dt;
      }
    }

    function resizeCanvases() {
      const dpr = Math.min(window.devicePixelRatio || 1, game.performance?.dprCap || 2);
      for (const canvas of [space, scanner, foreAftRadar]) {
        const r = canvas.getBoundingClientRect();
        const min = canvas === foreAftRadar ? 80 : 320;
        canvas.width = Math.max(min, Math.floor(r.width * dpr));
        canvas.height = Math.max(canvas === foreAftRadar ? min : 120, Math.floor(r.height * dpr));
      }
    }

    function planetBiomeForSystem(sys) {
      const desc = `${sys.description} ${ECONOMIES[sys.economy]} ${sys.species || ""}`.toLowerCase();
      const has = (words) => words.some((word) => desc.includes(word));
      const rng = mulberry(hash32(`${sys.galaxy}:${sys.index}:${sys.name}:biome`));
      const largeWorld = sys.radius > 6000;
      const smallWorld = sys.radius < 4200;
      const surfaceSpecific = has([
        "ocean", "forest", "rain", "tropical", "mountain", "rock formation",
        "volcano", "earthquake", "dust", "ice", "mud", "plantations"
      ]);
      const scores = { industrial: 0, ocean: 0, desert: 0, rocky: 0, ice: 0, venus: 0, gas: 0 };
      const economyProfiles = [
        { industrial: 4.1, ocean: .45, desert: .3, rocky: .65, ice: .18, venus: .35, gas: .12 },
        { industrial: 3.45, ocean: .55, desert: .55, rocky: .85, ice: .2, venus: .42, gas: .14 },
        { industrial: 2.65, ocean: .35, desert: 1.25, rocky: 1.45, ice: .3, venus: .6, gas: .18 },
        { industrial: 1.8, ocean: .85, desert: 1.75, rocky: 1.25, ice: .35, venus: .8, gas: .18 },
        { industrial: .85, ocean: 2.75, desert: 1.25, rocky: .8, ice: .42, venus: .35, gas: .14 },
        { industrial: .65, ocean: 3.55, desert: .55, rocky: .5, ice: .7, venus: .18, gas: .12 },
        { industrial: .42, ocean: 2.2, desert: 1.65, rocky: 1.45, ice: .9, venus: .4, gas: .16 },
        { industrial: .25, ocean: 1.05, desert: 2.55, rocky: 2.05, ice: 1.1, venus: .5, gas: .18 }
      ][sys.economy] || {};
      for (const [key, value] of Object.entries(economyProfiles)) scores[key] += value;

      if (largeWorld) {
        scores.gas += 2.45 + clamp((sys.radius - 6000) / 650, 0, 2.1);
        scores.ocean += .25;
        if (sys.radius > 6500) scores.gas += 1.15;
      }
      if (smallWorld) {
        scores.rocky += 1.15;
        scores.desert += .8;
        scores.ice += .25;
      }
      if (sys.population >= 42) scores.industrial += 1.25;
      else if (sys.population >= 32) scores.industrial += .65;
      else if (sys.population <= 18) {
        scores.rocky += .55;
        scores.desert += .45;
      }
      if (sys.productivity >= 23000 || sys.tech >= 10) scores.industrial += .85;
      if (sys.productivity <= 9000 && sys.economy >= 5) scores.desert += .45;

      if (has(["ocean", "oceans"])) scores.ocean += 4.2;
      if (has(["forest", "forests", "rain", "tropical", "exuberant", "plantations", "tulip", "banana", "corn", "weed"])) scores.ocean += 2.55;
      if (has(["volcano", "volcanoes"])) scores.venus += 2.35;
      if (has(["mountain", "mountains", "rock formation", "earthquake", "earthquakes"])) scores.rocky += 3.15;
      if (has(["ice", "ice berg", "ice bergs", "bleak", "remote"])) scores.ice += 3.75;
      if (has(["dust", "mud", "revolting"])) scores.venus += 1.15;
      if (has(["dust", "mud", "vacuum", "boring", "dull", "tedious", "unremarkable", "revolting"])) {
        scores.rocky += 1.55;
        scores.desert += 1.45;
      }
      if (has(["casinos", "night life", "parking meters", "discos", "tourists", "food blenders", "civil war"])) scores.industrial += 1.7;
      if (has(["ancient", "fabled", "notable", "pink"]) && largeWorld) scores.gas += .9;
      if (!largeWorld) scores.gas *= .25;
      else if (surfaceSpecific) scores.gas *= .45;

      for (const key of Object.keys(scores)) scores[key] += rng() * 1.1;
      return Object.entries(scores).sort((a, b) => b[1] - a[1])[0][0];
    }

    const DEV_STAR_TYPES = [
      ["auto", "Auto"],
      ["O", "O Class Blue Giant"],
      ["B", "B Class Blue-White"],
      ["A", "A Class White"],
      ["F", "F Class Yellow-White"],
      ["G", "G Class Solar"],
      ["K", "K Class Orange"],
      ["M", "M Class Red Dwarf"],
      ["whiteDwarf", "White Dwarf"],
      ["redGiant", "M Class Red Giant"],
      ["redSupergiant", "M Class Red Supergiant"]
    ];
    const DEV_PLANET_TYPES = [
      ["auto", "Auto"],
      ["ocean", "Blue-Green Ocean"],
      ["desert", "Desert"],
      ["venus", "Venus-Like"],
      ["gas", "Gas Giant"],
      ["ice", "Ice World"],
      ["rocky", "Rocky/Barren"],
      ["industrial", "Industrial"]
    ];
    const DEV_STATION_TYPES = [
      ["auto", "Auto"],
      ["coriolis", "Coriolis"],
      ["dodo", "Dodo"],
      ["rich", "Rich/New Finish"],
      ["poor", "Poor/Rusty Finish"]
    ];

    function stellarProfileForSystem(sys, forcedKind = null) {
      const desc = `${sys.description} ${ECONOMIES[sys.economy]}`.toLowerCase();
      const has = (words) => words.some((word) => desc.includes(word));
      const rng = mulberry(hash32(`${sys.name}:stellar`));
      let kind = "G";
      const profiles = {
        O: { label: "O CLASS BLUE GIANT", hue: 220 + rng() * 14, sat: 72, coreLight: 99, midLight: 88, rimLight: 62, sizeMul: 2.7 + rng() * .85, glowMul: 2.35, corona: .82, flare: .58, spots: 0, distMin: 5.8, distMax: 8.4 },
        B: { label: "B CLASS BLUE-WHITE", hue: 213 + rng() * 12, sat: 58, coreLight: 99, midLight: 86, rimLight: 60, sizeMul: 1.75 + rng() * .5, glowMul: 2.08, corona: .66, flare: .38, spots: .01, distMin: 7.2, distMax: 10.5 },
        A: { label: "A CLASS WHITE", hue: 205 + rng() * 10, sat: 28, coreLight: 99, midLight: 92, rimLight: 70, sizeMul: 1.22 + rng() * .28, glowMul: 1.85, corona: .5, flare: .22, spots: .01, distMin: 8.5, distMax: 12.5 },
        F: { label: "F CLASS YELLOW-WHITE", hue: 50 + rng() * 8, sat: 44, coreLight: 98, midLight: 86, rimLight: 62, sizeMul: 1.04 + rng() * .22, glowMul: 1.68, corona: .44, flare: .16, spots: .03, distMin: 9, distMax: 13.5 },
        G: { label: "G CLASS SOLAR", hue: 43 + rng() * 10, sat: 72, coreLight: 96, midLight: 78, rimLight: 50, sizeMul: .92 + rng() * .22, glowMul: 1.55, corona: .4, flare: .14, spots: .05, distMin: 9, distMax: 14 },
        K: { label: "K CLASS ORANGE", hue: 27 + rng() * 10, sat: 82, coreLight: 90, midLight: 64, rimLight: 36, sizeMul: .78 + rng() * .18, glowMul: 1.56, corona: .4, flare: .13, spots: .07, distMin: 9.5, distMax: 14.5 },
        M: { label: "M CLASS RED DWARF", hue: 6 + rng() * 8, sat: 90, coreLight: 88, midLight: 58, rimLight: 30, sizeMul: .34 + rng() * .1, glowMul: 2.35, corona: .54, flare: .18, spots: .08, distMin: 12, distMax: 18 },
        whiteDwarf: { label: "White Dwarf", hue: 205 + rng() * 20, sat: 30, coreLight: 100, midLight: 96, rimLight: 76, sizeMul: .18 + rng() * .07, glowMul: 3.55, corona: .78, flare: .18, spots: 0, distMin: 18, distMax: 28 },
        redGiant: { label: "M CLASS RED GIANT", hue: 3 + rng() * 16, sat: 90, coreLight: 82, midLight: 48, rimLight: 22, sizeMul: 18 + rng() * 7, heatMul: 1.15, glowMul: 1.06, corona: .14, flare: .5, spots: 0, distMin: 1.62, distMax: 2.16 },
        redSupergiant: { label: "M CLASS RED SUPERGIANT", hue: 1 + rng() * 12, sat: 92, coreLight: 78, midLight: 43, rimLight: 18, sizeMul: 46 + rng() * 18, heatMul: 1.08, glowMul: 1.025, corona: .08, flare: .74, spots: 0, distMin: 1.03, distMax: 1.38 }
      };
      const legacyKinds = {
        redDwarf: "M",
        orangeDwarf: "K",
        yellowDwarf: "G",
        blueWhite: "B"
      };
      if (forcedKind && legacyKinds[forcedKind]) forcedKind = legacyKinds[forcedKind];
      if (forcedKind && profiles[forcedKind]) kind = forcedKind;
      else {
        const weights = {
          O: .45,
          B: 1.25,
          A: 4.6,
          F: 8.5,
          G: 18,
          K: 22,
          M: 24,
          whiteDwarf: 5.4,
          redGiant: 6.2,
          redSupergiant: 1.1
        };
        if (has(["unstable", "fabled", "vast", "mountains"])) {
          weights.O *= 3.2;
          weights.B *= 2.4;
          weights.redSupergiant *= 2.2;
        }
        if (has(["ancient", "remote", "bleak", "notable"])) {
          weights.whiteDwarf *= 2.4;
          weights.redGiant *= 2.1;
          weights.redSupergiant *= 1.7;
        }
        if (has(["pink", "fabled", "cursed", "unusual"])) {
          weights.redGiant *= 1.7;
          weights.redSupergiant *= 2.3;
        }
        if (sys.economy >= 5) {
          weights.M *= 1.55;
          weights.K *= 1.2;
          weights.O *= .75;
          weights.B *= .85;
        } else if (sys.economy <= 2) {
          weights.F *= 1.18;
          weights.G *= 1.25;
          weights.K *= 1.25;
        }
        let total = 0;
        for (const value of Object.values(weights)) total += value;
        let pick = rng() * total;
        for (const [candidate, weight] of Object.entries(weights)) {
          pick -= weight;
          if (pick <= 0) {
            kind = candidate;
            break;
          }
        }
      }
      return { kind, ...profiles[kind], seed: hash32(`${sys.name}:stellar-surface`) };
    }

    function buildSystemBodies(sys) {
      // Positions/sizes are seeded from the system itself (not the visit), so a system
      // always looks the same when you return to it — matching the original's approach
      // of deriving planet/sun placement from the system seed rather than randomising
      // it per arrival. The original spawns the station later when the ship reaches the
      // planet station zone; Ultra keeps a targetable station, but places arrivals far
      // enough away to preserve that lane.
      const rng = mulberry(hash32(`${sys.name}:bodies`));
      // Biome drives deterministic surface rendering. It uses the original Elite
      // system data first, with goat-soup description words as flavour hints.
      const biome = DEV_PLANET_TYPES.some(([id]) => id === game.devPlanetType) && game.devPlanetType !== "auto"
        ? game.devPlanetType
        : planetBiomeForSystem(sys);
      const basePlanetR = lerp(900, 1900, clamp((sys.radius - 2816) / (6912 - 2816), 0, 1));
      const gasScale = biome === "gas" ? 2.55 + rng() * 1.15 : 1;
      const planetR = basePlanetR * (biome === "gas" ? gasScale : biome === "venus" ? .88 : biome === "ice" ? 1.05 : 1);
      const highOrbit = rng() < .46;
      const orbitA = rng() * TAU;
      const planetDir = highOrbit
        ? norm(vec(Math.cos(orbitA) * (1.25 + rng() * 1.35), (rng() > .5 ? 1 : -1) * (.95 + rng() * 1.2), .55 + Math.sin(orbitA) * .55 + rng() * .7))
        : norm(vec((rng() - .5) * 2, (rng() - .5) * 1.1, 1.4 + rng() * 1.2));
      const planetDist = planetR * ((biome === "gas" ? 5.2 : 7.5) + rng() * (biome === "gas" ? 2.2 : 3.5));
      const ringRng = mulberry(hash32(`${sys.galaxy}:${sys.index}:${sys.name}:rings`));
      const debrisRing = biome === "industrial" && ringRng() < .62;
      const gasRingRoll = ringRng();
      const rockyRingRoll = ringRng();
      const iceRingRoll = ringRng();
      const ambientRingRoll = ringRng();
      const hasRing = debrisRing
        || (biome === "gas" && gasRingRoll < .5)
        || (biome === "rocky" && rockyRingRoll < .36)
        || (biome === "ice" && iceRingRoll < .24)
        || (biome !== "gas" && ambientRingRoll < .28);
      const hueBand = (bands) => {
        const band = bands[Math.floor(rng() * bands.length) % bands.length];
        return lerp(band[0], band[1], rng());
      };
      const palette = {
        industrial: { hue: lerp(6, 62, rng()), sat: lerp(6, 30, rng()), light: lerp(8, 24, rng()) },
        desert: { hue: lerp(18, 52, rng()), sat: lerp(38, 72, rng()), light: lerp(40, 66, rng()) },
        ocean: { hue: lerp(178, 224, rng()), sat: lerp(44, 78, rng()), light: lerp(24, 46, rng()) },
        rocky: { hue: lerp(8, 58, rng()), sat: lerp(8, 38, rng()), light: lerp(22, 52, rng()) },
        ice: { hue: lerp(176, 230, rng()), sat: lerp(12, 42, rng()), light: lerp(54, 78, rng()) },
        venus: { hue: hueBand([[18, 58], [290, 330], [150, 188], [205, 236]]), sat: lerp(26, 88, rng()), light: lerp(30, 70, rng()) },
        gas: { hue: hueBand([[12, 58], [320, 354], [82, 142], [184, 228], [260, 292]]), sat: lerp(30, 78, rng()), light: lerp(36, 70, rng()) }
      }[biome];
      const planet = {
        type: "planet", name: sys.name, pos: scale(planetDir, planetDist), r: planetR,
        biome,
        hue: palette.hue,
        sat: palette.sat,
        light: palette.light,
        textureSeed: hash32(`${sys.galaxy}:${sys.index}:${sys.name}:surface`),
        rotAxis: norm(vec((rng() - .5) * .7, 1, (rng() - .5) * .7)),
        rotSpeed: (rng() > .5 ? 1 : -1) * (.003 + rng() * .005),
        rot: rng() * TAU,
        hasRing,
        debrisRing,
        debrisField: debrisRing && ringRng() < .68,
        ringInner: biome === "gas" ? 1.95 + ringRng() * 0.45 : 1.75 + ringRng() * 0.25,
        ringOuter: biome === "gas" ? 3.1 + ringRng() * 1.55 : 2.55 + ringRng() * 0.85,
        ringFlatten: biome === "gas" ? .18 + ringRng() * .12 : .22 + ringRng() * .16,
        ringTilt: (ringRng() - .5) * 1.1,
        hp: 9999, hostile: false
      };
      const stellar = stellarProfileForSystem(sys, game.devStarType !== "auto" ? game.devStarType : null);
      const baseSunR = planetR * lerp(.65, 1.05, rng());
      const sunR = baseSunR * stellar.sizeMul;
      let side = cross(planetDir, vec(0, 1, 0));
      if (len(side) < .001) side = vec(1, 0, 0);
      side = norm(side);
      const upSide = norm(cross(side, planetDir));
      const sunPhase = rng();
      const sunDir = sunPhase < .38
        ? norm(add(scale(planetDir, 1.05 + rng() * .45), add(scale(side, (rng() - .5) * .7), scale(upSide, (rng() - .5) * .55))))
        : sunPhase < .72
          ? norm(add(scale(side, rng() > .5 ? 1 : -1), add(scale(upSide, (rng() - .5) * .9), scale(planetDir, (rng() - .5) * .55))))
          : norm(add(scale(planetDir, -(1.1 + rng() * .55)), add(scale(side, (rng() - .5) * .8), scale(upSide, (rng() - .5) * .55))));
      const heatRadius = baseSunR * (stellar.heatMul || stellar.sizeMul);
      let sunDist = sunR * lerp(stellar.distMin ?? (stellar.kind === "whiteDwarf" ? 14 : 9), stellar.distMax ?? (stellar.kind === "whiteDwarf" ? 20 : 14), rng());
      if (dot(sunDir, planetDir) > .72) sunDist = Math.max(sunDist, planetDist + sunR * 2.4 + planetR);
      const scoopBand = Math.max(560, Math.min(1800, heatRadius * .62 + 260));
      const sun = {
        type: "sun", name: stellar.label.toUpperCase(), pos: scale(sunDir, sunDist), r: sunR,
        heatRadius,
        scoopBand,
        scoopRadius: sunR + scoopBand + 90,
        stellarClass: stellar.kind,
        stellarLabel: stellar.label,
        hue: stellar.hue,
        sat: stellar.sat,
        coreLight: stellar.coreLight,
        midLight: stellar.midLight,
        rimLight: stellar.rimLight,
        glowMul: stellar.glowMul,
        corona: stellar.corona,
        flare: stellar.flare,
        spots: stellar.spots,
        textureSeed: stellar.seed,
        rot: rng() * TAU,
        rotSpeed: (rng() > .5 ? 1 : -1) * (.018 + rng() * .035),
        hp: 9999, hostile: false
      };
      return { planet, sun };
    }

    function stationStyleForSystem(sys) {
      const wealth = 1 - sys.economy / 7;
      const poor = wealth < .32;
      const rich = wealth > .72;
      return {
        wealth,
        base: rich ? "#edf3e9" : poor ? "#9f927d" : "#c8cec3",
        trim: rich ? "#d8fff2" : poor ? "#b56b35" : "#cfd8cf",
        stripe: rich ? "#46dfff" : poor ? "#ffd33d" : "#65ff47",
        grime: clamp(1 - wealth, .08, .92),
        shine: clamp(wealth, .08, .92),
        seed: hash32(`${sys.name}:station-style`)
      };
    }

    function devStationStyleForSystem(sys) {
      if (game.devStationType === "rich") {
        return {
          wealth: .94,
          base: "#edf3e9",
          trim: "#d8fff2",
          stripe: "#46dfff",
          grime: .08,
          shine: .94,
          seed: hash32(`${sys.name}:station-style:dev-rich`)
        };
      }
      if (game.devStationType === "poor") {
        return {
          wealth: .12,
          base: "#9f927d",
          trim: "#b56b35",
          stripe: "#ffd33d",
          grime: .92,
          shine: .12,
          seed: hash32(`${sys.name}:station-style:dev-poor`)
        };
      }
      return stationStyleForSystem(sys);
    }

    function devStationModelForSystem(sys) {
      if (game.devStationType === "dodo") return "dodoStation";
      if (game.devStationType === "coriolis") return "coriolis";
      return sys.tech >= 10 ? "dodoStation" : "coriolis";
    }

    function stationModelFor(o) {
      return o?.model === "dodoStation" ? MODELS.dodoStation : STATION_MODEL;
    }

    function stationSlotVertexIndices(model) {
      // Dodo slot edges are 20-21-23-22; raw vertex order is 20-21-22-23,
      // which draws a crossed hourglass and corrupts slot-frame maths.
      if (model === MODELS.dodoStation) return [20, 21, 23, 22];
      const n = model.verts.length;
      return [n - 4, n - 3, n - 2, n - 1];
    }

    const ROCK_HERMIT_SCENE_CHANCE = 0.04;

    function isDockableStructure(o) {
      return !!o && !o._remove && o.type === "station";
    }

    function stationSlotFrame(st) {
      const model = stationModelFor(st);
      const slot = stationSlotVertexIndices(model).map((i) => {
        const [x, y, z] = model.verts[i];
        return vec(x, y, z);
      });
      const centerLocal = scale(slot.reduce((sum, p) => add(sum, p), vec()), 1 / slot.length);
      let normal = faceNormal(slot[0], slot[1], slot[2]);
      if (normal.z < 0) normal = scale(normal, -1);
      const rot = st?.rot || 0;
      const center = add(st.pos, rotatePoint(centerLocal, 0, 0, rot));
      const outward = norm(rotatePoint(normal, 0, 0, rot));
      const up = norm(rotatePoint(vec(1, 0, 0), 0, 0, rot));
      return { center, outward, up };
    }

    function stationPositionForScene(arrival, rng) {
      // BBC Elite does not place the station in the local bubble immediately after
      // hyperspace; it appears only once the player reaches the planet's station
      // zone. Ultra Elite keeps it targetable, but arrivals should still begin
      // outside the safe zone so the planet lane has room for normal encounters.
      return arrival ? vec(0, 0, 6600 + rng() * 1800) : vec(0, 0, 900);
    }

    function resetFlightScene(arrival = false) {
      const sys = currentSystem();
      game.dockScene = null;
      game.camera = makeCamera(arrival ? -1200 : -850);
      game.speed = 0;
      game.autoDock = false;
      game.jumpCountdown = null;
      const rng = mulberry(hash32(`${game.galaxy}:${game.current}:${game.kills}:${Date.now() >> 12}`));
      const { planet, sun } = buildSystemBodies(sys);
      // Original NWSPS swaps the SST blueprint to a Dodo station at internal
      // tech level 10+, otherwise the station remains Coriolis.
      const stationModel = devStationModelForSystem(sys);
      const stationStyle = devStationStyleForSystem(sys);
      const stationPos = stationPositionForScene(arrival, rng);
      game.objects = [
        {
          type: "station", model: stationModel,
          name: `${sys.name} ${stationModel === "dodoStation" ? "DODO STATION" : "STATION"}`,
          pos: stationPos, basePos: { ...stationPos }, rot: 0, rotSpeed: .34, driftPhase: rng() * TAU,
          r: shipStats(stationModel).r, color: stationStyle.base, stationStyle, hp: 9999, hostile: false
        },
        planet,
        sun
      ];
      // BBC Elite spawns rock hermits from the asteroid/junk path rather than
      // the SST station slot. Keep them rare and away from the station lane so
      // the docking computer never confuses a beaconed asteroid for the main port.
      const hermitRng = mulberry(hash32(`${sys.name}:hermit:${game.galaxy}`));
      if (hermitRng() < ROCK_HERMIT_SCENE_CHANCE) {
        const hermitStats = shipStats("hermit");
        const yaw = hermitRng() * TAU;
        const pitch = (hermitRng() - .5) * .75;
        const dir = norm(vec(Math.sin(yaw) * Math.cos(pitch), Math.sin(pitch), Math.cos(yaw) * Math.cos(pitch)));
        const dist = 3600 + hermitRng() * 2200;
        game.objects.push({
          type: "hermit", model: "hermit", name: `${sys.name} ROCK HERMIT`,
          pos: add(stationPos, scale(dir, dist)),
          basePos: null, rot: hermitRng() * TAU, rotSpeed: .07, tumbleRot: .07, tumblePitch: .035, driftPhase: hermitRng() * TAU,
          r: hermitStats.r, color: "#b9a888", hp: 9999, hostile: false
        });
      }
      const count = arrival ? 1 + Math.floor(rng() * 3) : 1 + Math.floor(rng() * 2);
      for (let i = 0; i < count; i++) spawnShip(rng, false);
      game.trafficClock = 5 + rng() * 8;
      game.extraVesselDelay = arrival ? 0 : 30 + rng() * 24;
      const rockCount = Math.floor(rng() * 3);
      for (let i = 0; i < rockCount; i++) spawnAsteroid(rng, vec(0, 0, 0));
      game.stars = Array.from({ length: 264 }, () => {
        const z = rng() * 3600 - 1300;
        const star = vec((rng() - .5) * 3200, (rng() - .5) * 1800, z);
        const tint = rng();
        star.hue = tint < .15 ? 210 + rng() * 30 : tint < .3 ? 28 + rng() * 20 : 0;
        star.sat = star.hue ? 45 + rng() * 30 : 0;
        star.tw = rng() * TAU;
        star.size = .8 + rng() * 1.1;
        return star;
      });
      game.targetObject = game.objects.find((o) => o.type === "station");
    }

    function extraVesselChanceForGovernment(gov) {
      if (gov <= 0) return 1;
      let allowed = 0;
      for (let a = 0; a < 256; a++) {
        if (a < 90 && ((a & 7) >= gov)) allowed++;
      }
      return allowed / 256;
    }

    function stationSafeZoneActive() {
      const st = game.objects.find((o) => o.type === "station");
      return !!st && len(sub(st.pos, game.camera.pos)) < 5200;
    }

    function spawnExtraVessels(rng = Math.random, liveShipCount = 0) {
      if (game.legal > 15) {
        spawnShip(rng, false);
        game.extraVesselDelay = 10 + rng() * 14;
        return 1;
      }
      const pirateGroup = rng() >= .39;
      if (!pirateGroup) {
        spawnShip(rng, true);
        game.extraVesselDelay = 18 + rng() * 22;
        return 1;
      }
      const count = Math.min(1 + Math.floor(rng() * 4), Math.max(1, 7 - liveShipCount));
      for (let i = 0; i < count; i++) spawnShip(rng, true);
      game.extraVesselDelay = 24 + count * 10 + rng() * 24;
      return count;
    }

    function spawnAmbientEncounter(dt, liveShipCount) {
      game.extraVesselDelay = Math.max(0, (game.extraVesselDelay || 0) - dt);
      if (game.witchspace) return;
      if (Math.random() >= dt * .035 || liveShipCount >= 7) return;
      const safeZone = stationSafeZoneActive();
      const gov = currentSystem().government;
      const extraChance = safeZone ? 0 : extraVesselChanceForGovernment(gov);
      if (game.extraVesselDelay <= 0 && Math.random() < extraChance) {
        spawnExtraVessels(Math.random, liveShipCount);
        return;
      }
      spawnShip(Math.random, false);
    }

    function spawnShip(rng = Math.random, hostile = false) {
      const police = game.legal > 15 && rng() > .45;
      const types = police ? POLICE_MODELS : hostile ? PIRATE_MODELS : TRADER_MODELS;
      const model = types[Math.floor(rng() * types.length)];
      const role = police ? "police" : hostile ? "pirate" : "trader";
      const stats = shipStats(model);
      const orbitRadius = 560 + rng() * 820;
      const orbitCenter = randomPointClearOfStation(rng, orbitRadius + stats.r + 680, 900);
      const orbitAngle = rng() * TAU;
      const o = {
        type: "ship",
        model,
        name: police ? "VIPER POLICE" : `${hostile ? "PIRATE" : "TRADER"} ${shipName(model)}`,
        pos: randomPointClearOfStation(rng, stats.r + 700, 2300),
        vel: vec((rng() - .5) * 36, (rng() - .5) * 24, -18 - rng() * 34),
        rot: rng() * TAU,
        pitch: rng() * TAU,
        roll: rng() * TAU,
        r: stats.r,
        color: shipColor(model, police),
        hp: Math.round(stats.hp * (police ? 1.2 : hostile ? 1.08 : .9)),
        maxHp: Math.round(stats.hp * (police ? 1.2 : hostile ? 1.08 : .9)),
        hostile: hostile || police,
        police,
        role,
        bounty: police ? 0 : hostile ? 75 + Math.floor(rng() * 100) : 0,
        aiMode: police || hostile ? "attack" : (rng() > .55 ? "orbit" : "cruise"),
        orbitCenter,
        orbitRadius,
        orbitAngle,
        orbitSpeed: (rng() > .5 ? 1 : -1) * (.18 + rng() * .28),
        attackClock: rng() * 2,
        wobble: rng() * TAU,
        npcMissiles: npcMissileStock(model, role, police),
        decalSeed: hash32(`${game.galaxy}:${game.current}:${model}:${role}`)
      };
      setNoseDirection(o, o.vel, o.roll);
      game.objects.push(o);
      return o;
    }

    function stationTrafficModels() {
      return ["shuttle", "transporter", "worm", "adder", "gecko", "cobra1", "python"];
    }

    function stationSlotAxes(st) {
      const slot = stationSlotFrame(st);
      let right = cross(slot.up, slot.outward);
      if (len(right) < .01) right = vec(1, 0, 0);
      return { ...slot, right: norm(right) };
    }

    function stationAutoDockFrame(st) {
      return stationSlotAxes(st);
    }

    function spawnStationTraffic(kind = "launch", rng = Math.random) {
      const st = game.objects.find((o) => o.type === "station");
      if (!st) return null;
      const shipCount = game.objects.filter((o) => o.type === "ship").length;
      if (shipCount >= 9) return null;
      const { center, outward, up, right } = stationSlotAxes(st);
      const types = stationTrafficModels();
      const model = types[Math.floor(rng() * types.length)];
      const stats = shipStats(model);
      const role = "trader";
      const name = `TRADER ${shipName(model)}`;
      const slotOffset = add(scale(right, (rng() - .5) * 42), scale(up, (rng() - .5) * 28));
      const launch = kind === "launch";
      const approach = 1300 + rng() * 760;
      const pos = launch
        ? add(center, add(slotOffset, scale(outward, 34)))
        : add(center, add(slotOffset, scale(outward, approach)));
      const dir = launch ? outward : scale(outward, -1);
      const speed = launch ? 42 : 88;
      const o = {
        type: "ship",
        model,
        name,
        pos,
        vel: scale(dir, speed),
        speed,
        rot: 0,
        pitch: 0,
        roll: rng() * .4 - .2,
        r: stats.r,
        color: shipColor(model, false),
        hp: Math.round(stats.hp * .88),
        maxHp: Math.round(stats.hp * .88),
        hostile: false,
        police: false,
        role,
        bounty: 0,
        aiMode: launch ? "stationLaunch" : "stationDock",
        trafficStation: st,
        trafficAge: 0,
        trafficSlotOffset: slotOffset,
        attackClock: rng() * 2,
        wobble: rng() * TAU,
        npcMissiles: 0,
        decalSeed: hash32(`${game.galaxy}:${game.current}:${model}:station-traffic:${Math.floor(rng() * 99999)}`)
      };
      setNoseDirection(o, dir, o.roll);
      game.objects.push(o);
      return o;
    }

    function spawnArmada() {
      if (!game.developerMode) {
        setMessage("Developer mode required for test armada.", true);
        return;
      }
      if (game.transition) return;
      if (game.docked) launch();
      game.objects = game.objects.filter((o) => o.type !== "ship" && o.type !== "canister");
      const center = cameraLocalToWorld(game.camera, vec(0, 0, 3800));
      for (let i = 0; i < ARMADA_MODELS.length; i++) {
        const ring = Math.floor(i / 7);
        const slot = i % 7;
        const angle = slot / 7 * TAU + ring * .34;
        const radius = 230 + ring * 245;
        const local = vec(Math.cos(angle) * radius, Math.sin(angle) * (145 + ring * 70), 3800 + ring * 340 + (slot % 2) * 80);
        const model = ARMADA_MODELS[i];
        const stats = shipStats(model);
        const hostile = ALIEN_MODELS.includes(model) || PIRATE_MODELS.includes(model);
        const role = hostile ? "pirate" : "trader";
        const pos = cameraLocalToWorld(game.camera, local);
        const o = {
          type: "ship",
          model,
          name: `${hostile ? "PIRATE" : "ARMADA"} ${shipName(model)} ${i + 1}`,
          pos,
          vel: scale(norm(sub(pos, center)), 18 + (i % 4) * 7),
          rot: angle + Math.PI,
          pitch: 0,
          roll: angle * .5,
          r: stats.r,
          color: shipColor(model),
          hp: stats.hp,
          maxHp: stats.hp,
          hostile,
          role,
          thargoid: model === "thargoid",
          bounty: hostile ? 90 + i * 8 : 0,
          aiMode: "formation",
          orbitCenter: center,
          orbitRadius: radius,
          orbitAngle: angle,
          orbitSpeed: (i % 2 ? -1 : 1) * (.16 + ring * .04),
          attackClock: 1 + (i % 5) * .35,
          wobble: i * .73,
          npcMissiles: npcMissileStock(model, role, false),
          formationY: local.y,
          formationZ: local.z,
          decalSeed: hash32(`armada:${game.galaxy}:${game.current}:${model}:${role}:${i}`)
        };
        setNoseDirection(o, o.vel, o.roll);
        game.objects.push(o);
      }
      game.targetObject = game.objects.find((o) => o.type === "ship") || game.targetObject;
      setMessage("Test armada deployed.", true);
      renderPanel();
    }

    function launch() {
      if (!game.docked || game.transition || game.jumpCountdown) return;
      const finishLaunch = (startSpeed = 40) => {
        game.docked = false;
        resetFlightScene(false);
        const station = game.objects.find((o) => o.type === "station");
        const slot = station ? stationSlotFrame(station) : null;
        const fromPos = slot ? add(slot.center, scale(slot.outward, 34)) : vec(0, 0, -560);
        const toPos = slot ? add(slot.center, scale(slot.outward, 310)) : vec(0, 0, -980);
        game.camera.pos = { ...toPos };
        game.camera.q = slot ? quatLookRotation(slot.outward, slot.up) : quat();
        game.speed = startSpeed;
        spawnPlayerEnginePlume(2.1);
        commsMessage(stationCommsName(), stationControllerLine("launch"), "station");
        setMessage("Launch complete.", true);
        renderPanel();
        return { station, slot, fromPos, toPos };
      };
      if (ultraFxEnabled()) {
        if (!game.dockScene) game.dockScene = makeDockScene(game.dockedAt || `${currentSystem().name} STATION`, false, "", []);
        syncDockSceneShip();
        eliteAudio.play("beep");
        commsMessage(stationCommsName(), "Clear for take off. Start engines and proceed through the field.", "station");
        startTransition("launchHangar", 8.2, () => {
          finishLaunch(55);
        }, { scene: game.dockScene });
        renderPanel();
        return;
      }
      eliteAudio.play("launch");
      game.docked = false;
      resetFlightScene(false);
      const station = game.objects.find((o) => o.type === "station");
      const slot = station ? stationSlotFrame(station) : null;
      const fromPos = slot ? add(slot.center, scale(slot.outward, 34)) : vec(0, 0, -560);
      const toPos = slot ? add(slot.center, scale(slot.outward, 310)) : vec(0, 0, -980);
      game.camera.pos = { ...fromPos };
      game.camera.q = slot ? quatLookRotation(slot.outward, slot.up) : quat();
      game.speed = 0;
      startTransition("launch", 1.25, () => {
        game.camera.pos = { ...toPos };
        game.camera.q = slot ? quatLookRotation(slot.outward, slot.up) : quat();
        game.speed = 40;
        spawnPlayerEnginePlume(1.6);
        commsMessage(stationCommsName(), stationControllerLine("launch"), "station");
        setMessage("Launch complete.", true);
        renderPanel();
      }, { fromPos, toPos, fromSpeed: 0, toSpeed: 40 });
      renderPanel();
    }

    function dockableTarget() {
      if (isDockableStructure(game.targetObject)) return game.targetObject;
      const stations = worldSnapshot().stations.filter((o) => !o._remove);
      if (stations.length) {
        return stations.reduce((a, b) => len(sub(b.pos, game.camera.pos)) < len(sub(a.pos, game.camera.pos)) ? b : a);
      }
      return null;
    }

    function dock(auto = false) {
      if (game.docked || game.transition || game.jumpCountdown) return;
      const st = dockableTarget();
      if (!st) return;
      const status = manualDockingStatus(st, auto);
      if (auto || status.ok) {
        eliteAudio.play("beep");
        game.speed = 0;
        game.autoDock = false;
        commsMessage(`${st.name.toUpperCase()} CONTROL`, stationControllerLine("dockClear"), "station");
        const finishDockArrival = () => {
          const hullRepaired = playerHullRepairNeeded();
          const repairLine = hullRepaired ? stationHullRepairLine() : "";
          const preRepairMarks = game.playerDamageMarks ? game.playerDamageMarks.map((m) => ({ ...m })) : [];
          game.docked = true;
          setViewMode("fwd");
          game.dockedAt = st.name;
          restoreShipSystems();
          game.fuel = clamp(game.fuel + 0.2, 0, 7);
          game.legal = Math.max(0, game.legal - 2);
          game.dockScene = makeDockScene(st.name, hullRepaired, repairLine, preRepairMarks);
          const completeDock = () => {
            if (!game.dockScene?._sequenceServiceComms) {
              commsMessage(`${st.name.toUpperCase()} CONTROL`, stationControllerLine("dockComplete"), "station");
              if (hullRepaired) commsMessage(`${st.name.toUpperCase()} SERVICE`, repairLine, "station");
            }
            setMessage(hullRepaired ? `Welcome to ${st.name}. Free hull repair complete.` : `Welcome to ${st.name}.`, true);
            renderPanel();
          };
          if (ultraFxEnabled()) startTransition("dockHangar", 10.2, completeDock, { scene: game.dockScene });
          else completeDock();
          renderPanel();
        };
        if (ultraFxEnabled()) finishDockArrival();
        else startTransition("dock", 1.25, finishDockArrival);
      } else {
        const reason = status.reason || "BAD APPROACH";
        eliteAudio.play("boop");
        commsMessage(`${st.name.toUpperCase()} CONTROL`, stationControllerLine("dockDeny", reason), "station");
        setMessage("Docking denied.", true);
      }
    }

    function tryManualDockingCapture() {
      if (game.docked || game.transition || game.jumpCountdown || game.autoDock) return false;
      const st = dockableTarget();
      if (!st) return false;
      if (!manualDockingStatus(st, true).ok) return false;
      dock(true);
      return true;
    }

    function startAutoDock() {
      if (game.docked || game.transition || game.jumpCountdown) return;
      if (!game.equipment.dockingComputer) {
        setMessage("No docking computer fitted.");
        return;
      }
      if (!game.autoDock && !stationSafeZoneActive()) {
        eliteAudio.play("boop");
        setMessage("Docking computer waiting for station safe zone.");
        return;
      }
      game.autoDock = game.autoDock ? false : { stage: "marshal", announced: "" };
      setMessage(game.autoDock ? "Docking computer engaged." : "Docking computer disengaged.");
      commsMessage("TRAFFIC CONTROL", stationControllerLine(game.autoDock ? "autoOn" : "autoOff"), "station");
    }

    function hyperspace() {
      if (game.transition || game.jumpCountdown) return;
      if (game.docked) {
        eliteAudio.play("boop");
        setMessage("Launch before engaging hyperspace.");
        return;
      }
      const from = currentSystem();
      const to = targetSystem();
      const d = distance(from, to);
      if (game.target === game.current) {
        eliteAudio.play("boop");
        setMessage(`Already in ${from.name}. Select another system.`, true);
        return;
      }
      if (!game.developerMode && d > 7) {
        eliteAudio.play("boop");
        setMessage("Target is outside the 7.0 light year jump range.", true);
        return;
      }
      if (!game.developerMode && game.fuel + 0.0001 < d) {
        eliteAudio.play("boop");
        setMessage("Insufficient fuel for hyperspace.", true);
        return;
      }
      if (!game.developerMode) game.fuel -= d;
      const toWitch = Math.random() < 0.012 + (game.legal > 15 ? 0.006 : 0);
      setMessage("Hyperspace countdown initiated.", true);
      const jumpSeed = hash32(`jump:${game.galaxy}:${game.current}:${game.target}:${Date.now() >> 8}`);
      const countdownTrajectory = ultraFxEnabled() ? {
        trajectoryControl: true,
        fromQ: quatNorm(ensureCameraQuat(game.camera)),
        trajectoryQ: calculateJumpTrajectoryQuat(game.camera, jumpSeed),
        wobbleSeed: jumpSeed
      } : {};
      startJumpCountdown("hyperspace", 5, "HYPERSPACE", () => {
        eliteAudio.play("hyperspace");
        const finalTrajectoryQ = quatNorm(ensureCameraQuat(game.camera));
        const arrive = () => {
          if (toWitch) {
            game.witchspace = true;
            game.objects = [];
            game.stars = Array.from({ length: 264 }, (_, i) => vec((Math.random() - .5) * 2600, (Math.random() - .5) * 1600, Math.random() * 2600 - 900));
            for (let i = 0; i < 4; i++) {
              const stats = shipStats("thargoid");
              const thargoid = {
                type: "ship", model: "thargoid", name: "THARGOID", pos: vec((Math.random() - .5) * 900, (Math.random() - .5) * 500, 700 + Math.random() * 900),
                vel: vec(0, 0, -35), rot: Math.random() * TAU, pitch: 0, r: stats.r, color: shipColor("thargoid"),
                hp: stats.hp, maxHp: stats.hp, hostile: true, role: "alien", bounty: 500, thargoid: true,
                aiMode: "attack", attackClock: .35 + Math.random() * .65, wobble: Math.random() * TAU,
                npcMissiles: npcMissileStock("thargoid", "alien", false),
                decalSeed: hash32(`witchspace:${Date.now() >> 10}:${i}:thargoid`)
              };
              setNoseDirection(thargoid, sub(game.camera.pos, thargoid.pos), thargoid.roll || 0);
              game.objects.push(thargoid);
            }
            game.docked = false;
            game.speed = 50;
            setMessage("Witch-space malfunction. Thargoids detected.", true);
          } else {
            game.current = game.target;
            game.witchspace = false;
            resetFlightScene(true);
            setMessage(`Hyperspace complete. Arrived at ${currentSystem().name}.`, true);
          }
        };
        const finish = () => {
          if (!ultraFxEnabled() || toWitch) arrive();
          game.screenShake = Math.max(game.screenShake || 0, ultraFxEnabled() ? 1.2 : .5);
          flash();
          renderPanel();
        };
        const extra = ultraFxEnabled() ? {
          departureEnd: .26,
          arrivalAt: .74,
          fromQ: finalTrajectoryQ,
          trajectoryQ: finalTrajectoryQ,
          departureClearance: jumpDepartureClearanceDistance(finalTrajectoryQ, game.camera),
          departureStars: captureJumpDepartureStarfield(game.camera),
          ...(toWitch ? {} : { onArrive: arrive })
        } : {};
        startTransition("hyperspace", ultraFxEnabled() ? 3.8 : 1.1, finish, extra);
      }, countdownTrajectory);
    }

    function galacticJump() {
      if (game.transition || game.jumpCountdown) return;
      if (!game.equipment.galacticHyperdrive) {
        eliteAudio.play("boop");
        setMessage("No Galactic Hyperdrive fitted.");
        return;
      }
      setMessage("Galactic jump countdown initiated.", true);
      const jumpSeed = hash32(`galactic:${game.galaxy}:${game.current}:${Date.now() >> 8}`);
      const countdownTrajectory = ultraFxEnabled() ? {
        trajectoryControl: true,
        fromQ: quatNorm(ensureCameraQuat(game.camera)),
        trajectoryQ: calculateJumpTrajectoryQuat(game.camera, jumpSeed),
        wobbleSeed: jumpSeed
      } : {};
      startJumpCountdown("galactic", 10, "GALACTIC JUMP", () => {
        eliteAudio.play("hyperspace");
        const finalTrajectoryQ = quatNorm(ensureCameraQuat(game.camera));
        const arrive = () => {
          game.galaxy = (game.galaxy + 1) % 8;
          game.current = 0;
          game.target = 1;
          game.equipment.galacticHyperdrive = false;
          game.docked = false;
          game.witchspace = false;
          resetFlightScene(true);
        };
        const finish = () => {
          if (!ultraFxEnabled()) arrive();
          game.screenShake = Math.max(game.screenShake || 0, ultraFxEnabled() ? 1.6 : .6);
          flash();
          setMessage(`Galactic hyperspace complete. Galaxy ${game.galaxy + 1}.`, true);
          renderPanel();
        };
        const extra = ultraFxEnabled() ? {
          departureEnd: .22,
          arrivalAt: .76,
          fromQ: finalTrajectoryQ,
          trajectoryQ: finalTrajectoryQ,
          departureClearance: jumpDepartureClearanceDistance(finalTrajectoryQ, game.camera),
          departureStars: captureJumpDepartureStarfield(game.camera),
          onArrive: arrive
        } : {};
        startTransition("galactic", ultraFxEnabled() ? 7.2 : 2.8, finish, extra);
      }, countdownTrajectory);
    }

    function nearStationSafeZone() {
      const st = dockableTarget();
      return !!st && len(sub(st.pos, game.camera.pos)) < 900;
    }

    // The station's own true visual size (~226-247, see modelBoundingRadius) is
    // considerably bigger than ambient traffic's spawn/orbit/cruise distances were ever
    // tuned for, so anything steering toward or orbiting "the station" needs to reason
    // about its actual bulk, not just its point position, or ships fly straight through
    // the hull. Falls back to the Coriolis radius if no station is in the scene yet.
    function stationClearanceRadius() {
      const st = primaryStation();
      const model = st && st.model === "dodoStation" ? MODELS.dodoStation : STATION_MODEL;
      return modelBoundingRadius(model);
    }

    // A random point at least minDist clear of the station's hull (plus a further random
    // spread), used so ambient ship spawn/orbit positions can never land inside it.
    function randomPointClearOfStation(rng, minDist, spread) {
      const station = primaryStation();
      const stationPos = station ? station.pos : vec(0, 0, 900);
      const dir = norm(vec(rng() - .5, (rng() - .5) * .6, rng() - .5));
      const dist = stationClearanceRadius() + minDist + rng() * spread;
      return add(stationPos, scale(dir, dist));
    }

    function spawnPoliceResponse() {
      const stats = shipStats("viper");
      const dist = 500 + Math.random() * 400;
      const dir = norm(vec(Math.random() - .5, Math.random() - .5, Math.random() - .5));
      const o = {
        type: "ship", model: "viper", name: "VIPER POLICE",
        pos: add(game.camera.pos, scale(dir, dist)),
        vel: vec(0, 0, 0), rot: Math.random() * TAU, pitch: 0, roll: 0,
        r: stats.r, color: shipColor("viper", true),
        hp: Math.round(stats.hp * 1.2), maxHp: Math.round(stats.hp * 1.2),
        hostile: true, police: true, role: "police", bounty: 0,
        aiMode: "attack", orbitCenter: vec(), orbitRadius: 300, orbitAngle: Math.random() * TAU,
        orbitSpeed: .2, attackClock: 1, wobble: Math.random() * TAU,
        npcMissiles: npcMissileStock("viper", "police", true),
        decalSeed: hash32(`${game.galaxy}:${game.current}:viper:police`)
      };
      game.objects.push(o);
      hail(o, policeScrambleLine());
      return o;
    }

    function stationProtectedTarget(o) {
      if (!o) return false;
      if (o.type === "ship") return o.police || !o.hostile;
      return o.type === "canister" || o.type === "plate";
    }

    function provokeStationPolice(reason = "Weapons fire near the station") {
      game.legal = Math.min(60, game.legal + 2);
      const policeNearby = worldSnapshot().ships.filter((o) => o.police).length;
      if (policeNearby < 2 && Math.random() < .55) spawnPoliceResponse();
      setMessage(`${reason}! Police scrambled.`, true);
    }

    function reportStationWeaponOffence(target) {
      if (!nearStationSafeZone() || !stationProtectedTarget(target)) return false;
      const label = target.police ? "Police vessel attacked near the station" : "Innocent ship hit near the station";
      provokeStationPolice(label);
      return true;
    }

    function segmentSphereHit(a, b, center, radius) {
      const ab = sub(b, a);
      const ab2 = dot(ab, ab);
      if (ab2 <= 1e-6) return null;
      const t = clamp(dot(sub(center, a), ab) / ab2, 0, 1);
      const closest = add(a, scale(ab, t));
      const d = len(sub(center, closest));
      return d <= radius ? { t, point: closest, d } : null;
    }

    function stationBlocksLaser(from, to, ignoreTarget = null) {
      let best = null;
      for (const st of worldSnapshot().stationLike) {
        if ((st.type !== "station" && st.type !== "hermit") || st === ignoreTarget || st._remove) continue;
        const radius = largeCollisionRadius(st) * 1.03;
        const hit = segmentSphereHit(from, to, st.pos, radius);
        if (!hit || hit.t <= .015 || hit.t >= .985) continue;
        if (!best || hit.t < best.t) best = { ...hit, station: st };
      }
      return best;
    }

    function fireLaser() {
      if (game.transition) return;
      if (game.docked) {
        eliteAudio.play("boop");
        setMessage("Lasers are safed while docked.");
        return;
      }
      if (!["fwd", "ext"].includes(game.viewMode || "fwd")) {
        eliteAudio.play("boop");
        setMessage("Lasers are forward-mounted.");
        return;
      }
      const now = performance.now();
      const laser = laserPower();
      if (game.laserHeat >= 95) {
        if (now - (game.lastHeatWarning || 0) > 900) {
          game.lastHeatWarning = now;
          setMessage("Laser temperature critical.");
        }
        return;
      }
      if (now - game.lastShot < laser.cooldown) return;
      game.lastShot = now;
      game.laserHeat = clamp(game.laserHeat + laser.heat, 0, 100);
      if (!DEV_DISABLE_LASER_EFFECTS) eliteAudio.play(laser.sound || "laser");
      let best = null;
      let score = Infinity;
      let hitDepth = null;
      let outOfRange = null;
      const w = space.width, h = space.height;
      const damageNow = performance.now();
      for (const o of game.objects) {
        const isRock = o.type === "asteroid" || o.type === "boulder" || o.type === "splinter";
        if (o.type !== "ship" && o.type !== "canister" && o.type !== "plate" && !isRock && !(o.type === "missile" && o.hostile)) continue;
        if (freshDropLaserProtected(o, damageNow)) continue;
        const rel = cameraTransform(o.pos, game.camera);
        if (rel.z < 30) continue;
        if (rel.z > laser.range) {
          const p = project(rel, w, h);
          if (p) {
            const model = MODELS[o.model || "cobra"];
            const radius = model?.verts?.length ? modelBoundingRadius(model) : (o.r || 50);
            const projectedRadius = (radius / Math.max(1, rel.z)) * Math.min(w, h) * .82;
            const screenDist = Math.hypot(p.x - w / 2, p.y - h / 2);
            const aimLimit = Math.max(24, projectedRadius * .72);
            if (screenDist <= aimLimit && (!outOfRange || rel.z < outOfRange.dist)) outOfRange = { o, dist: rel.z };
          }
          continue;
        }
        const hit = laserFootprintHit(o, rel, w, h);
        if (!hit) continue;
        const candidateHitPos = cameraLocalToWorld(game.camera, vec(0, 0, hit.depth));
        if (stationBlocksLaser(game.camera.pos, candidateHitPos, o)) continue;
        const aim = Math.hypot(rel.x, rel.y) / Math.max(1, rel.z);
        const depthScore = hit.depth + aim * 18 + hit.screenDist * .05;
        if (depthScore < score) {
          best = o;
          score = depthScore;
          hitDepth = hit.depth;
        }
      }
      const hitPos = best ? cameraLocalToWorld(game.camera, vec(0, 0, hitDepth || cameraTransform(best.pos, game.camera).z)) : null;
      game.playerShot = DEV_DISABLE_LASER_EFFECTS ? null : {
        to: hitPos,
        color: laser.color,
        width: laser.width,
        duration: laser.duration,
        kind: laser.id,
        range: laser.range,
        t: now
      };
      if (!best) {
        if (outOfRange) setMessage(`${outOfRange.o.name} out of ${laser.name.toLowerCase()} laser range (${Math.round(outOfRange.dist)}m / ${laser.range}m).`);
        else setMessage("Laser fired.");
        return;
      }
      if (hitPos && !DEV_DISABLE_LASER_EFFECTS) spawnSmokePuffs(hitPos, best.r ? clamp(best.r / 70, .45, 1.8) : .7, best.type === "ship" ? 4 : 3);
      const isRockTarget = best.type === "asteroid" || best.type === "boulder" || best.type === "splinter";
      best.hp -= isRockTarget && game.equipment.miningLaser ? laser.damage * (laser.rockMul || 2) : laser.damage;
      if (!DEV_DISABLE_LASER_EFFECTS) eliteAudio.playAt("hit", hitPos || best.pos, { range: 1400, gain: best.type === "ship" ? 1 : .82 });
      addImpactShake(best.type === "ship" ? .24 : .16, hitPos || best.pos, 950);
      setMessage(`${best.name} hit.`);
      if (best.type === "ship") reactToPlayerAttack(best);
      else reportStationWeaponOffence(best);
      maybeHailMercy(best, game.commander, 1);
      if (best.hp <= 0) destroyObject(best);
    }

    function spawnMissile({ pos, target, source, hostile }) {
      const launchDir = norm(source ? shipForward(source) : forwardVector(game.camera));
      const attitude = yawPitchForDirection(launchDir);
      const startSpeed = 260;
      game.objects.push({
        type: "missile", model: "missile", name: source ? `${source.name} MISSILE` : "MISSILE",
        pos: { ...pos }, vel: scale(launchDir, startSpeed), rot: attitude.yaw, pitch: attitude.pitch, roll: source ? (source.roll || 0) : 0,
        r: shipStats("missile").r, color: hostile ? "#ff6a55" : "#ffd33d", hp: shipStats("missile").hp, maxHp: shipStats("missile").hp, hostile,
        target: target || null, source: source || null, speed: startSpeed, t: 0, dur: 5
      });
    }

    function updateMissile(o, dt) {
      o.t += dt;
      const targetPos = o.target ? o.target.pos : game.camera.pos;
      const toTarget = sub(targetPos, o.pos);
      const dist = len(toTarget);
      if (dist > 1) {
        const desired = norm(toTarget);
        const { yaw, pitch } = yawPitchForDirection(desired);
        o.rot = lerpAngle(o.rot || 0, yaw, dt * 7.5);
        o.pitch = lerpAngle(o.pitch || 0, pitch, dt * 7.5);
      }
      o.roll = lerpAngle(o.roll || 0, 0, dt * 5);
      o.speed = clamp((o.speed || len(o.vel) || 260) + dt * 420, 260, 360);
      const fwd = shipForward(o);
      o.vel = scale(fwd, o.speed);
      spawnMissileTrail(add(o.pos, scale(fwd, -Math.max(10, o.r * .35))), scale(fwd, -1), clamp(o.speed / 260, .8, 1.5));
      o.pos = add(o.pos, scale(o.vel, dt));
      const nextDist = len(sub(targetPos, o.pos));
      if (nextDist < 40) {
        game.objects = game.objects.filter((x) => x !== o);
        detonateMissile(o);
      } else if (o.t > o.dur) {
        game.objects = game.objects.filter((x) => x !== o);
      }
    }

    function detonateMissile(o) {
      eliteAudio.playAt("explosion", o.pos, { range: 1800 });
      addImpactShake(1.05, o.pos, 1250);
      spawnExplosion(o.pos, .6);
      spawnSmokePuffs(o.pos, .8, 5);
      if (o.target) {
        o.target.hp -= 120;
        spawnSmokePuffs(o.target.pos, clamp((o.target.r || 50) / 60, .7, 2), 7);
        setMessage(`${o.target.name} missile hit.`, true);
        if (o.target.hp <= 0) destroyObject(o.target, !o.hostile);
      } else {
        const arc = damagePlayer(22, o.source ? o.source.name : "missile", { sourcePos: o.source?.pos });
        addImpactShake(1.45);
        setMessage(`${o.source ? o.source.name + " missile" : "Missile"} impact!`, true);
        if (arc === "aft") commsMessage("DAMAGE CONTROL", "AFT SHIELD STRIKE", "warning");
      }
    }

    function fireMissile() {
      if (game.docked || game.missiles <= 0) return;
      const target = nearestTarget(true);
      if (!target) {
        eliteAudio.play("boop");
        setMessage("No missile lock.");
        return;
      }
      reportStationWeaponOffence(target);
      game.missiles--;
      eliteAudio.play("missile");
      spawnMissile({ pos: add(game.camera.pos, scale(forwardVector(game.camera), 40)), target, hostile: false });
      setMessage(`Missile away: ${target.name}.`, true);
    }

    function randomBurstDir(flatten = 1) {
      return norm(vec(Math.random() - .5, (Math.random() - .5) * flatten, Math.random() - .5));
    }

    function addExplosionShake(pos, magnitude) {
      if (!ultraFxEnabled()) return;
      const dist = len(sub(pos, game.camera.pos));
      const near = clamp(1 - dist / 1450, 0, 1);
      const through = clamp(1 - dist / 520, 0, 1);
      const rel = cameraTransform(pos, game.camera);
      const inView = rel.z > -220 && rel.z < 1800 ? 1 : .55;
      const shake = magnitude * (.8 + near * near * 6.2 + through * through * through * 12) * inView;
      game.screenShake = Math.max(game.screenShake || 0, shake);
    }

    function addImpactShake(amount = .35, pos = null, range = 1400) {
      if (!ultraFxEnabled()) return;
      let strength = amount;
      if (pos && finiteVec3(pos) && finiteVec3(game.camera?.pos)) {
        const dist = len(sub(pos, game.camera.pos));
        strength *= clamp(1 - dist / Math.max(1, range), 0, 1);
      }
      if (strength > .025) game.screenShake = Math.max(game.screenShake || 0, clamp(strength, .04, 2.4));
    }

    function spawnExplosionCloud(pos, magnitude = 1) {
      if (!ultraFxEnabled()) return;
      const mag = clamp(magnitude, .35, 5.2);
      const count = Math.max(2, Math.round((7 + mag * 9 + Math.random() * 5) * performanceParticleScale()));
      for (let i = 0; i < count; i++) {
        const dir = randomBurstDir(.72);
        game.smokePuffs.push({
          kind: "fireSmoke",
          pos: add(pos, scale(dir, Math.random() * 18 * mag)),
          drift: scale(dir, (16 + Math.random() * 58) * mag),
          t: 0,
          dur: 1.45 + Math.random() * 1.55 + mag * .28,
          radius: (16 + Math.random() * 42) * mag,
          alpha: .18 + Math.random() * .26,
          heat: .45 + Math.random() * .55,
          shade: 58 + Math.random() * 52
        });
      }
      trimParticleStore(game.smokePuffs, 300);
    }

    function spawnExplosion(pos, magnitude = 1) {
      const mag = clamp(magnitude, .35, 5.2);
      const particleScale = performanceParticleScale();
      const shardCount = Math.max(5, Math.round((16 + mag * 10 + Math.random() * 8) * particleScale));
      const sparkCount = Math.max(6, Math.round((20 + mag * 14 + Math.random() * 10) * particleScale));
      const fragmentCount = Math.max(1, Math.round((4 + mag * 5) * particleScale));
      const shards = Array.from({ length: shardCount }, () => ({
        dir: randomBurstDir(.85),
        len: (16 + Math.random() * 42) * mag,
        speed: (120 + Math.random() * 260) * mag,
        width: .8 + Math.random() * 2.2,
        warm: Math.random()
      }));
      const sparks = Array.from({ length: sparkCount }, () => ({
        dir: randomBurstDir(.9),
        speed: (90 + Math.random() * 360) * mag,
        life: .45 + Math.random() * .45,
        size: .8 + Math.random() * 2.4
      }));
      const fragments = Array.from({ length: fragmentCount }, () => ({
        dir: randomBurstDir(.75),
        speed: (45 + Math.random() * 150) * mag,
        size: (5 + Math.random() * 13) * mag,
        spin: (Math.random() - .5) * 8,
        angle: Math.random() * TAU,
        shade: 70 + Math.random() * 90
      }));
      game.explosions.push({
        pos: { ...pos },
        t: 0,
        dur: .95 + Math.random() * .35 + mag * .12,
        shards,
        sparks,
        fragments,
        magnitude: mag
      });
      spawnExplosionCloud(pos, mag);
      addExplosionShake(pos, mag);
      eliteAudio.explosionRumble(pos, mag);
      trimParticleStore(game.explosions, 28);
    }

    function shipExplosionMagnitude(o) {
      const radius = o.r || shipStats(o.model).r || 50;
      const size = clamp(radius / 46, .45, 5.4);
      const heavyHull = clamp(((o.maxHp || o.hp || 40) - 45) / 220, 0, 1.6);
      return clamp(.55 + Math.pow(size, 1.18) * .72 + heavyHull * .65, .65, 5.2);
    }

    function spawnSmokePuffs(pos, magnitude = 1, count = 4) {
      if (!ultraFxEnabled()) return;
      const mag = clamp(magnitude, .35, 2.8);
      count = Math.max(1, Math.round(count * performanceParticleScale()));
      for (let i = 0; i < count; i++) {
        game.smokePuffs.push({
          kind: "smoke",
          pos: add(pos, scale(randomBurstDir(.8), Math.random() * 8 * mag)),
          drift: scale(randomBurstDir(.55), (3 + Math.random() * 10) * mag),
          t: 0,
          dur: 2.1 + Math.random() * 1.8 + mag * .35,
          radius: (9 + Math.random() * 22) * mag,
          alpha: .12 + Math.random() * .16,
          shade: 118 + Math.random() * 70
        });
      }
      const plasmaCount = Math.max(1, Math.round(count * .65));
      for (let i = 0; i < plasmaCount; i++) {
        const dir = randomBurstDir(.75);
        game.smokePuffs.push({
          kind: "plasma",
          pos: add(pos, scale(dir, Math.random() * 5 * mag)),
          drift: scale(dir, (42 + Math.random() * 105) * mag),
          t: 0,
          dur: .45 + Math.random() * .65 + mag * .08,
          radius: (5 + Math.random() * 10) * mag,
          alpha: .32 + Math.random() * .36,
          tail: (18 + Math.random() * 44) * mag,
          hue: 188 + Math.random() * 34
        });
      }
      trimParticleStore(game.smokePuffs, 130);
    }

    function makeEnginePlasmaPuff(pos, aftDir, magnitude = 1, alien = false, hueOverride = null) {
      const mag = clamp(magnitude, .45, 2.2);
      const jitter = scale(randomBurstDir(.7), 4.5 * mag);
      const drift = add(scale(aftDir, 72 + Math.random() * 82), jitter);
      const podTrail = hueOverride != null;
      return {
        kind: "enginePlasma",
        pos: add(pos, scale(randomBurstDir(.8), Math.random() * 2.4 * mag)),
        drift,
        t: 0,
        dur: (podTrail ? 1.65 : 2.35) + Math.random() * (podTrail ? .28 : .45),
        radius: (podTrail ? 4.8 + Math.random() * 4.2 : 7 + Math.random() * 8) * mag,
        alpha: podTrail ? .2 + Math.random() * .08 : alien ? .16 + Math.random() * .09 : .13 + Math.random() * .07,
        tailTime: podTrail ? .34 + Math.random() * .1 : .42 + Math.random() * .18,
        hue: hueOverride ?? (alien ? 266 + Math.random() * 28 : 190 + Math.random() * 26),
        alien
      };
    }

    function spawnEnginePlasmaInto(store, pos, aftDir, magnitude = 1, alien = false, hueOverride = null, limit = 260) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled()) return;
      if (Math.random() > performanceParticleScale()) return;
      store.push(makeEnginePlasmaPuff(pos, aftDir, magnitude, alien, hueOverride));
      trimParticleStore(store, limit);
    }

    function emitEnginePlasmaForShip(store, ship, trailMul, opts = {}) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled() || trailMul <= .03) return;
      const anchors = engineWorldAnchors(ship);
      const engineMul = anchors.length > 3 ? .82 : 1;
      const alienTrail = opts.alien ?? isAlienShip(ship);
      const hue = opts.hue ?? (ship.model === "escapePod" ? 48 + Math.random() * 8 : null);
      const boostMul = opts.boostMul ?? (1 + (ship.engineBoost || 0) * 1.45);
      for (const anchor of anchors) {
        spawnEnginePlasmaInto(store, anchor.pos, anchor.aft, clamp(trailMul * engineMul * boostMul, .45, 2.2), alienTrail, hue, opts.limit || 260);
      }
    }

    function spawnEnginePlasma(pos, aftDir, magnitude = 1, alien = false, hueOverride = null) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled()) return;
      spawnEnginePlasmaInto(game.smokePuffs, pos, aftDir, magnitude, alien, hueOverride, 260);
    }

    function spawnDamagedEngineSmoke(pos, aftDir, magnitude = 1, alien = false) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled()) return;
      const mag = clamp(magnitude, .55, 3.6);
      const burst = clamp((mag - .9) / 2.7, 0, 1);
      const jitter = scale(randomBurstDir(.75), (12 + burst * 22) * mag);
      game.smokePuffs.push({
        kind: "smoke",
        pos: add(pos, scale(randomBurstDir(.85), Math.random() * (5 + burst * 9) * mag)),
        drift: add(scale(aftDir, 30 + Math.random() * (54 + burst * 58)), jitter),
        t: 0,
        dur: 1.85 + Math.random() * 1.25 + burst * .65,
        radius: (9 + Math.random() * 16 + burst * 18) * mag,
        alpha: (alien ? .2 : .15) + Math.random() * .13 + burst * .12,
        shade: alien ? 96 + Math.random() * 48 : 74 + Math.random() * 58,
        burst,
        smokeTint: alien ? [80, 255, 125] : null
      });
      trimParticleStore(game.smokePuffs, 320);
    }

    function spawnMissileTrail(pos, aftDir, magnitude = 1) {
      if (!ultraFxEnabled()) return;
      const mag = clamp(magnitude, .55, 1.8);
      const jitter = scale(randomBurstDir(.55), 3.2 * mag);
      game.smokePuffs.push({
        kind: "missileTrail",
        pos: add(pos, scale(randomBurstDir(.65), Math.random() * 1.8 * mag)),
        drift: add(scale(aftDir, 210 + Math.random() * 95), jitter),
        t: 0,
        dur: .82 + Math.random() * .34,
        radius: (4 + Math.random() * 5) * mag,
        alpha: .38 + Math.random() * .22,
        tailTime: .5 + Math.random() * .16,
        hue: 4 + Math.random() * 12
      });
      trimParticleStore(game.smokePuffs, 280);
    }

    function engineWorldAnchors(o) {
      const model = MODELS[o.model];
      if (!model?.details?.length) return [];
      const roll = o.roll ?? (o.rot || 0) * .7;
      const scaleFactor = o.scaleFactor ?? o.scale ?? 1;
      const orient = (v) => o.quat ? quatRotate(o.quat, v) : rotateShipPoint(v, o.rot || 0, o.pitch || 0, roll);
      const anchors = [];
      for (const detail of model.details) {
        if (detail.type !== "engine") continue;
        const localPoints = detail.points || (detail.indices || []).map((i) => model.verts[i]).filter(Boolean);
        if (!localPoints.length) continue;
        const center = scale(localPoints.reduce((sum, p) => add(sum, vec(p[0] * scaleFactor, p[1] * scaleFactor, p[2] * scaleFactor)), vec()), 1 / localPoints.length);
        const normal = detail.normal ? norm(vec(...detail.normal)) : vec(0, 0, -1);
        const lift = (detail.lift ?? 1) * scaleFactor;
        anchors.push({
          pos: add(o.pos, orient(add(center, scale(normal, lift)))),
          aft: norm(orient(vec(0, 0, -1)))
        });
      }
      if (anchors.length) return anchors;
      return [{
        pos: add(o.pos, orient(vec(0, 0, -objectCollisionRadius({ model: o.model }) * scaleFactor * .72))),
        aft: norm(orient(vec(0, 0, -1)))
      }];
    }

    function engineWorldCenters(o) {
      return engineWorldAnchors(o).map((anchor) => anchor.pos);
    }

    function spawnPlayerEnginePlume(strength = 1) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled()) return;
      const ship = playerWorldShip();
      const aft = scale(shipForwardWorld(ship), -1);
      const centers = engineWorldCenters(ship);
      const engineMul = centers.length > 3 ? .82 : 1;
      for (let burst = 0; burst < 5; burst++) {
        for (const center of centers) {
          spawnEnginePlasma(add(center, scale(aft, burst * 10)), aft, strength * engineMul * (1.35 - burst * .12));
        }
      }
    }

    function playerWorldShip(camera = game.camera, opts = {}) {
      const model = opts.model || playerShipModel();
      const boost = opts.engineBoost ?? game.playerEngineBoost ?? 0;
      return {
        type: "ship",
        model,
        pos: opts.pos || camera.pos,
        quat: opts.quat || ensureCameraQuat(camera),
        rot: 0,
        pitch: 0,
        roll: 0,
        speed: opts.speed ?? game.speed,
        engineBoost: boost,
        engineGlow: opts.engineGlow ?? shipEngineGlowLevel({ model, speed: opts.speed ?? game.speed, engineBoost: boost }),
        engineTrailClock: opts.engineTrailClock ?? game.playerEngineTrailClock ?? 0,
        hp: opts.hp ?? game.energy,
        maxHp: opts.maxHp ?? 100,
        name: opts.name || game.commander,
        role: opts.role || "private",
        color: opts.color || "#e9f2e4",
        playerDamageMarks: opts.playerDamageMarks || game.playerDamageMarks
      };
    }

    function playerLaserHardpoints(ship = playerWorldShip()) {
      const q = ship.quat || ensureCameraQuat(game.camera);
      const forward = quatRotate(q, vec(0, 0, 1));
      const right = quatRotate(q, vec(1, 0, 0));
      const down = quatRotate(q, vec(0, -1, 0));
      const radius = Math.max(48, modelBoundingRadius(MODELS[ship.model] || MODELS[playerShipModel()]));
      return [
        add(ship.pos, add(scale(forward, radius * .55), add(scale(right, -radius * .42), scale(down, radius * .08)))),
        add(ship.pos, add(scale(forward, radius * .55), add(scale(right, radius * .42), scale(down, radius * .08))))
      ];
    }

    function updatePlayerEngineTrails(dt) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled() || game.docked || game.playerDestroyed || !MODELS[playerShipModel()]?.details) return;
      const ship = playerWorldShip(game.camera);
      updateEngineTrails(ship, dt);
      game.playerEngineTrailClock = ship.engineTrailClock || 0;
    }

    function updateEngineTrails(o, dt) {
      if (DEV_DISABLE_ENGINE_EFFECTS) return;
      if (!ultraFxEnabled() || o.type !== "ship" || !MODELS[o.model]?.details) return;
      const speed = o.speed ?? len(o.vel || vec());
      if (speed < 16) return;
      o.engineTrailClock = (o.engineTrailClock || 0) - dt;
      if (o.engineTrailClock > 0) return;
      o.engineTrailClock = (.035 + Math.random() * .025) * (1 + performanceLod() * .85);
      const aft = scale(shipForwardWorld(o), -1);
      const centers = engineWorldCenters(o);
      const alienTrail = isAlienShip(o);
      const model = MODELS[o.model];
      const trailDistance = sceneModelDistance(o);
      const trailVisible = !model || trailDistance <= sceneModelDotDistance(model, o);
      if (trailVisible) emitEnginePlasmaForShip(game.smokePuffs, o, clamp(speed / 105, .6, 2.2), { alien: alienTrail });
      const hullFrac = o.maxHp ? (o.hp ?? o.maxHp) / o.maxHp : 1;
      const smokeThreshold = .28;
      if (trailVisible && hullFrac < smokeThreshold && centers.length) {
        o.damageSmokeClock = (o.damageSmokeClock || 0) - dt;
        if (o.damageSmokeClock <= 0) {
          const severity = clamp((smokeThreshold - hullFrac) / smokeThreshold, .15, 1);
          const critical = hullFrac < .18;
          o.damageSmokeClock = critical
            ? .045 + Math.random() * .12
            : .13 + Math.random() * .2 - severity * .06;
          const smokeCount = critical
            ? 2 + Math.floor(Math.random() * 4)
            : 1 + (severity > .55 && Math.random() < .65 ? 1 : 0);
          for (let i = 0; i < smokeCount; i++) {
            const center = centers[Math.floor(Math.random() * centers.length)];
            spawnDamagedEngineSmoke(center, aft, clamp(speed / 95, .55, 2.1) * (.85 + severity * (critical ? 1.95 : 1.1)), alienTrail);
          }
        }
      }
    }

    // Canopy-pop flash for an ejecting pilot: an expanding cold ring + a few glass
    // glints, visually distinct from the hot orange death explosion.
    function spawnEjectFlash(pos) {
      const shards = Array.from({ length: 6 }, () => ({
        dir: norm(vec(Math.random() - .5, Math.random() - .5, Math.random() - .5)),
        len: 6 + Math.random() * 10,
        speed: 90 + Math.random() * 120
      }));
      game.explosions.push({ pos: { ...pos }, t: 0, dur: .8, shards, magnitude: 1, kind: "eject" });
    }

    function spawnAsteroid(rng = Math.random, near = game.camera.pos) {
      const isBoulder = rng() < .3;
      const model = isBoulder ? "boulder" : "asteroid";
      const stats = shipStats(model);
      const dist = 1200 + rng() * 2000;
      const dir = norm(vec((rng() - .5) * 2, (rng() - .5) * 1.2, (rng() - .5) * 2));
      game.objects.push({
        type: isBoulder ? "boulder" : "asteroid", model, name: isBoulder ? "BOULDER" : "ASTEROID",
        pos: add(near, scale(dir, dist)),
        vel: scale(norm(vec(rng() - .5, rng() - .5, rng() - .5)), 8 + rng() * 12),
        rot: rng() * TAU, pitch: rng() * TAU, roll: 0,
        tumbleRot: (rng() - .5) * .5, tumblePitch: (rng() - .5) * .4,
        r: stats.r, color: isBoulder ? "#7a7268" : "#8a8276",
        hp: stats.hp, maxHp: stats.hp, hostile: false
      });
    }

    function spawnSplinter(pos, parentVel) {
      const stats = shipStats("splinter");
      const dir = norm(vec(Math.random() - .5, Math.random() - .5, Math.random() - .5));
      game.objects.push({
        type: "splinter", model: "splinter", name: "SPLINTER",
        pos: { ...pos }, vel: add(scale(dir, 30 + Math.random() * 30), scale(parentVel || vec(), .3)),
        rot: Math.random() * TAU, pitch: Math.random() * TAU, roll: 0,
        tumbleRot: (Math.random() - .5) * 1.6, tumblePitch: (Math.random() - .5) * 1.4,
        r: stats.r, color: "#8a8276", hp: stats.hp, maxHp: stats.hp, hostile: false
      });
    }

    function spawnMineralCanister(pos, parentVel, small) {
      const good = ["Minerals", "Gold", "Platinum", "Gem-Stones"][Math.floor(Math.random() * 4)];
      game.objects.push(protectFreshDropFromLaser({
        type: "canister", model: "canister", name: `${good.toUpperCase()} CANISTER`, forcedGood: good,
        pos: add(pos, vec(0, 0, small ? 10 : 20)), vel: scale(parentVel || vec(), .5),
        rot: 0, pitch: 0, r: small ? 14 : 18, color: "#ffd33d", hp: small ? 6 : 8, hostile: false
      }));
    }

    function spawnEscapePod(pos) {
      const stats = shipStats("escapePod");
      const pod = {
        type: "ship", model: "escapePod", name: "ESCAPE POD",
        pos: { ...pos }, vel: scale(norm(vec(Math.random() - .5, Math.random() - .5, Math.random() - .5)), 50),
        rot: 0, pitch: 0, roll: 0, r: stats.r, color: "#e9f2e4", hp: stats.hp, maxHp: stats.hp,
        hostile: false, role: "pod", bounty: 15, aiMode: "cruise", wobble: Math.random() * TAU
      };
      protectFreshDropFromLaser(pod);
      game.objects.push(pod);
      return pod;
    }

    function destroyObject(o, byPlayer = true) {
      game.objects = game.objects.filter((x) => x !== o);
      if (o.type === "ship") {
        eliteAudio.playAt("explosion", o.pos, { range: 2400, gain: clamp(shipExplosionMagnitude(o) / 1.5, .65, 1.35) });
        // Original Elite treats escape pods as a ship-blueprint capability
        // rather than a universal bailout chance.
        const behaviour = SOURCE_BEHAVIOUR[o.model] || {};
        const canEject = byPlayer && behaviour.escapePod && !isAlienShip(o) && o.role !== "police" && o.role !== "pod";
        if (canEject && Math.random() < .28) {
          const mag = shipExplosionMagnitude(o);
          spawnEscapePod(o.pos);
          spawnEjectFlash(o.pos);
          spawnExplosion(o.pos, mag * .58);
          spawnSmokePuffs(o.pos, clamp(mag * .62, .7, 3.6), 6 + Math.floor(mag * 1.5));
          setMessage(`${o.name} pilot ejects!`, true);
          return;
        }
        const mag = shipExplosionMagnitude(o);
        spawnExplosion(o.pos, mag);
        spawnSmokePuffs(o.pos, clamp(mag * .74, .8, 4.4), 7 + Math.floor(mag * 2));
        if (mag > 2.6) {
          const blasts = Math.min(3, Math.floor((mag - 1.7) / 1.1) + 1);
          for (let i = 0; i < blasts; i++) {
            const offset = scale(randomBurstDir(.75), (18 + Math.random() * 42) * mag);
            setTimeout(() => {
              spawnExplosion(add(o.pos, offset), mag * (.38 + Math.random() * .18));
              spawnSmokePuffs(add(o.pos, offset), clamp(mag * .38, .9, 3.2), 4 + Math.floor(mag));
            }, 90 + i * 135 + Math.random() * 120);
          }
        }
        if (Math.random() > .5) {
          const isPlate = Math.random() < .35;
          const stats = shipStats(isPlate ? "plate" : "canister");
          game.objects.push(isPlate
            ? protectFreshDropFromLaser({ type: "plate", model: "plate", name: "ALLOY PLATE", pos: add(o.pos, vec(0, 0, 30)), vel: vec(0, 0, -12), rot: .3, pitch: .2, roll: 0, r: stats.r, color: "#9aa79a", hp: stats.hp, hostile: false })
            : protectFreshDropFromLaser({ type: "canister", model: "canister", name: "CARGO CANISTER", pos: add(o.pos, vec(0, 0, 30)), vel: vec(0, 0, -12), rot: 0, pitch: 0, r: stats.r, color: "#ffd33d", hp: stats.hp, hostile: false }));
        }
        if (!byPlayer) {
          setMessage(`${o.name} destroyed.`, true);
          return;
        }
        const witness = game.objects.find((s) => s !== o && s.type === "ship" && s.role && s.role !== "pod" && Math.random() < .4);
        if (witness) hail(witness, witnessLine(o.name));
        game.kills++;
        game.credits += o.bounty || 0;
        if (o.police || !o.hostile) game.legal += o.police ? 24 : 8;
        else game.legal = Math.max(0, game.legal - 1);
        setMessage(`${o.name} destroyed. ${o.bounty ? `Bounty ${o.bounty} CR.` : "Debris detected."}`, true);
      } else if (o.type === "canister" || o.type === "plate") {
        scoopCargo(o);
      } else if (o.type === "asteroid") {
        eliteAudio.playAt("explosion", o.pos, { range: 1800, gain: .85 });
        spawnExplosion(o.pos, .8);
        spawnSmokePuffs(o.pos, 1.1, 6);
        const count = 2 + Math.floor(Math.random() * 2);
        for (let i = 0; i < count; i++) spawnSplinter(o.pos, o.vel);
        if (Math.random() < .5) spawnMineralCanister(o.pos, o.vel, false);
        setMessage("Asteroid breaks apart.");
      } else if (o.type === "boulder") {
        eliteAudio.playAt("hit", o.pos, { range: 1300, gain: .9 });
        spawnExplosion(o.pos, 1.1);
        spawnSmokePuffs(o.pos, 1.2, 6);
        setMessage("Boulder shattered.");
      } else if (o.type === "splinter") {
        eliteAudio.playAt("hit", o.pos, { range: 1100, gain: .65 });
        spawnExplosion(o.pos, .4);
        spawnSmokePuffs(o.pos, .55, 3);
        if (Math.random() < .7) spawnMineralCanister(o.pos, o.vel, true);
      }
    }

    function scoopCargo(o) {
      if (usedCargo() >= game.cargoCap) {
        setMessage("Cargo bay full.");
        return;
      }
      const good = o.forcedGood || (o.type === "plate" ? "Alloys" : GOODS[Math.floor(Math.random() * (GOODS.length - 1))][0]);
      game.cargo[good]++;
      game.objects = game.objects.filter((x) => x !== o);
      eliteAudio.play("cargoScoop");
      setMessage(`Scooped ${o.type === "plate" ? "alloy plate" : "cargo canister"}: ${good}.`);
    }

    function targetBaseRank(o, shipsOnly = false) {
      if (o.type === "missile") return o.hostile ? 0 : 9;
      if (o.type === "ship") {
        if (o.hostile && (o.target == null || o.target === undefined)) return o.police ? 1 : 0;
        if (o.hostile) return o.police ? 2 : 1;
        if (o.role === "pirate" || o.thargoid) return 1;
        if (o.role === "pod") return 6;
        if (o.aiMode === "stationLaunch" || o.aiMode === "stationDock") return 5;
        return 4;
      }
      if (shipsOnly) return 99;
      if (o.type === "station") return 7;
      if (o.type === "canister" || o.type === "plate") return 8;
      if (o.type === "asteroid" || o.type === "boulder" || o.type === "splinter" || o.type === "hermit") return 9;
      return 99;
    }

    function targetPriorityEntry(o, shipsOnly = false) {
      const rel = cameraTransform(o.pos, game.camera);
      const dist = len(sub(o.pos, game.camera.pos));
      const inFront = rel.z > 35;
      const screenDist = Math.hypot(rel.x, rel.y);
      const aimOffset = inFront ? screenDist / Math.max(80, rel.z) : 4 + screenDist / 1000;
      const rank = targetBaseRank(o, shipsOnly);
      const sizeBonus = clamp((o.r || 0) / 220, 0, .55);
      const threatBonus = o.hostile ? .45 : 0;
      const score = rank * 1000000
        + (inFront ? 0 : 220000)
        + aimOffset * 90000
        + dist * 7
        - sizeBonus * 50000
        - threatBonus * 70000;
      return { o, score, rank, dist, inFront, aimOffset };
    }

    function targetList(shipsOnly = false) {
      const candidates = [];
      for (const o of game.objects) {
        if (o.hp !== undefined && o.hp <= 0) continue;
        if (shipsOnly && o.type !== "ship") continue;
        const entry = targetPriorityEntry(o, shipsOnly);
        if (entry.rank >= 99) continue;
        candidates.push(entry);
      }
      candidates.sort((a, b) => a.score - b.score);
      return candidates;
    }

    function nearestTarget(shipsOnly = false) {
      return targetList(shipsOnly)[0]?.o || null;
    }

    function lockNextTarget() {
      const list = targetList(false);
      if (!list.length) {
        game.targetObject = null;
        setMessage("No target lock.");
        return null;
      }
      const currentIndex = game.targetObject ? list.findIndex((entry) => entry.o === game.targetObject) : -1;
      const next = list[(currentIndex + 1) % list.length].o;
      game.targetObject = next;
      const entry = list.find((item) => item.o === next);
      const detail = entry?.inFront ? "" : " (aft)";
      setMessage(`Locked: ${next.name}${detail}.`);
      return next;
    }

    function destroyPlayer(reason) {
      if (game.playerDestroyed) return;
      game.playerDestroyed = true;
      eliteAudio.play("death");
      const hadCapsule = game.equipment.escapeCapsule;
      game.equipment.escapeCapsule = false;
      const deathPos = { ...game.camera.pos };
      const deathQuat = ensureCameraQuat(game.camera);
      const deathModel = playerShipModel();
      const finish = () => {
        if (hadCapsule) {
          setMessage(`Escape capsule fired! Ship lost to ${reason}, but you're alive. Picked up and returned to Lave.`, true);
        } else {
          setMessage(`Ship destroyed by ${reason}. Rebuilt at Lave with a replacement Cobra.`, true);
        }
        game.galaxy = 0;
        game.current = LAVE_INDEX;
        game.target = DISO_INDEX;
        game.docked = true;
        setViewMode("fwd");
        game.playerDestroyed = false;
        game.credits = Math.max(10, Math.floor(game.credits * (hadCapsule ? .7 : .35)));
        game.fuel = 7;
        restoreShipSystems();
        game.speed = 0;
        game.legal = hadCapsule ? Math.max(0, game.legal - 6) : 0;
        game.cargo = Object.fromEntries(GOODS.map((g) => [g[0], 0]));
        resetFlightScene(false);
        renderPanel();
      };
      game.docked = false;
      game.speed = 0;
      game.playerShot = null;
      setViewMode("ext");
      game.externalView.yaw = .52;
      game.externalView.pitch = .28;
      game.externalView.zoom = .82;
      setMessage(hadCapsule ? "EJECT EJECT EJECT" : "HULL BREACH - SHIP LOST", true);
      startTransition("death", hadCapsule ? 4.2 : 3.5, finish, {
        reason,
        hadCapsule,
        deathPos,
        deathQuat,
        deathModel
      });
    }

    function finishGameOver() {
      const tr = game.transition;
      if (!tr || tr.kind !== "death" || !tr.waitingForRestart) return false;
      game.transition = null;
      tr.onComplete();
      return true;
    }

    function useEnergyBomb() {
      if (game.docked) {
        eliteAudio.play("boop");
        setMessage("Energy bomb is safed while docked.");
        return;
      }
      if (!game.equipment.energyBomb) {
        eliteAudio.play("boop");
        setMessage("No energy bomb fitted.");
        return;
      }
      game.equipment.energyBomb = false;
      eliteAudio.play("bomb");
      flash();
      let hits = 0;
      for (const o of game.objects) {
        if (o.type !== "ship" || !o.hostile) continue;
        if (len(sub(o.pos, game.camera.pos)) > 1400) continue;
        o.hp -= 999;
        hits++;
      }
      for (const o of [...game.objects]) {
        if (o.type === "ship" && o.hp <= 0) destroyObject(o);
      }
      game.legal = Math.min(60, game.legal + 15);
      setMessage(hits ? `Energy bomb detonated. ${hits} hostile${hits === 1 ? "" : "s"} vaporized.` : "Energy bomb detonated. No targets in range.", true);
      renderPanel();
    }

    function buyGood(name) {
      if (!canUseMarket()) return;
      const sys = currentSystem();
      const stock = marketStockFor(sys);
      const item = marketFor(sys).find((g) => g.name === name);
      if (!item || item.qty <= 0) {
        eliteAudio.play("boop");
        setMessage(`${name} unavailable.`);
        renderPanel();
        return;
      }
      if (usedCargo() >= game.cargoCap) {
        eliteAudio.play("boop");
        setMessage("Cargo bay full.");
        return;
      }
      if (game.credits < item.price) {
        eliteAudio.play("boop");
        setMessage("Insufficient credits.");
        return;
      }
      game.credits -= item.price;
      game.cargo[name]++;
      stock[name] = Math.max(0, (stock[name] ?? item.qty) - 1);
      eliteAudio.play("beep");
      if (item.illegal && Math.random() > .92) game.legal += 2;
      renderPanel();
    }

    function sellGood(name) {
      if (!canUseMarket() || game.cargo[name] <= 0) return;
      const sys = currentSystem();
      const stock = marketStockFor(sys);
      const item = marketFor(sys).find((g) => g.name === name);
      if (!item) return;
      game.cargo[name]--;
      game.credits += item.price;
      stock[name] = Math.max(0, Math.trunc(Number(stock[name] ?? item.qty) || 0) + 1);
      eliteAudio.play("beep");
      if (item.illegal && Math.random() > .8) game.legal += 1;
      renderPanel();
    }

    function buyFuel() {
      if (!canUseMarket()) return;
      const needTenths = Math.max(0, Math.round((7 - game.fuel) * 10));
      if (needTenths <= 0) {
        eliteAudio.play("boop");
        setMessage("Fuel tanks already full.");
        return;
      }
      const affordableTenths = Math.min(needTenths, Math.floor((game.credits + 0.0001) / 0.2));
      if (affordableTenths <= 0) {
        eliteAudio.play("boop");
        setMessage("Insufficient credits for fuel.");
        return;
      }
      const amount = affordableTenths / 10;
      const cost = affordableTenths * 0.2;
      const partial = affordableTenths < needTenths;
      game.credits -= cost;
      game.fuel = clamp(game.fuel + amount, 0, 7);
      eliteAudio.play("scoop");
      setMessage(partial ? `Insufficient credits for full refuel. Partial fill: ${fmt(amount)} LY.` : `Fuel tanks filled: ${fmt(amount)} LY loaded.`);
      renderPanel();
    }

    function buyEquipment(id) {
      const item = EQUIPMENT.find((e) => e.id === id);
      if (!item || !game.docked) return;
      const sys = currentSystem();
      if (game.equipment[id]) {
        eliteAudio.play("boop");
        setMessage("Already fitted.");
        return;
      }
      if (sys.tech + 1 < item.tech) {
        eliteAudio.play("boop");
        setMessage("Local tech level too low.");
        return;
      }
      if (game.credits < item.cost) {
        eliteAudio.play("boop");
        setMessage("Insufficient credits.");
        return;
      }
      game.credits -= item.cost;
      if (isLaserEquipment(id)) fitLaser(id);
      else game.equipment[id] = true;
      if (id === "cargoBay") applyPlayerShipStats({ trimCargo: false });
      eliteAudio.play("beep");
      setMessage(`${item.name} fitted.`);
      renderPanel();
    }

    // Testing helpers only — bypass cost/tech-level/docked gating entirely, unlike
    // buyFuel/buyEquipment above. Not tied to any key/hotkey; reachable only via the
    // Cheats panel tab, so there's no risk of an accidental keypress granting free stuff.
    function cheatAddCredits(amount) {
      game.credits += amount;
      setMessage(`Cheat: +${fmt(amount)} CR.`);
      renderPanel();
    }

    function cheatSetEquipment(id, fitted) {
      const item = EQUIPMENT.find((e) => e.id === id);
      if (!item) return;
      if (isLaserEquipment(id) && fitted) fitLaser(id);
      else game.equipment[id] = fitted;
      if (id === "cargoBay") applyPlayerShipStats();
      setMessage(`Cheat: ${item.name} ${fitted ? "fitted" : "removed"}.`);
      renderPanel();
    }

    function cheatChangePlayerShip(model) {
      if (!playerSelectableShipList().includes(model)) return;
      game.playerShip = model;
      applyPlayerShipStats();
      restoreShipSystems();
      shipDiagramState.model = model;
      setMessage(`Cheat: ship changed to ${shipName(model)}.`);
      renderPanel();
    }

    function cheatRefillShip() {
      game.fuel = 7;
      restoreShipSystems();
      game.missiles = 4;
      setMessage("Cheat: ship fully refuelled and repaired.");
      renderPanel();
    }

    function cheatClearLegalStatus() {
      game.legal = 0;
      setMessage("Cheat: legal status cleared.");
      renderPanel();
    }

    function cheatFillCargo() {
      for (const g of GOODS) game.cargo[g[0]] = 0;
      game.cargo[GOODS[0][0]] = game.cargoCap;
      setMessage("Cheat: cargo hold filled.");
      renderPanel();
    }

    function cheatToggleGodMode() {
      game.godMode = !game.godMode;
      if (game.godMode) restoreShipSystems();
      setMessage(`God mode ${game.godMode ? "enabled" : "disabled"}.`);
      renderPanel();
    }

    function optionList(options, current) {
      return options.map(([value, label]) => `<option value="${value}" ${value === current ? "selected" : ""}>${label}</option>`).join("");
    }

    function replaceSceneObject(type, replacement) {
      const idx = game.objects.findIndex((o) => o.type === type);
      if (idx >= 0) {
        if (game.targetObject === game.objects[idx]) game.targetObject = replacement;
        game.objects[idx] = replacement;
      } else {
        game.objects.push(replacement);
      }
    }

    function applyDevWorldOverrides() {
      const sys = currentSystem();
      const { planet, sun } = buildSystemBodies(sys);
      replaceSceneObject("planet", planet);
      replaceSceneObject("sun", sun);
      const stationModel = devStationModelForSystem(sys);
      const stationStyle = devStationStyleForSystem(sys);
      for (const st of game.objects.filter((o) => o.type === "station")) {
        st.model = stationModel;
        st.name = `${sys.name} ${stationModel === "dodoStation" ? "DODO STATION" : "STATION"}`;
        st.r = shipStats(stationModel).r;
        st.color = stationStyle.base;
        st.stationStyle = stationStyle;
      }
      stationTextureCache.clear();
    }

    function cheatSetWorldOverride(kind, value) {
      if (kind === "star" && DEV_STAR_TYPES.some(([id]) => id === value)) game.devStarType = value;
      else if (kind === "planet" && DEV_PLANET_TYPES.some(([id]) => id === value)) game.devPlanetType = value;
      else if (kind === "station" && DEV_STATION_TYPES.some(([id]) => id === value)) game.devStationType = value;
      else return;
      applyDevWorldOverrides();
      const label = { star: "star", planet: "planet", station: "station" }[kind] || kind;
      const option = ([...DEV_STAR_TYPES, ...DEV_PLANET_TYPES, ...DEV_STATION_TYPES].find(([id]) => id === value) || [value, value])[1];
      setMessage(`Dev visual override: ${label} ${option}.`, true);
      renderPanel();
    }

